import {
  createContext,
  useContext,
  useEffect,
  useId,
  useRef,
  type ReactNode,
} from "react";
import { X } from "lucide-react";
import { useApp } from "../context/AppContext";
import { useDashboardBrand } from "../hooks/useDashboardBrand";
import { FONT } from "../constants/theme";

const DialogTitleIdContext = createContext<string>("");

export function useDialogTitleId() {
  return useContext(DialogTitleIdContext);
}

export function ModalBase({
  children,
  maxWidth = 440,
  onClose,
  zIndex = 1000,
}: {
  children: ReactNode;
  maxWidth?: number;
  onClose: () => void;
  zIndex?: number;
}) {
  const { theme: t } = useApp();
  const brand = useDashboardBrand();
  const titleId = useId();
  const containerRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    function onKey(e: KeyboardEvent) {
      if (e.key === "Escape") onClose();
    }
    document.addEventListener("keydown", onKey);
    return () => document.removeEventListener("keydown", onKey);
  }, [onClose]);

  useEffect(() => {
    const first = containerRef.current?.querySelector<HTMLElement>(
      'button, [href], input, select, textarea, [tabindex]:not([tabindex="-1"])',
    );
    first?.focus();
  }, []);

  return (
    <div
      style={{
        position: "fixed",
        inset: 0,
        background: "#00000090",
        display: "flex",
        alignItems: "center",
        justifyContent: "center",
        zIndex,
        padding: "20px",
      }}
      onMouseDown={(e) => {
        /* `click` no backdrop após selecionar texto (mousedown no input + mouseup no overlay)
         * fechava o modal; `mousedown` só no fundo evita esse caso. */
        if (e.target === e.currentTarget) onClose();
      }}
      onKeyDown={(e) => {
        if (e.key === "Escape") onClose();
      }}
      role="presentation"
    >
      <div
        ref={containerRef}
        role="dialog"
        aria-modal="true"
        aria-labelledby={titleId}
        onMouseDown={(e) => e.stopPropagation()}
        onClick={(e) => e.stopPropagation()}
        style={{
          background: brand.blockBg,
          border: `1px solid ${t.cardBorder}`,
          borderRadius: "20px",
          padding: "28px",
          width: "100%",
          maxWidth,
          minWidth: 0,
          maxHeight: "90dvh",
          overflow: "auto",
        }}
      >
        <DialogTitleIdContext.Provider value={titleId}>{children}</DialogTitleIdContext.Provider>
      </div>
    </div>
  );
}

export function ModalHeader({
  title,
  onClose,
}: {
  title: string;
  onClose: () => void;
}) {
  const { theme: t } = useApp();
  const titleId = useDialogTitleId();
  return (
    <div
      style={{
        display: "flex",
        justifyContent: "space-between",
        alignItems: "center",
        marginBottom: "20px",
      }}
    >
      <h2
        id={titleId}
        style={{
          margin: 0,
          fontSize: "17px",
          fontWeight: 900,
          color: t.text,
          fontFamily: FONT.title,
        }}
      >
        {title}
      </h2>
      <button
        type="button"
        onClick={onClose}
        style={{
          background: "none",
          border: "none",
          cursor: "pointer",
          padding: 4,
          display: "flex",
          alignItems: "center",
          justifyContent: "center",
          color: t.textMuted,
        }}
        aria-label="Fechar modal"
      >
        <X size={20} strokeWidth={2} aria-hidden />
      </button>
    </div>
  );
}

export function ModalConfirmDelete({
  texto,
  onCancel,
  onConfirm,
  loading,
  title = "Confirmar exclusão",
  confirmLabel = "Excluir",
  destructive = true,
  zIndex = 1000,
  error,
  loadingLabel,
}: {
  texto: string;
  onCancel: () => void;
  onConfirm: () => void;
  loading?: boolean;
  /** Quando não for exclusão (ex.: descartar seleção no modal). */
  title?: string;
  confirmLabel?: string;
  destructive?: boolean;
  zIndex?: number;
  /** Mensagem inline (ex.: erro de API); não usar alert(). */
  error?: string | null;
  /** Texto do botão de confirmação enquanto loading (padrão: Excluindo… / Aguarde…). */
  loadingLabel?: string;
}) {
  const { theme: t } = useApp();
  const brand = useDashboardBrand();
  const loadingText =
    loadingLabel ??
    (destructive ? "Excluindo..." : "Aguarde...");
  function handleClose() {
    if (loading) return;
    onCancel();
  }
  return (
    <ModalBase onClose={handleClose} maxWidth={400} zIndex={zIndex}>
      <ModalHeader title={title} onClose={handleClose} />
      <p
        style={{
          fontSize: 14,
          color: t.text,
          fontFamily: FONT.body,
          lineHeight: 1.55,
          margin: "0 0 24px",
        }}
      >
        {texto}
      </p>
      {error ? (
        <div
          role="alert"
          aria-live="polite"
          style={{
            color: "#ef4444",
            fontSize: 12,
            fontFamily: FONT.body,
            marginTop: -12,
            marginBottom: 16,
          }}
        >
          {error}
        </div>
      ) : null}
      <div style={{ display: "flex", gap: 10 }}>
        <button
          type="button"
          onClick={handleClose}
          disabled={loading}
          style={{
            flex: 1,
            padding: 12,
            borderRadius: 10,
            border: `1px solid ${t.cardBorder}`,
            background: t.inputBg,
            color: t.textMuted,
            fontWeight: 700,
            fontFamily: FONT.body,
            cursor: loading ? "not-allowed" : "pointer",
          }}
        >
          Cancelar
        </button>
        <button
          type="button"
          onClick={onConfirm}
          disabled={loading}
          style={{
            flex: 1,
            padding: 12,
            borderRadius: 10,
            border: "none",
            background: destructive
              ? "#ef4444"
              : brand.useBrand
                ? "linear-gradient(135deg, var(--brand-primary), var(--brand-secondary))"
                : "linear-gradient(135deg, #4a2082, #1e36f8)",
            color: "#fff",
            fontWeight: 700,
            fontFamily: FONT.body,
            cursor: loading ? "not-allowed" : "pointer",
            opacity: loading ? 0.7 : 1,
          }}
        >
          {loading ? loadingText : confirmLabel}
        </button>
      </div>
    </ModalBase>
  );
}

import { FONT } from "../constants/theme";

/**
 * Retorna bg, color e border para uma tag baseada na cor primária da operadora.
 * Sem cor salva: usa --brand-action via color-mix (evita concatenar sufixo hex em var()).
 */
function getOperadoraTagStyles(corPrimaria: string | null | undefined) {
  const trimmed = corPrimaria?.trim();
  if (!trimmed) {
    return {
      bg: "color-mix(in srgb, var(--brand-action, #7c3aed) 10%, transparent)",
      color: "var(--brand-action, #7c3aed)",
      borderProperty: "1px solid color-mix(in srgb, var(--brand-action, #7c3aed) 27%, transparent)",
    };
  }
  return {
    bg: `${trimmed}18`,
    color: trimmed,
    borderProperty: `1px solid ${trimmed}44`,
  };
}

export interface OperadoraTagProps {
  label: string;
  corPrimaria?: string | null;
  icon?: React.ReactNode;
  style?: React.CSSProperties;
}

/**
 * Tag de operadora usando a cor primária da operadora.
 * Quando corPrimaria não está definida, usa --brand-action como fallback.
 */
export default function OperadoraTag({ label, corPrimaria, icon, style }: OperadoraTagProps) {
  const { bg, color, borderProperty } = getOperadoraTagStyles(corPrimaria);

  return (
    <span
      style={{
        display: "inline-flex",
        alignItems: "center",
        gap: 5,
        fontSize: 11,
        padding: "3px 9px",
        borderRadius: 20,
        background: bg,
        color,
        border: borderProperty,
        fontWeight: 600,
        fontFamily: FONT.body,
        ...style,
      }}
    >
      {icon}
      {label}
    </span>
  );
}

export { getOperadoraTagStyles };

import { ExternalLink, Loader2, Paperclip } from "lucide-react";
import type { CSSProperties } from "react";
import { FONT } from "../../constants/theme";
import type { RhFuncionarioHistorico } from "../../types/rhFuncionario";

export const HIST_TIPO_LABEL: Record<string, string> = {
  revisao_contrato: "Revisão de Contrato",
  periodo_indisponibilidade: "Período de Indisponibilidade",
  retorno_indisponibilidade: "Retorno de Indisponibilidade",
  alinhamento_formal: "Alinhamento Formal",
  termino_prestacao: "Término da Prestação",
  reativacao_prestacao: "Reativação da Prestação",
  rh_talks: "RH Talks",
  anotacao_rh: "Anotação do RH",
  staff_gestao_edicao: "Edição (Gestão de Staff)",
  dados_cadastro_self: "Atualização — Dados de Cadastro",
};

const HIST_TIPO_SURFACE: Record<string, { bg: string; border: string }> = {
  revisao_contrato: { bg: "rgba(34, 197, 94, 0.12)", border: "rgba(34, 197, 94, 0.38)" },
  periodo_indisponibilidade: { bg: "rgba(245, 158, 11, 0.14)", border: "rgba(245, 158, 11, 0.42)" },
  retorno_indisponibilidade: { bg: "rgba(167, 139, 250, 0.16)", border: "rgba(167, 139, 250, 0.42)" },
  alinhamento_formal: { bg: "rgba(249, 115, 22, 0.14)", border: "rgba(249, 115, 22, 0.4)" },
  termino_prestacao: { bg: "rgba(232, 64, 37, 0.1)", border: "rgba(232, 64, 37, 0.36)" },
  reativacao_prestacao: { bg: "rgba(59, 130, 246, 0.14)", border: "rgba(59, 130, 246, 0.4)" },
  rh_talks: { bg: "rgba(107, 114, 128, 0.14)", border: "rgba(107, 114, 128, 0.42)" },
  anotacao_rh: { bg: "rgba(100, 116, 139, 0.12)", border: "rgba(100, 116, 139, 0.38)" },
  staff_gestao_edicao: { bg: "rgba(59, 130, 246, 0.12)", border: "rgba(59, 130, 246, 0.36)" },
  dados_cadastro_self: { bg: "rgba(59, 130, 246, 0.1)", border: "rgba(59, 130, 246, 0.34)" },
};

export function cardStyleHistoricoPorTipo(
  tipo: string,
  t: { cardBorder: string; inputBg: string },
): CSSProperties {
  const c = HIST_TIPO_SURFACE[tipo];
  return {
    marginBottom: 14,
    padding: "12px 14px",
    borderRadius: 12,
    border: `1px solid ${c?.border ?? t.cardBorder}`,
    background: c?.bg ?? t.inputBg,
    fontFamily: FONT.body,
    fontSize: 13,
  };
}

/** Formata `YYYY-MM-DD` ou ISO para exibição pt-BR; vazio → "—". */
export function fmtDataIsoPtBr(iso: string | null | undefined): string {
  if (!iso || !String(iso).trim()) return "—";
  const s = String(iso).slice(0, 10);
  const p = s.split("-");
  if (p.length === 3 && p[0].length === 4) return `${p[2]}/${p[1]}/${p[0]}`;
  return s;
}

function labelTipoTerminoPrestacaoDet(v: unknown): string {
  if (v === "voluntario") return "Voluntário";
  if (v === "nao_voluntario") return "Não voluntário";
  return "—";
}

export function ListaHistoricoRh({
  items,
  loading,
  t,
}: {
  items: RhFuncionarioHistorico[];
  loading: boolean;
  t: { text: string; textMuted: string; cardBorder: string; inputBg: string };
}) {
  if (loading) {
    return (
      <div style={{ color: t.textMuted, fontSize: 13, fontFamily: FONT.body }}>
        <Loader2 size={16} className="app-lucide-spin" aria-hidden style={{ verticalAlign: "middle", marginRight: 8 }} />
        Carregando histórico…
      </div>
    );
  }
  if (items.length === 0) {
    return (
      <div style={{ padding: "24px 0", textAlign: "center", color: t.textMuted, fontSize: 13, fontFamily: FONT.body }}>
        Sem dados para o período selecionado.
      </div>
    );
  }
  return (
    <ul style={{ listStyle: "none", margin: 0, padding: 0 }}>
      {items.map((h) => {
        const anexos = Array.isArray(h.anexos)
          ? (h.anexos as { name?: string; publicUrl: string }[]).filter((a) => a?.publicUrl)
          : [];
        const det = h.detalhes ?? {};
        const titulo = HIST_TIPO_LABEL[h.tipo] ?? h.tipo;
        const quando = new Date(h.created_at).toLocaleString("pt-BR");
        return (
          <li key={h.id} style={cardStyleHistoricoPorTipo(h.tipo, t)}>
            <div style={{ fontWeight: 800, color: t.text, marginBottom: 6 }}>{titulo}</div>
            <div style={{ fontSize: 12, color: t.textMuted, marginBottom: 8 }}>
              {quando}
              {det.usuario_label ? ` · ${String(det.usuario_label)}` : ""}
            </div>
            {"alteracoes" in det && Array.isArray(det.alteracoes) ? (
              <ul style={{ margin: "6px 0 0", paddingLeft: 18, color: t.text }}>
                {(det.alteracoes as { campo: string; antes: string; depois: string }[]).map((alt, j) => (
                  <li key={j} style={{ marginBottom: 4 }}>
                    <strong>{alt.campo}:</strong> {alt.antes} → {alt.depois}
                  </li>
                ))}
              </ul>
            ) : null}
            {h.tipo === "periodo_indisponibilidade" && "data_saida" in det ? (
              <div style={{ color: t.text, marginTop: 6 }}>
                <div>
                  <strong>Data de saída:</strong> {String(det.data_saida ?? "—")}
                </div>
                {det.data_retorno ? (
                  <div>
                    <strong>Data de retorno:</strong> {String(det.data_retorno)}
                  </div>
                ) : null}
                {det.observacao ? (
                  <div style={{ marginTop: 4 }}>
                    <strong>Observação:</strong> {String(det.observacao)}
                  </div>
                ) : null}
              </div>
            ) : null}
            {h.tipo === "termino_prestacao" && "data_termino" in det ? (
              <div style={{ color: t.text, marginTop: 6 }}>
                <div>
                  <strong>Data de término:</strong> {String(det.data_termino ?? "—")}
                </div>
                <div style={{ marginTop: 4 }}>
                  <strong>Tipo de término:</strong> {labelTipoTerminoPrestacaoDet(det.tipo_termino)}
                </div>
                {det.observacao ? (
                  <div style={{ marginTop: 4 }}>
                    <strong>Observação:</strong> {String(det.observacao)}
                  </div>
                ) : null}
              </div>
            ) : null}
            {h.tipo === "retorno_indisponibilidade" && det.observacao ? (
              <div style={{ color: t.text, marginTop: 6 }}>
                <strong>Observação:</strong> {String(det.observacao)}
              </div>
            ) : null}
            {h.tipo === "alinhamento_formal" && det.observacao ? (
              <div style={{ color: t.text, marginTop: 6 }}>
                <strong>Observação:</strong> {String(det.observacao)}
              </div>
            ) : null}
            {h.tipo === "rh_talks" ? (
              <div style={{ color: t.text, marginTop: 6, lineHeight: 1.5 }}>
                {det.assunto ? (
                  <div>
                    <strong>Assunto:</strong> {String(det.assunto)}
                  </div>
                ) : null}
                {det.data_rh_talks ? (
                  <div style={{ marginTop: 4 }}>
                    <strong>Data do RH Talks:</strong> {fmtDataIsoPtBr(String(det.data_rh_talks))}
                  </div>
                ) : null}
              </div>
            ) : null}
            {h.tipo === "anotacao_rh" ? (
              <div style={{ color: t.text, marginTop: 6, lineHeight: 1.5 }}>
                {det.tipo_visibilidade ? (
                  <div>
                    <strong>Tipo:</strong> {String(det.tipo_visibilidade)}
                  </div>
                ) : null}
                {det.assunto ? (
                  <div style={{ marginTop: 4 }}>
                    <strong>Assunto:</strong> {String(det.assunto)}
                  </div>
                ) : null}
                {det.data_conversa ? (
                  <div style={{ marginTop: 4 }}>
                    <strong>Data da conversa:</strong> {fmtDataIsoPtBr(String(det.data_conversa))}
                  </div>
                ) : null}
                {det.ata_reuniao ? (
                  <div style={{ marginTop: 8 }}>
                    <strong>Ata da reunião:</strong>
                    <pre
                      style={{
                        margin: "6px 0 0",
                        whiteSpace: "pre-wrap",
                        wordBreak: "break-word",
                        fontFamily: FONT.body,
                        fontSize: 12,
                        color: t.text,
                        maxHeight: 220,
                        overflow: "auto",
                        padding: 8,
                        borderRadius: 8,
                        background: "color-mix(in srgb, var(--brand-secondary, #4a2082) 6%, transparent)",
                      }}
                    >
                      {String(det.ata_reuniao)}
                    </pre>
                  </div>
                ) : null}
              </div>
            ) : null}
            {anexos.length > 0 ? (
              <div style={{ display: "flex", flexWrap: "wrap", gap: 8, marginTop: 10, alignItems: "center" }}>
                {anexos.map((a, k) => (
                  <a
                    key={k}
                    href={a.publicUrl}
                    target="_blank"
                    rel="noopener noreferrer"
                    style={{
                      display: "inline-flex",
                      alignItems: "center",
                      gap: 6,
                      fontSize: 12,
                      color: "var(--brand-action, #7c3aed)",
                      fontWeight: 600,
                    }}
                  >
                    <Paperclip size={14} aria-hidden />
                    {a.name || "Anexo"}
                    <ExternalLink size={12} aria-hidden />
                  </a>
                ))}
              </div>
            ) : null}
          </li>
        );
      })}
    </ul>
  );
}

import { createContext, useContext, useState, useEffect, useCallback, ReactNode } from "react";
import { User, PageKey, PermissaoValor, Role } from "../types";
import { LIGHT_THEME, DARK_THEME, Theme } from "../constants/theme";
import { supabase } from "../lib/supabase";
import { validarBrandguide, cssDerivadasBrand, type BrandValidated } from "../lib/brandguideValidation";

// Todas as PageKeys existentes — usadas para liberar tudo ao admin
const ALL_PAGE_KEYS: PageKey[] = [
  "home",
  "mesas_spin", "streamers", "dash_overview_influencer", "dash_midias_sociais",
  "agenda", "resultados", "feedback",
  "influencers", "scout", "financeiro", "banca_jogo", "gestao_links", "campanhas", "gestao_dealers", "central_notificacoes",
  "gestao_usuarios", "gestao_operadoras", "gestao_mesas", "status_tecnico",
  "roteiro_mesa",
  "playbook_influencers",
  "links_materiais",
  "rh_figurinos",
  "rh_funcionarios",
  "rh_dados_cadastro",
  "rh_organograma",
  "rh_vagas",
  "rh_escala_mes",
  "rh_staff",
  "configuracoes", "ajuda",
];

// Tipo do mapa de permissões de visualização
export type PermissoesMapa = Record<PageKey, PermissaoValor>;

// Escopos visíveis
// semRestricaoEscopo=true (admin/gestor): vê tudo, ignora arrays
// semRestricaoEscopo=false ou undefined: só vê o que está em influencersVisiveis/operadorasVisiveis
export interface EscoposVisiveis {
  influencersVisiveis: string[];  // UUIDs
  operadorasVisiveis:  string[];  // slugs
  semRestricaoEscopo?: boolean;   // true = admin/gestor, vê tudo (dados)
  vêTodosInfluencers?: boolean;   // true = executivo, vê todos os influencers
  /** Tipos de gestor (user_scopes gestor_tipo); usado para filtrar menu vs gestor_tipo_pages */
  gestorTiposVisiveis?: string[];
}

/** Brand da operadora (operador): logo, fonte e fundo (hex); demais cores via CSS vars --brand-* */
export interface OperadoraBrand {
  nome:      string | null;
  logo_url:  string | null;
  font_url:  string | null;
  brand_bg:  string | null;
}

interface AppContextValue {
  // Auth
  user:        User | null;
  setUser:     (u: User | null) => void;
  checking:    boolean;
  // Navegação (página ativa no layout)
  activePage:  string;
  setActivePage: (page: string) => void;
  // Permissões de menu
  permissions: PermissoesMapa;
  setPermissions: (p: PermissoesMapa) => void;
  // Escopos para segregação de dados (Etapa 7)
  escoposVisiveis: EscoposVisiveis;
  /** [] = sem restrição. true se pode ver o influencer. */
  podeVerInfluencer: (id: string) => boolean;
  /** [] = sem restrição. true se pode ver a operadora. */
  podeVerOperadora: (slug: string) => boolean;
  /** Brand da operadora (operador): logo_url para Sidebar; cores via --brand-* */
  operadoraBrand: OperadoraBrand | null;
  // Theme
  theme:    Theme;
  isDark:   boolean;
  setIsDark:(v: boolean) => void;
}

const AppContext = createContext<AppContextValue | null>(null);

const ESCOPOS_VAZIOS: EscoposVisiveis = { influencersVisiveis: [], operadorasVisiveis: [], semRestricaoEscopo: false };

const DEFAULT_FONT_FAMILY = "'Inter', 'Helvetica Neue', Arial, sans-serif";

/** Cores extras de gráficos / semântica — não vêm da operadora. */
const CHART_SEMANTIC = {
  extra1: "#1e36f8",
  extra2: "#22c55e",
  extra3: "#f59e0b",
  extra4: "#e84025",
} as const;

/** Injeta tokens Opção C + aliases legados (`--brand-primary` = `--brand-action`, etc.). */
function injectBrandCss(validated: BrandValidated) {
  const root = document.documentElement.style;
  const der = cssDerivadasBrand(validated);
  Object.entries(der).forEach(([k, v]) => root.setProperty(k, v));
  root.setProperty("--brand-action", validated.action);
  root.setProperty("--brand-contrast", validated.contrast);
  root.setProperty("--brand-bg", validated.bg);
  root.setProperty("--brand-text", validated.text);
  root.setProperty("--brand-primary", validated.action);
  root.setProperty("--brand-secondary", validated.contrast);
  root.setProperty("--brand-accent", validated.contrast);
  root.setProperty("--brand-background", validated.bg);
  const iconMix = der["--brand-icon-color"]!;
  root.setProperty("--brand-icon-color", iconMix);
  root.setProperty("--brand-icon", iconMix);
  (Object.keys(CHART_SEMANTIC) as (keyof typeof CHART_SEMANTIC)[]).forEach((k) => {
    root.setProperty(`--brand-${k}`, CHART_SEMANTIC[k]);
  });
  root.setProperty("--brand-danger", CHART_SEMANTIC.extra4);
  root.setProperty("--brand-success", CHART_SEMANTIC.extra2);
}

/** Reseta para paleta Spin validada (usuário não operador ou sem brand). */
function aplicarBrandguideReset() {
  injectBrandCss(validarBrandguide({}));
}

type OperadoraBrandRow = {
  brand_action?: string | null;
  brand_contrast?: string | null;
  brand_bg?: string | null;
  brand_text?: string | null;
  logo_url?: string | null;
};

function aplicarBrandguideOperadora(data: OperadoraBrandRow | null | undefined) {
  const validated = validarBrandguide({
    action: data?.brand_action,
    contrast: data?.brand_contrast,
    bg: data?.brand_bg,
    text: data?.brand_text,
  });
  if (validated.warnings.length) console.warn("[brandguide]", validated.warnings);
  injectBrandCss(validated);
}

// ─── Carrega escopos visíveis por role e user_scopes (Etapa 7) ─────────────────
async function carregarEscoposVisiveis(
  userId: string,
  role: Role
): Promise<EscoposVisiveis> {
  if (role === "admin") {
    return { influencersVisiveis: [], operadorasVisiveis: [], semRestricaoEscopo: true };
  }

  if (role === "gestor") {
    const { data: scopes } = await supabase
      .from("user_scopes")
      .select("scope_type, scope_ref")
      .eq("user_id", userId);
    const lista = scopes ?? [];
    const gestorTiposVisiveis = lista
      .filter((s) => s.scope_type === "gestor_tipo")
      .map((s) => s.scope_ref)
      .filter(Boolean);
    return {
      influencersVisiveis: [],
      operadorasVisiveis: [],
      semRestricaoEscopo: true,
      gestorTiposVisiveis,
    };
  }

  const { data: scopes } = await supabase
    .from("user_scopes")
    .select("scope_type, scope_ref")
    .eq("user_id", userId);

  const lista = scopes ?? [];

  if (role === "influencer") {
    const operadorasVisiveis = lista
      .filter((s) => s.scope_type === "operadora")
      .map((s) => s.scope_ref);
    return { influencersVisiveis: [userId], operadorasVisiveis, semRestricaoEscopo: false };
  }

  // Executivo: vê TODOS os influencers, escopo só para operadoras
  if (role === "executivo") {
    const operadorasVisiveis = lista
      .filter((s) => s.scope_type === "operadora")
      .map((s) => s.scope_ref);
    return { influencersVisiveis: [], operadorasVisiveis, semRestricaoEscopo: false, vêTodosInfluencers: true };
  }

  // Operador: vê TODOS os influencers, escopo só para operadoras
  if (role === "operador") {
    const operadorasVisiveis = lista
      .filter((s) => s.scope_type === "operadora")
      .map((s) => s.scope_ref)
      .sort((a, b) => (a ?? "").localeCompare(b ?? ""));
    return { influencersVisiveis: [], operadorasVisiveis, semRestricaoEscopo: false, vêTodosInfluencers: true };
  }

  if (role === "agencia") {
    const pares = lista.filter((s) => s.scope_type === "agencia_par");
    const infIds = new Set<string>();
    const opSlugs = new Set<string>();
    pares.forEach((s) => {
      const [infId, opSlug] = s.scope_ref.split(":");
      if (infId) infIds.add(infId);
      if (opSlug) opSlugs.add(opSlug);
    });
    return {
      influencersVisiveis: [...infIds],
      operadorasVisiveis: [...opSlugs],
      semRestricaoEscopo: false,
    };
  }

  return { ...ESCOPOS_VAZIOS, semRestricaoEscopo: false };
}

// ─── Carrega can_view de todas as páginas para o role do usuário ──────────────
// Para operador: intersecta com operadora_pages (páginas liberadas por operadora)
async function carregarPermissoes(
  role: User["role"],
  options?: { operadorasVisiveis?: string[]; gestorTiposVisiveis?: string[] }
): Promise<PermissoesMapa> {
  const operadorasVisiveis = options?.operadorasVisiveis;
  const gestorTiposVisiveis = options?.gestorTiposVisiveis;
  const { data } = await supabase
    .from("role_permissions")
    .select("page_key, can_view")
    .eq("role", role);

  // Monta mapa — páginas sem registro ficam com null (= bloqueado no menu)
  const mapa = Object.fromEntries(
    ALL_PAGE_KEYS.map((k) => [k, null as PermissaoValor])
  ) as PermissoesMapa;

  (data || []).forEach((r) => {
    if (r.page_key in mapa) {
      mapa[r.page_key as PageKey] = r.can_view as PermissaoValor;
    }
  });

  // Gestão de Usuários: APENAS admin tem acesso (gestores não podem alterar perfis)
  mapa.gestao_usuarios = role === "admin" ? "sim" : "nao";

  // Overview Influencer: padrão "proprios" para influencer e agencia (único dash para eles)
  if (mapa.dash_overview_influencer === null && ["influencer", "agencia"].includes(role)) {
    mapa.dash_overview_influencer = "proprios";
  }
  if (mapa.dash_overview_influencer === null && ["admin", "gestor", "executivo"].includes(role)) {
    mapa.dash_overview_influencer = "sim";
  }

  // Operador: só vê páginas que estão em operadora_pages para suas operadoras
  if (role === "operador") {
    if (!operadorasVisiveis || operadorasVisiveis.length === 0) {
      ALL_PAGE_KEYS.forEach((k) => { mapa[k] = "nao"; });
    } else {
      const { data: opPages } = await supabase
        .from("operadora_pages")
        .select("page_key")
        .in("operadora_slug", operadorasVisiveis);
      const pagesPermitidas = new Set((opPages ?? []).map((r) => r.page_key));
      ALL_PAGE_KEYS.forEach((k) => {
        const cv = mapa[k];
        if (cv === "sim" || cv === "proprios") {
          if (!pagesPermitidas.has(k)) mapa[k] = "nao";
        }
      });
    }
  }

  // Gestor: união das páginas em gestor_tipo_pages para os tipos do usuário. Se não houver linhas na tabela
  // para esses tipos ainda, mantém só role_permissions (transição até a aba Gestores ser preenchida).
  if (role === "gestor" && gestorTiposVisiveis && gestorTiposVisiveis.length > 0) {
    const { data: gtPages } = await supabase
      .from("gestor_tipo_pages")
      .select("page_key")
      .in("gestor_tipo_slug", gestorTiposVisiveis);
    const rows = gtPages ?? [];
    if (rows.length > 0) {
      const pagesPermitidas = new Set(rows.map((r) => r.page_key));
      ALL_PAGE_KEYS.forEach((k) => {
        const cv = mapa[k];
        if (cv === "sim" || cv === "proprios") {
          if (!pagesPermitidas.has(k)) mapa[k] = "nao";
        }
      });
    }
  }

  return mapa;
}

export function AppProvider({ children }: { children: ReactNode }) {
  const [user,           setUserState]    = useState<User | null>(null);
  const [checking,       setChecking]    = useState(true);
  const [isDark,         setIsDark]      = useState(false);
  const [activePage,     setActivePage]   = useState("home");
  const [permissions,    setPermissions]  = useState<PermissoesMapa>(
    Object.fromEntries(ALL_PAGE_KEYS.map((k) => [k, null])) as PermissoesMapa
  );
  const [escoposVisiveis, setEscoposVisiveis] = useState<EscoposVisiveis>(ESCOPOS_VAZIOS);
  const [operadoraBrand, setOperadoraBrand] = useState<OperadoraBrand | null>(null);
  const [brandRefreshKey, setBrandRefreshKey] = useState(0);

  // Refetch brand ao voltar para a aba (ex.: admin atualizou operadora em outra aba)
  useEffect(() => {
    if (user?.role !== "operador") return;
    const onFocus = () => setBrandRefreshKey((k) => k + 1);
    window.addEventListener("focus", onFocus);
    return () => window.removeEventListener("focus", onFocus);
  }, [user?.role]);

  // Operador: sempre modo Dark (brand da operadora); demais roles escolhem tema
  const effectiveIsDark = user?.role === "operador" ? true : isDark;
  const theme = effectiveIsDark ? DARK_THEME : LIGHT_THEME;

  // data-theme no html para background full-viewport e scrollbar (evita linhas brancas)
  useEffect(() => {
    document.documentElement.setAttribute("data-theme", effectiveIsDark ? "dark" : "light");
  }, [effectiveIsDark]);

  // Brandguide: operador vê cores e logo da operadora; demais roles usam default
  useEffect(() => {
    if (!user || user.role !== "operador" || !escoposVisiveis.operadorasVisiveis?.length) {
      aplicarBrandguideReset();
      setOperadoraBrand(null);
      return;
    }
    const slug = escoposVisiveis.operadorasVisiveis[0];
    void (async () => {
      try {
        const { data } = await supabase.from("operadoras").select(
          "nome, brand_action, brand_contrast, brand_bg, brand_text, logo_url, font_url"
        ).eq("slug", slug).single();
        const hasBrand = !!(
          data?.brand_action || data?.brand_contrast || data?.brand_bg || data?.brand_text
          || (data?.logo_url ?? "").trim()
        );
        if (hasBrand) {
          aplicarBrandguideOperadora(data as OperadoraBrandRow);
        } else {
          aplicarBrandguideReset();
        }
        const nome = (data?.nome ?? "").trim() || null;
        const logo = (data?.logo_url ?? "").trim() || null;
        const font = (data?.font_url ?? "").trim() || null;
        const bg = (data?.brand_bg ?? "").trim() || null;
        setOperadoraBrand({ nome, logo_url: logo, font_url: font, brand_bg: bg });
      } catch {
        aplicarBrandguideReset();
        setOperadoraBrand(null);
      }
    })();
  }, [user, escoposVisiveis.operadorasVisiveis, brandRefreshKey]);

  // Fonte customizada: injeta @font-face e aplica --brand-fontFamily quando operador tem font_url
  useEffect(() => {
    const id = "operadora-brand-font";
    const existing = document.getElementById(id);
    if (existing) existing.remove();
    const root = document.documentElement.style;
    if (!operadoraBrand?.font_url) {
      root.setProperty("--brand-fontFamily", DEFAULT_FONT_FAMILY);
      return;
    }
    const url = operadoraBrand.font_url;
    const ext = url.split(".").pop()?.toLowerCase().split("?")[0] ?? "woff2";
    const format = ext === "woff2" ? "woff2" : ext === "woff" ? "woff" : "truetype";
    const style = document.createElement("style");
    style.id = id;
    style.textContent = `@font-face{font-family:"OperadoraBrandFont";src:url("${url}") format("${format}");font-display:swap;}`;
    document.head.appendChild(style);
    root.setProperty("--brand-fontFamily", '"OperadoraBrandFont", "Inter", sans-serif');
    return () => {
      document.getElementById(id)?.remove();
      root.setProperty("--brand-fontFamily", DEFAULT_FONT_FAMILY);
    };
  }, [operadoraBrand?.font_url]);

  // Wrapper de setUser que também carrega permissões e escopos
  async function setUser(u: User | null) {
    setUserState(u);
    if (u) setActivePage("home"); // Ao fazer login, volta para a página Home
    if (u) {
      try {
        const escopos = await carregarEscoposVisiveis(u.id, u.role);
        setEscoposVisiveis(escopos);
        const perms = await carregarPermissoes(u.role, {
          operadorasVisiveis: u.role === "operador" ? escopos.operadorasVisiveis : undefined,
          gestorTiposVisiveis: u.role === "gestor" ? escopos.gestorTiposVisiveis : undefined,
        });
        setPermissions(perms);
      } catch (err) {
        console.error("Erro ao carregar permissões/escopos após login:", err);
        setPermissions(Object.fromEntries(ALL_PAGE_KEYS.map((k) => [k, null])) as PermissoesMapa);
        setEscoposVisiveis(ESCOPOS_VAZIOS);
      }
    } else {
      setPermissions(
        Object.fromEntries(ALL_PAGE_KEYS.map((k) => [k, null])) as PermissoesMapa
      );
      setEscoposVisiveis(ESCOPOS_VAZIOS);
    }
  }

  useEffect(() => {
    // Carrega fontes
    const link = document.createElement("link");
    link.rel  = "stylesheet";
    link.href = "https://fonts.googleapis.com/css2?family=Barlow+Condensed:wght@700;900&family=Inter:wght@400;500;600;700&display=swap";
    document.head.appendChild(link);

    // Restaura sessão ativa
    supabase.auth.getSession().then(async ({ data: { session } }) => {
      try {
        if (session) {
          const { data: profile } = await supabase
            .from("profiles")
            .select("id, name, role, email, ativo, must_change_password")
            .eq("id", session.user.id)
            .single();
          if (profile) {
            if (profile.ativo === false) {
              await supabase.auth.signOut();
              setUserState(null);
              setChecking(false);
              return;
            }
            const u = profile as User;
            setUserState(u);
            try {
              const escopos = await carregarEscoposVisiveis(u.id, u.role);
              setEscoposVisiveis(escopos);
              const perms = await carregarPermissoes(u.role, {
                operadorasVisiveis: u.role === "operador" ? escopos.operadorasVisiveis : undefined,
                gestorTiposVisiveis: u.role === "gestor" ? escopos.gestorTiposVisiveis : undefined,
              });
              setPermissions(perms);
            } catch (err) {
              console.error("Erro ao carregar permissões/escopos:", err);
              setPermissions(Object.fromEntries(ALL_PAGE_KEYS.map((k) => [k, null])) as PermissoesMapa);
              setEscoposVisiveis(ESCOPOS_VAZIOS);
            }
          }
        }
      } catch (err) {
        console.error("Erro ao restaurar sessão:", err);
      } finally {
        setChecking(false);
      }
    });
  }, []);

  const podeVerInfluencer = useCallback(
    (id: string) =>
      escoposVisiveis.semRestricaoEscopo === true ||
      escoposVisiveis.vêTodosInfluencers === true ||
      escoposVisiveis.influencersVisiveis.includes(id),
    [escoposVisiveis],
  );
  const podeVerOperadora = useCallback(
    (slug: string) =>
      escoposVisiveis.semRestricaoEscopo === true || escoposVisiveis.operadorasVisiveis.includes(slug),
    [escoposVisiveis],
  );

  const setTheme = (v: boolean) => {
    if (user?.role === "operador") return; // Operador travado em Dark
    setIsDark(v);
  };

  return (
    <AppContext.Provider value={{
      user, setUser, checking,
      activePage, setActivePage,
      permissions, setPermissions,
      escoposVisiveis, podeVerInfluencer, podeVerOperadora,
      operadoraBrand,
      theme, isDark: effectiveIsDark, setIsDark: setTheme,
    }}>
      {children}
    </AppContext.Provider>
  );
}

export function useApp() {
  const ctx = useContext(AppContext);
  if (!ctx) throw new Error("useApp must be used within AppProvider");
  return ctx;
}

import { useMemo } from "react";
import { useApp } from "../context/AppContext";

/**
 * Regras de exibição de filtros por role (Etapa 8):
 * - Filtro influencer: admin, gestor, executivo sempre; operador/agência se ≥2
 * - Filtro operadora: admin, gestor, executivo sempre; influencer/agência se ≥2
 * - Operador: filtro operadora FORÇADO pelo escopo (só vê dados das suas operadoras)
 */
export function useDashboardFiltros() {
  const { user, escoposVisiveis, podeVerInfluencer, podeVerOperadora } = useApp();

  const showFiltroInfluencer = useMemo(() => {
    if (!user) return false;
    if (["admin", "gestor", "executivo"].includes(user.role)) return true;
    if (["operador", "agencia"].includes(user.role))
      return escoposVisiveis.influencersVisiveis.length >= 2;
    return false;
  }, [user, escoposVisiveis.influencersVisiveis.length]);

  const showFiltroOperadora = useMemo(() => {
    if (!user) return false;
    if (user.role === "operador" && escoposVisiveis.operadorasVisiveis.length > 0) return false;
    if (["admin", "gestor", "executivo"].includes(user.role)) return true;
    if (["influencer", "agencia"].includes(user.role))
      return escoposVisiveis.operadorasVisiveis.length >= 2;
    return false;
  }, [user, escoposVisiveis.operadorasVisiveis.length]);

  /** Operador: slugs das operadoras do escopo (filtro forçado). Outros roles: null. */
  const operadoraSlugsForcado = useMemo(() => {
    if (!user || user.role !== "operador") return null;
    const slugs = escoposVisiveis.operadorasVisiveis;
    return slugs.length > 0 ? slugs : null;
  }, [user?.role, escoposVisiveis.operadorasVisiveis]);

  return {
    showFiltroInfluencer,
    showFiltroOperadora,
    podeVerInfluencer,
    podeVerOperadora,
    escoposVisiveis,
    operadoraSlugsForcado,
  };
}

