            </div>
            <div className="app-grid-kpi-3" style={{ marginBottom: 12 }}>
              {[0, 1, 2].map((i) => (
                <SkeletonKpiCard key={`sk-r2-${i}`} />
              ))}
            </div>
            <div className="app-grid-kpi-4">
              {[0, 1, 2, 3].map((i) => (
                <SkeletonKpiCard key={`sk-r3-${i}`} />
