      </div>

      {/* ─── BLOCO 3: Funil de Conversão ───────────────────────────────────────── */}
      <div style={{ ...card, marginBottom: 14 }}>
        <SectionTitle icon={<Filter size={14} aria-hidden="true" />} sub={historico ? "acumulado" : undefined}>
