      const margin_pct = turnover !== 0 ? (ggr / turnover) * 100 : null;
      const bet_size = bets !== 0 ? turnover / bets : null;
      if (modoAgregadoTodasOperadoras) {
        const somaUapHist = uapMeses.reduce((a, b) => a + b, 0);
