                      subLinhas.map((sl, j) => {
                        const gg = sl.ggr ?? 0;
                        return (
                          <tr
                            key={`${rowKey}-${sl.operadora_slug}`}
                            style={{
                              background: brand.useBrand
                                ? zebraStripeBrandContrast(j)
                                : j % 2 === 1
                                  ? "color-mix(in srgb, var(--brand-contrast, #4a2082) 4%, transparent)"
                                  : "color-mix(in srgb, var(--brand-contrast, #4a2082) 2%, transparent)",
                              borderTop: j === 0 ? `1px solid ${t.cardBorder}` : undefined,
                            }}
                          >
                            <th
                              scope="row"
                              style={{
                                ...tdStyle,
                                fontWeight: 600,
                                paddingLeft: 32,
                                boxShadow:
                                  "inset 3px 0 0 color-mix(in srgb, var(--brand-action, #7c3aed) 35%, transparent)",
                              }}
                            >
                              {slugToNome(sl.operadora_slug)}
                            </th>
                            <td
                              style={{
                                ...tdNum,
                                color: gg > 0 ? BRAND.verde : gg < 0 ? BRAND.vermelho : t.text,
                                fontWeight: 600,
                              }}
                            >
                              {sl.ggr != null ? fmtBRL(sl.ggr) : "—"}
                            </td>
                            <td style={tdNum}>{sl.turnover != null ? fmtBRL(sl.turnover) : "—"}</td>
                            <td style={tdNum}>
                              {sl.bets != null ? sl.bets.toLocaleString("pt-BR") : "—"}
                            </td>
                            <td style={{ ...tdNum }}>
                              <MarginBadge value={sl.margin_pct} />
                            </td>
                            <td style={tdNum}>{sl.bet_size != null ? fmtBRL(sl.bet_size) : "—"}</td>
                            <td style={tdNum}>{sl.uap != null ? sl.uap.toLocaleString("pt-BR") : "—"}</td>
                            <td style={tdNum}>{sl.arpu != null ? fmtBRL(sl.arpu) : "—"}</td>
                          </tr>
                        );
                      })}
                  </Fragment>
                );
              })}
            </tbody>
          </table>
        </div>
      ) : dadosGraficoDetalheOperadoras.length === 0 || slugsGraficoDetalhe.length === 0 ? (
        <div
          style={{
            padding: "24px 0",
            textAlign: "center",
            color: t.textMuted,
            fontSize: 12,
            fontFamily: FONT.body,
          }}
        >
          {MSG_SEM_DADOS_FILTRO}
        </div>
      ) : (
        <>
          <p
            style={{
              fontSize: 11,
              color: t.textMuted,
              fontFamily: FONT.body,
              marginBottom: 8,
              marginTop: 0,
            }}
          >
            Exibindo <strong style={{ color: t.text }}>{kpiGraficoDetalheConfig.label}</strong> por operadora
          </p>
          <div
            role="img"
            aria-label={`Gráfico de ${kpiGraficoDetalheConfig.label} por operadora — ${historico ? "todo o período" : mesSelecionado?.label ?? ""}`}
            style={{ width: "100%", height: "clamp(220px, 35vh, 420px)", minHeight: 220 }}
          >
            <ResponsiveContainer width="100%" height="100%">
              {kpiGraficoDetalheConfig.tipoGrafico === "barra" ? (
                <BarChart
                  data={dadosGraficoDetalheOperadoras as Record<string, string | number | null>[]}
                  margin={{ top: 8, right: 16, left: 8, bottom: 4 }}
                  barCategoryGap="30%"
                  barGap={3}
                >
                  <CartesianGrid strokeDasharray="3 3" stroke={t.cardBorder} opacity={0.5} />
                  <XAxis
                    dataKey="label"
                    tick={{ fontSize: 10, fill: t.textMuted, fontFamily: FONT.body }}
                    interval="preserveStartEnd"
                    tickLine={false}
                  />
                  <YAxis
                    tick={{ fontSize: 10, fill: t.textMuted, fontFamily: FONT.body }}
                    width={isBRLKpiGraficoDetalhe ? 72 : 44}
                    tickFormatter={(v) =>
                      isBRLKpiGraficoDetalhe ? `R$${(v / 1000).toFixed(0)}K` : v.toLocaleString("pt-BR")
                    }
                    tickLine={false}
                    axisLine={false}
                  />
                  <Tooltip content={<TooltipDetalheOperadoras />} />
                  <Legend wrapperStyle={{ fontSize: 12, color: t.textMuted, fontFamily: FONT.body }} />
                  {slugsGraficoDetalhe.map((slug) => (
                    <Bar
                      key={slug}
                      dataKey={slug}
                      name={slugToNome(slug)}
                      fill={coresOperadorasDetalhe.get(slug) ?? "var(--brand-action, #7c3aed)"}
                      radius={[4, 4, 0, 0]}
                      maxBarSize={28}
                    />
                  ))}
                </BarChart>
              ) : (
                <LineChart
                  data={dadosGraficoDetalheOperadoras as Record<string, string | number | null>[]}
                  margin={{ top: 8, right: 16, left: 8, bottom: 4 }}
                >
                  <CartesianGrid strokeDasharray="3 3" stroke={t.cardBorder} opacity={0.5} />
                  <XAxis
                    dataKey="label"
                    tick={{ fontSize: 10, fill: t.textMuted, fontFamily: FONT.body }}
                    interval="preserveStartEnd"
                    tickLine={false}
                  />
                  <YAxis
                    tick={{ fontSize: 10, fill: t.textMuted, fontFamily: FONT.body }}
                    width={isBRLKpiGraficoDetalhe ? 72 : 44}
                    tickFormatter={(v) =>
                      isBRLKpiGraficoDetalhe
                        ? `R$${(v / 1000).toFixed(0)}K`
                        : kpiGraficoDetalhe === "margin_pct"
                          ? `${v.toFixed(0)}%`
                          : v.toLocaleString("pt-BR")
                    }
                    tickLine={false}
                    axisLine={false}
                  />
                  <Tooltip content={<TooltipDetalheOperadoras />} />
                  <Legend wrapperStyle={{ fontSize: 12, color: t.textMuted, fontFamily: FONT.body }} />
                  {slugsGraficoDetalhe.map((slug) => (
                    <Line
                      key={slug}
                      type="monotone"
                      name={slugToNome(slug)}
                      dataKey={slug}
                      stroke={coresOperadorasDetalhe.get(slug) ?? "var(--brand-action, #7c3aed)"}
                      strokeWidth={2}
                      dot={{ r: 2 }}
                      connectNulls
                    />
                  ))}
                </LineChart>
              )}
            </ResponsiveContainer>
          </div>
        </>
      )}
    </>
  );

  const renderComparativoJogoInterativo = (colTempoLabel: "Data" | "Mês") => (
    <>
      <div
        style={{
          display: "flex",
          alignItems: "center",
          justifyContent: "space-between",
          flexWrap: "wrap",
          gap: 10,
          marginBottom: 16,
        }}
      >
        <div style={{ display: "flex", flexDirection: "column", gap: 4 }}>
          <div style={{ display: "flex", gap: 6, flexWrap: "wrap", alignItems: "center" }}>
            <span
              style={{
                fontSize: 10,
                color: t.textMuted,
                fontFamily: FONT.body,
                fontWeight: 600,
                letterSpacing: "0.08em",
                textTransform: "uppercase" as const,
                marginRight: 2,
              }}
            >
              KPIs visíveis:
            </span>
            {KPIS_DISPONIVEIS.map((kpi) => {
              const ativo =
                modoVisualizacao === "tabela"
                  ? kpisSelecionados.has(kpi.key)
                  : kpiGrafico === kpi.key;
              return (
                <button
                  type="button"
                  role="button"
                  key={kpi.key}
                  aria-pressed={ativo}
                  aria-label={
                    modoVisualizacao === "tabela"
                      ? `${ativo ? "Desativar" : "Ativar"} KPI ${kpi.label}`
                      : `KPI do gráfico: ${kpi.label}`
                  }
                  onClick={() => {
                    if (modoVisualizacao === "tabela") {
                      setKpisSelecionados((prev) => {
                        const next = new Set(prev);
                        if (next.has(kpi.key) && next.size === 1) return prev;
                        if (next.has(kpi.key)) next.delete(kpi.key);
                        else next.add(kpi.key);
                        return next;
                      });
                    } else {
                      setKpiGrafico(kpi.key);
                    }
                  }}
                  style={{
                    display: "inline-flex",
                    alignItems: "center",
                    gap: 5,
                    padding: "8px 14px",
                    minHeight: 40,
                    borderRadius: 10,
                    cursor: "pointer",
                    fontFamily: FONT.body,
                    fontSize: 12,
                    fontWeight: ativo ? 700 : 500,
                    border: `1px solid ${ativo ? brand.accent : t.cardBorder}`,
                    background: ativo
                      ? brand.useBrand
                        ? "color-mix(in srgb, var(--brand-contrast, #1e36f8) 15%, transparent)"
                        : "color-mix(in srgb, var(--brand-action, #7c3aed) 15%, transparent)"
                      : (t.inputBg ?? t.cardBg),
                    color: ativo ? brand.accent : t.textMuted,
                    transition: "all 0.15s",
                  }}
                >
                  <span
                    style={{
                      width: 6,
                      height: 6,
                      borderRadius: "50%",
                      background: ativo ? brand.accent : t.cardBorder,
                      flexShrink: 0,
                      transition: "background 0.15s",
                    }}
                  />
                  {kpi.label}
                </button>
              );
            })}
          </div>
          {modoVisualizacao === "grafico" && (
            <span style={{ fontSize: 10, color: t.textMuted, fontFamily: FONT.body }}>
              Selecione um KPI para o gráfico
            </span>
          )}
        </div>

        <div
          style={{
            display: "flex",
            border: `1px solid ${t.cardBorder}`,
            borderRadius: 10,
            overflow: "hidden",
          }}
        >
          {(
            [
              { modo: "tabela" as const, icon: <Table2 size={14} aria-hidden />, label: "Tabela" },
              { modo: "grafico" as const, icon: <ChartColumnBig size={14} aria-hidden />, label: "Gráfico" },
            ] as const
          ).map(({ modo, icon, label }) => (
            <button
              type="button"
              key={modo}
              aria-label={`Ver em ${label}`}
              aria-pressed={modoVisualizacao === modo}
              onClick={() => setModoVisualizacao(modo)}
              style={{
                display: "flex",
                alignItems: "center",
                gap: 5,
                padding: "6px 12px",
                border: "none",
                cursor: "pointer",
                fontFamily: FONT.body,
                fontSize: 11,
                fontWeight: modoVisualizacao === modo ? 700 : 400,
                background:
                  modoVisualizacao === modo ? `color-mix(in srgb, ${brand.accent} 12%, transparent)` : "transparent",
                color: modoVisualizacao === modo ? brand.accent : t.textMuted,
                transition: "all 0.15s",
                borderRight: modo === "tabela" ? `1px solid ${t.cardBorder}` : "none",
              }}
            >
              {icon} {label}
            </button>
          ))}
        </div>
      </div>

      {modoVisualizacao === "tabela" ? (
        <div className="app-table-wrap" style={{ borderRadius: 14, overflow: "hidden" }}>
          <div style={{ overflowX: "auto" }}>
            <table
              style={{
                width: "100%",
                borderCollapse: "collapse",
                minWidth: minWidthTabelaComparativoJogo,
              }}
            >
              <caption style={{ display: "none" }}>
                Comparativo de jogo {colTempoLabel === "Mês" ? "histórico" : (mesSelecionado?.label ?? "")}
              </caption>
              <thead>
                <tr>
                  <th rowSpan={2} scope="col" style={thStickyComparativo}>
                    {colTempoLabel}
                  </th>
                  {kpisAtivosComparativo.map((kpi) => (
                    <th
                      key={kpi.key}
                      colSpan={4}
                      scope="colgroup"
                      style={{
                        ...thStyle,
                        textAlign: "center",
                        borderLeft: `2px solid ${t.cardBorder}`,
                        borderBottom: "none",
                      }}
                    >
                      {kpi.label}
                    </th>
                  ))}
                </tr>
                <tr>
                  {kpisAtivosComparativo.map((kpi) => (
                    <Fragment key={`sub-${kpi.key}`}>
                      <th
                        scope="col"
                        style={{
                          ...thJogoComparativoSub,
                          borderLeft: `2px solid ${t.cardBorder}`,
                          fontSize: 9,
                          color: t.text,
                          fontWeight: 700,
                        }}
                      >
                        Total
                      </th>
                      {JOGOS_COMPARATIVO.map((jogo) => (
                        <th
                          key={jogo.key}
                          scope="col"
                          style={{
                            ...thJogoComparativoSub,
                            fontSize: 9,
                            fontWeight: 600,
                            color: jogo.cor,
                            letterSpacing: "0.04em",
                            textTransform: "none",
                          }}
                        >
                          {jogo.label}
                        </th>
                      ))}
                    </Fragment>
                  ))}
                </tr>
              </thead>
              <tbody>
                {linhasComparativoJogo.map((row, i) => {
                  const totaisOficiais = row.totaisOficiais;
                  return (
                    <tr
                      key={row.dataIso}
                      style={{
                        background: zebraTabelaSpin(i),
                      }}
                    >
                      <th scope="row" style={tdStickyComparativo(i)}>
                        {row.labelData}
                      </th>
                      {kpisAtivosComparativo.map((kpi) => (
                        <Fragment key={`${row.dataIso}-${kpi.key}`}>
                          <td
                            style={{
                              ...tdNum,
                              textAlign: "right",
                              fontVariantNumeric: "tabular-nums",
                              borderLeft: `2px solid ${t.cardBorder}`,
                              fontWeight: 700,
                              color: t.text,
                            }}
                          >
                            {renderValorKpiComparativo(kpi, totaisOficiais[kpi.key])}
                          </td>
                          {JOGOS_COMPARATIVO.map((jogo) => {
                            const cel = row[jogo.key];
                            const valorJogo = cel[kpi.key] as number | null;
                            const pct = calcularPctComparativoOficial(valorJogo, row, kpi);
                            return (
                              <td
                                key={jogo.key}
                                style={{
                                  ...tdNum,
                                  textAlign: "right",
                                  fontVariantNumeric: "tabular-nums",
                                  color: jogo.cor,
                                  fontWeight: 600,
                                }}
                              >
                                {valorJogo != null ? (
                                  <div
                                    style={{
                                      display: "flex",
                                      flexDirection: "column",
                                      alignItems: "flex-end",
                                      gap: 1,
                                    }}
                                  >
                                    <span>{renderValorKpiComparativo(kpi, valorJogo)}</span>
                                    {kpi.somavel && pct != null && (
                                      <span
                                        style={{
                                          fontSize: 10,
                                          color: t.textMuted,
                                          fontWeight: 700,
                                          opacity: 0.75,
                                        }}
                                      >
                                        {pct.toFixed(0)}%
                                      </span>
                                    )}
                                  </div>
                                ) : (
                                  "—"
                                )}
                              </td>
                            );
                          })}
                        </Fragment>
                      ))}
                    </tr>
                  );
                })}
              </tbody>
            </table>
          </div>
        </div>
      ) : linhasComparativoJogo.length === 0 ? (
        <div
          style={{
            padding: "24px 0",
            textAlign: "center",
            color: t.textMuted,
            fontSize: 12,
            fontFamily: FONT.body,
          }}
        >
          {MSG_SEM_DADOS_FILTRO}
        </div>
      ) : (
        <>
          <p
            style={{
              fontSize: 11,
              color: t.textMuted,
              fontFamily: FONT.body,
              marginBottom: 8,
              marginTop: 0,
            }}
          >
            Exibindo <strong style={{ color: t.text }}>{kpiGraficoConfig.label}</strong> por jogo
          </p>
          <div
            role="img"
            aria-label={`Gráfico de ${kpiGraficoConfig.label} por jogo — ${historico ? "todo o período" : mesSelecionado?.label ?? ""}`}
            style={{ width: "100%", height: "clamp(220px, 35vh, 420px)", minHeight: 220 }}
          >
            <ResponsiveContainer width="100%" height="100%">
              {kpiGraficoConfig.tipoGrafico === "barra" ? (
                <BarChart
                  data={dadosGraficoComparativoJogo}
                  margin={{ top: 8, right: 16, left: 8, bottom: 4 }}
                  barCategoryGap="30%"
                  barGap={3}
                >
                  <CartesianGrid strokeDasharray="3 3" stroke={t.cardBorder} opacity={0.5} />
                  <XAxis
                    dataKey="label"
                    tick={{ fontSize: 10, fill: t.textMuted, fontFamily: FONT.body }}
                    interval="preserveStartEnd"
                    tickLine={false}
                  />
                  <YAxis
                    tick={{ fontSize: 10, fill: t.textMuted, fontFamily: FONT.body }}
                    width={isBRLKpiGrafico ? 72 : 44}
                    tickFormatter={(v) =>
                      isBRLKpiGrafico ? `R$${(v / 1000).toFixed(0)}K` : v.toLocaleString("pt-BR")
                    }
                    tickLine={false}
                    axisLine={false}
                  />
                  <Tooltip content={<TooltipComparativoJogo />} />
                  <Legend wrapperStyle={{ fontSize: 12, color: t.textMuted, fontFamily: FONT.body }} />
                  <Bar
                    dataKey="Blackjack"
                    fill={COR_BLACKJACK}
                    radius={[4, 4, 0, 0]}
                    maxBarSize={32}
                  />
                  <Bar dataKey="Roleta" fill={COR_ROLETA} radius={[4, 4, 0, 0]} maxBarSize={32} />
                  <Bar dataKey="Baccarat" fill={COR_BACCARAT} radius={[4, 4, 0, 0]} maxBarSize={32} />
                </BarChart>
              ) : (
                <LineChart
                  data={dadosGraficoComparativoJogo}
                  margin={{ top: 8, right: 16, left: 8, bottom: 4 }}
                >
                  <CartesianGrid strokeDasharray="3 3" stroke={t.cardBorder} opacity={0.5} />
                  <XAxis
                    dataKey="label"
                    tick={{ fontSize: 10, fill: t.textMuted, fontFamily: FONT.body }}
                    interval="preserveStartEnd"
                    tickLine={false}
                  />
                  <YAxis
                    tick={{ fontSize: 10, fill: t.textMuted, fontFamily: FONT.body }}
                    width={isBRLKpiGrafico ? 72 : 44}
                    tickFormatter={(v) =>
                      isBRLKpiGrafico
                        ? `R$${(v / 1000).toFixed(0)}K`
                        : kpiGrafico === "margin_pct"
                          ? `${v.toFixed(0)}%`
                          : v.toLocaleString("pt-BR")
                    }
                    tickLine={false}
                    axisLine={false}
                  />
                  <Tooltip content={<TooltipComparativoJogo />} />
                  <Legend wrapperStyle={{ fontSize: 12, color: t.textMuted, fontFamily: FONT.body }} />
                  <Line
                    type="monotone"
                    name="Blackjack"
                    dataKey="Blackjack"
                    stroke={COR_BLACKJACK}
                    strokeWidth={2}
                    dot={{ r: 2 }}
                    connectNulls
                  />
                  <Line
                    type="monotone"
                    name="Roleta"
                    dataKey="Roleta"
                    stroke={COR_ROLETA}
                    strokeWidth={2}
                    dot={{ r: 2 }}
                    connectNulls
                  />
                  <Line
                    type="monotone"
                    name="Baccarat"
                    dataKey="Baccarat"
                    stroke={COR_BACCARAT}
                    strokeWidth={2}
                    dot={{ r: 2 }}
                    connectNulls
                  />
                </LineChart>
              )}
            </ResponsiveContainer>
          </div>
        </>
      )}
    </>
  );

  if (perm.canView === "nao") {
    return (
      <div style={{ padding: 24, textAlign: "center", color: t.textMuted, fontFamily: FONT.body }}>
        Você não tem permissão para visualizar este dashboard.
      </div>
    );
  }

  return (
    <div
      className="app-page-shell app-page-shell--pb64"
      style={{ background: t.bg, minHeight: "100vh", fontFamily: FONT.body }}
    >
      <div style={{ display: "flex", alignItems: "flex-start", gap: 14, marginBottom: 18, flexWrap: "wrap" }}>
        <div style={{ display: "flex", alignItems: "center", gap: 14 }}>
          <div
            style={{
              width: 28,
              height: 28,
              borderRadius: 8,
              background: brand.primaryIconBg,
              border: brand.primaryIconBorder,
              display: "flex",
              alignItems: "center",
              justifyContent: "center",
              flexShrink: 0,
              color: brand.primaryIconColor,
            }}
          >
            <LayoutGrid size={14} aria-hidden />
          </div>
          <div>
            <h1
              style={{
                fontSize: 22,
                fontWeight: 800,
                color: brand.primary,
                fontFamily: FONT_TITLE,
                margin: 0,
                letterSpacing: "0.5px",
                textTransform: "uppercase",
              }}
            >
              Overview Spin
            </h1>
            <p style={{ color: t.textMuted, fontFamily: FONT.body, fontSize: 13, margin: "5px 0 0" }}>
              Resultados consolidados das mesas ao vivo — Baccarat, Roleta e Blackjack.
            </p>
          </div>
        </div>
      </div>

      <div style={{ marginBottom: 14 }}>
        <div
          style={{
            borderRadius: 14,
            border: `1px solid ${t.cardBorder}`,
            background: brand.blockBg,
            padding: "12px 20px",
          }}
        >
          <div
            style={{
              display: "flex",
              alignItems: "center",
              justifyContent: "center",
              gap: 10,
              flexWrap: "wrap",
            }}
          >
            <button
              type="button"
              aria-label="Mês anterior"
              style={{
                ...btnNav,
                opacity: historico || isPrimeiro ? 0.35 : 1,
                cursor: historico || isPrimeiro ? "not-allowed" : "pointer",
              }}
              onClick={irMesAnterior}
              disabled={historico || isPrimeiro}
            >
              <ChevronLeft size={14} aria-hidden />
            </button>
            <span
              style={{
                fontSize: 18,
                fontWeight: 800,
                color: t.text,
                fontFamily: FONT.body,
                minWidth: "min(100%, 180px)",
                textAlign: "center",
              }}
            >
              {historico ? "Todo o período" : mesSelecionado?.label}
            </span>
            <button
              type="button"
              aria-label="Próximo mês"
              style={{
                ...btnNav,
                opacity: historico || isUltimo ? 0.35 : 1,
                cursor: historico || isUltimo ? "not-allowed" : "pointer",
              }}
              onClick={irMesProximo}
              disabled={historico || isUltimo}
            >
              <ChevronRight size={14} aria-hidden />
            </button>

            <button
              type="button"
              aria-label={historico ? "Desativar modo histórico" : "Ativar modo histórico — ver todo o período"}
              aria-pressed={historico}
              onClick={toggleHistorico}
              style={{
                display: "flex",
                alignItems: "center",
                gap: 6,
                padding: "6px 14px",
                borderRadius: 999,
                cursor: "pointer",
                fontFamily: FONT.body,
                fontSize: 13,
                border: historico ? `1px solid ${brand.accent}` : `1px solid ${t.cardBorder}`,
                background: historico
                  ? brand.useBrand
                    ? "color-mix(in srgb, var(--brand-contrast, #1e36f8) 15%, transparent)"
                    : "color-mix(in srgb, var(--brand-action, #7c3aed) 15%, transparent)"
                  : "transparent",
                color: historico ? brand.accent : t.textMuted,
                fontWeight: historico ? 700 : 400,
                transition: "all 0.15s",
              }}
            >
              <Calendar size={15} aria-hidden /> Histórico
            </button>

            {showFiltroOperadora && (
              <SelectComIcone
                icon={<Shield size={15} aria-hidden />}
                label="Filtrar por operadora"
                value={filtroOperadora}
                onChange={setFiltroOperadora}
              >
                <option value="todas">Todas as operadoras</option>
                {operadorasOcr
                  .filter((o) => podeVerOperadora(o.slug))
                  .sort((a, b) => a.nome.localeCompare(b.nome, "pt-BR"))
                  .map((o) => (
                    <option key={o.slug} value={o.slug}>
                      {o.nome}
                    </option>
                  ))}
              </SelectComIcone>
            )}

            {loading && (
              <span
