  const resolved =
    brand.useBrand && accentVar != null && accentVar !== ""
      ? resolveWhitelabelAccentCss(accentVar) ?? "var(--brand-action, #7c3aed)"
      : accentCor;
  const barBg = brand.useBrand
    ? `linear-gradient(90deg, ${resolved}, transparent)`
