            </span>
          ))}
        </div>
        {dealer.perfil_influencer ? (
          <p
            style={{
              fontSize: 12,
              color: t.textMuted,
              fontFamily: FONT.body,
              lineHeight: 1.4,
              margin: "0 0 12px",
              overflow: "hidden",
              display: "-webkit-box",
              WebkitLineClamp: 3,
              WebkitBoxOrient: "vertical",
