          </p>
        ) : null}
        {/* Ocupa o espaço vertical restante para alinhar género e botões entre cards da mesma linha */}
        <div style={{ flex: 1, minHeight: 0 }} aria-hidden />
        <div style={{ display: "flex", gap: 6, flexWrap: "wrap", marginBottom: 14 }}>
