        >
          <h2
            style={{
              margin: "0 0 14px 0",
              fontSize: 13,
              fontWeight: 800,
              color: t.sectionTitle,
              fontFamily: FONT_TITLE,
              letterSpacing: "0.08em",
              textTransform: "uppercase",
            }}
          >
            Próximas lives
          </h2>
          <div
            style={{
              display: "grid",
              gridTemplateColumns: "repeat(auto-fill, minmax(min(100%, 240px), 1fr))",
