                <div style={{ display: "flex", alignItems: "center", gap: 8 }}>
                  <PlatLogoHome plataforma={live.plataforma} size={22} isDark={isDark} />
                  <span style={{ fontSize: 13, fontWeight: 600, color: t.textMuted }}>{live.plataforma}</span>
