// ─── STATUS ───────────────────────────────────────────────────────────────────
const STATUS_COLOR: Record<string, string> = {
  agendada:      BRAND.azul,
  realizada:     BRAND.verde,
  nao_realizada: BRAND.vermelho,
};

const STATUS_LABEL: Record<string, string> = {
  agendada:      "Agendada",
  realizada:     "Realizada",
  nao_realizada: "Não Realizada",
};

// ─── CALENDÁRIO ───────────────────────────────────────────────────────────────
type ViewMode = "mes" | "semana" | "dia";

const MONTHS = ["Janeiro","Fevereiro","Março","Abril","Maio","Junho","Julho","Agosto","Setembro","Outubro","Novembro","Dezembro"];
const DAYS   = ["Dom","Seg","Ter","Qua","Qui","Sex","Sáb"];

function getWeekDays(date: Date): Date[] {
  const day = date.getDay();
  const start = new Date(date);
  start.setDate(date.getDate() - day);
  return Array.from({ length: 7 }, (_, i) => {
    const d = new Date(start);
    d.setDate(start.getDate() + i);
    return d;
  });
}

function getMonthDays(year: number, month: number): (Date | null)[] {
  const first = new Date(year, month, 1).getDay();
  const total = new Date(year, month + 1, 0).getDate();
  const cells: (Date | null)[] = Array(first).fill(null);
  for (let d = 1; d <= total; d++) cells.push(new Date(year, month, d));
  return cells;
}

function toISO(d: Date) {
  return d.toISOString().split("T")[0];
}

// ─── SINGLE DROPDOWN (Visualização) ──────────────────────────────────────────
interface SingleDropdownProps {
  value: string;
  options: { value: string; label: string }[];
  onChange: (v: string) => void;
  icon?: React.ReactNode;
  t: any;
}

function SingleDropdown({ value, options, onChange, icon, t, accent }: SingleDropdownProps & { accent?: string }) {
  const [open, setOpen] = useState(false);
  const ref = useRef<HTMLDivElement>(null);
  const accentColor = accent ?? BRAND.roxoVivo;

  useEffect(() => {
    function handleClick(e: MouseEvent) {
      if (ref.current && !ref.current.contains(e.target as Node)) setOpen(false);
    }
    document.addEventListener("mousedown", handleClick);
    return () => document.removeEventListener("mousedown", handleClick);
  }, []);

  const current = options.find(o => o.value === value);

  return (
    <div ref={ref} style={{ position: "relative" }}>
      <button
        type="button"
        onClick={() => setOpen(!open)}
        aria-haspopup="menu"
        aria-expanded={open}
        aria-label={`Modo de visualização: ${current?.label ?? value}`}
        style={{
          padding: "6px 14px", borderRadius: 999,
          border: `1px solid ${accentColor}`,
          background: accentColor.startsWith("var(") ? "color-mix(in srgb, var(--brand-contrast, #1e36f8) 15%, transparent)" : `${accentColor}22`,
          color: accentColor,
          fontSize: 13, fontWeight: 600, fontFamily: FONT.body,
          cursor: "pointer", outline: "none",
          display: "flex", alignItems: "center", gap: 6,
          whiteSpace: "nowrap" as const,
          lineHeight: 1,
        }}
      >
        {icon && <span style={{ display: "inline-flex", alignItems: "center", lineHeight: 0 }}>{icon}</span>}
        <span style={{ display: "inline-flex", alignItems: "center" }}>{current?.label}</span>
        {open ? <ChevronUp size={9} style={{ opacity: 0.7 }} aria-hidden="true" /> : <ChevronDown size={9} style={{ opacity: 0.7 }} aria-hidden="true" />}
      </button>

      {open && (
        <div
          role="menu"
          style={{
            position: "absolute", top: "calc(100% + 6px)", left: 0, zIndex: 200,
            background: t.cardBg, border: `1px solid ${t.cardBorder}`,
            borderRadius: 12, padding: 8, minWidth: 130,
            boxShadow: "0 8px 24px rgba(0,0,0,0.3)",
          }}
        >
          {options.map(opt => {
            const selected = opt.value === value;
            return (
              <button
                type="button"
                role="menuitem"
                key={opt.value}
                onClick={() => { onChange(opt.value); setOpen(false); }}
                style={{
                  width: "100%", padding: "8px 12px", borderRadius: 8,
                  border: "none",
                  background: selected ? (accentColor.startsWith("var(") ? "color-mix(in srgb, var(--brand-contrast, #1e36f8) 15%, transparent)" : `${accentColor}22`) : "transparent",
                  color: selected ? accentColor : t.text,
                  fontSize: 12, fontFamily: FONT.body,
                  cursor: "pointer", textAlign: "left",
                  display: "flex", alignItems: "center", gap: 8,
                  fontWeight: selected ? 700 : 400,
                }}
              >
                <span style={{
                  width: 14, height: 14, borderRadius: "50%", flexShrink: 0,
                  border: `1.5px solid ${selected ? accentColor : t.cardBorder}`,
                  background: selected ? accentColor : "transparent",
                  display: "flex", alignItems: "center", justifyContent: "center",
                }}>
                  {selected ? <Check size={9} color="#fff" aria-hidden="true" /> : null}
                </span>
                {opt.label}
              </button>
            );
          })}
        </div>
      )}
    </div>
  );
}

// ─── COMPONENTE PRINCIPAL ─────────────────────────────────────────────────────
export default function Agenda() {
  const { theme: t, isDark, user, setActivePage } = useApp();
  const brand = useDashboardBrand();
  const { showFiltroInfluencer, showFiltroOperadora, podeVerInfluencer, podeVerOperadora, escoposVisiveis: _escoposVisiveis, operadoraSlugsForcado } = useDashboardFiltros();
  const perm = usePermission("agenda");

  const [view,    setView]    = useState<ViewMode>("mes");
  const [current, setCurrent] = useState(new Date());
  const [lives,   setLives]   = useState<Live[]>([]);
  const [loading, setLoading] = useState(true);
  const [modal,   setModal]   = useState<{ open: boolean; live?: Live }>({ open: false });
  const [bloqueioNovaLive, setBloqueioNovaLive] = useState<{
    perfilIncompleto: boolean;
    faltaPlaybook: boolean;
  } | null>(null);
  const [checandoNovaLive, setChecandoNovaLive] = useState(false);

  const [filterStatus,      setFilterStatus]      = useState<string | null>(null);
  const [filterPlat,        setFilterPlat]        = useState<string | null>(null);
  const [filterInfluencers, setFilterInfluencers] = useState<string[]>([]);
  const [filterOperadora,   setFilterOperadora]   = useState<string>("todas");
  const [influencerList,    setInfluencerList]    = useState<{ id: string; name: string }[]>([]);
  const [operadorasList,    setOperadorasList]    = useState<{ slug: string; nome: string }[]>([]);

  const hasActiveFilters = filterStatus !== null || filterPlat !== null || filterInfluencers.length > 0 || filterOperadora !== "todas";

  const influencerListVisiveis = useMemo(
    () => influencerList.filter((i) => podeVerInfluencer(i.id)),
    [influencerList, podeVerInfluencer]
  );
  async function loadLives() {
    setLoading(true);
    let q = supabase.from("lives").select("*, profiles!lives_influencer_id_fkey(name)").order("data", { ascending: true }).order("horario", { ascending: true });
    if (operadoraSlugsForcado?.length) q = q.in("operadora_slug", operadoraSlugsForcado);
    const { data, error } = await q;
    if (!error && data) {
      const mapped = data.map((l: any) => ({ ...l, influencer_name: l.profiles?.name }));
      setLives(mapped.filter((l: Live) => podeVerInfluencer(l.influencer_id)));
    }
    setLoading(false);
  }

  useEffect(() => { loadLives(); }, [podeVerInfluencer, operadoraSlugsForcado]);

  useEffect(() => {
    if (showFiltroInfluencer || showFiltroOperadora) {
      Promise.all([
        showFiltroInfluencer ? supabase.from("profiles").select("id, name").eq("role", "influencer").order("name") : Promise.resolve({ data: [] }),
        showFiltroOperadora  ? supabase.from("operadoras").select("slug, nome").order("nome") : Promise.resolve({ data: [] }),
      ]).then(([profRes, opsRes]) => {
        if (showFiltroInfluencer && profRes.data) setInfluencerList(profRes.data);
        if (showFiltroOperadora)  setOperadorasList((opsRes.data ?? []) as { slug: string; nome: string }[]);
      });
    }
  }, [showFiltroInfluencer, showFiltroOperadora]);

  const operadoraEfetiva = operadoraSlugsForcado ?? (filterOperadora !== "todas" ? [filterOperadora] : null);
  function livesForDay(date: Date): Live[] {
    const iso = toISO(date);
    return lives.filter(l => {
      if (l.data !== iso) return false;
      if (filterStatus && l.status !== filterStatus) return false;
      if (filterPlat   && l.plataforma !== filterPlat) return false;
      if (filterInfluencers.length > 0 && !filterInfluencers.includes(l.influencer_id)) return false;
      if (operadoraEfetiva && (!l.operadora_slug || !operadoraEfetiva.includes(l.operadora_slug))) return false;
      return true;
    });
  }

  function prev() {
    const d = new Date(current);
    if (view === "mes")    d.setMonth(d.getMonth() - 1);
    if (view === "semana") d.setDate(d.getDate() - 7);
    if (view === "dia")    d.setDate(d.getDate() - 1);
    setCurrent(d);
  }
  function next() {
    const d = new Date(current);
    if (view === "mes")    d.setMonth(d.getMonth() + 1);
    if (view === "semana") d.setDate(d.getDate() + 7);
    if (view === "dia")    d.setDate(d.getDate() + 1);
    setCurrent(d);
  }
  function goToday() { setCurrent(new Date()); }

  function headerTitle() {
    if (view === "mes")    return `${MONTHS[current.getMonth()]} ${current.getFullYear()}`;
    if (view === "semana") {
      const w = getWeekDays(current);
      return `${w[0].getDate()} – ${w[6].getDate()} ${MONTHS[w[6].getMonth()]} ${w[6].getFullYear()}`;
    }
    return `${current.getDate()} ${MONTHS[current.getMonth()]} ${current.getFullYear()}`;
  }

  // ── Estilos de dia por estado ────────────────────────────────────────────────
  function dayStyle(date: Date, todayISO: string): React.CSSProperties {
    const iso = toISO(date);
    if (iso === todayISO) return {
      border: `1.5px solid ${BRAND.azul}55`,
      background: isDark ? "rgba(30,54,248,0.10)" : "rgba(30,54,248,0.06)",
    };
    if (iso < todayISO) return {
      border: `1.5px solid rgba(232,64,37,0.22)`,
      background: isDark ? "rgba(232,64,37,0.07)" : "rgba(232,64,37,0.04)",
    };
    return {
      border: `1.5px solid rgba(34,197,94,0.22)`,
      background: isDark ? "rgba(34,197,94,0.07)" : "rgba(34,197,94,0.04)",
    };
  }

  function dayNumberColor(date: Date, todayISO: string) {
    const iso = toISO(date);
    if (iso === todayISO) return BRAND.azul;
    if (iso < todayISO)   return isDark ? "rgba(232,64,37,0.65)"  : "rgba(232,64,37,0.75)";
    return                       isDark ? "rgba(34,197,94,0.75)"  : "rgba(34,197,94,0.85)";
  }

  const card: React.CSSProperties = {
    background: brand.blockBg,
    border: `1px solid ${t.cardBorder}`,
    borderRadius: 18,
    padding: 20,
    boxShadow: "0 4px 20px rgba(0,0,0,0.18)",
  };

  const DEFAULT_CHIP_COLOR = "var(--brand-action, #7c3aed)";
  function chipActiveBg(color: string): string {
    if (color.startsWith("var(")) return `color-mix(in srgb, ${color} 14%, transparent)`;
    return `${color}22`;
  }

  const btnNav: React.CSSProperties = {
    width: 30, height: 30, borderRadius: "50%",
    border: `1px solid ${t.cardBorder}`,
    background: "transparent", color: t.text, cursor: "pointer",
    display: "flex", alignItems: "center", justifyContent: "center",
  };

  const chipBase = (active: boolean, color: string = DEFAULT_CHIP_COLOR): React.CSSProperties => ({
    padding: "6px 14px", borderRadius: 999, fontSize: 13,
    cursor: "pointer", border: `1px solid ${active ? color : t.cardBorder}`,
    background: active ? chipActiveBg(color) : "transparent",
    color: active ? color : t.textMuted,
    fontFamily: FONT.body, fontWeight: active ? 700 : 400,
    transition: "all 0.15s",
    display: "flex", alignItems: "center", gap: 6,
    lineHeight: 1,
  });

  // ── Chip de live no calendário ───────────────────────────────────────────────
  function LiveChip({ live }: { live: Live }) {
    return (
      <button
        type="button"
        onClick={() => setModal({ open: true, live })}
        aria-label={`${live.horario.slice(0, 5)} · ${live.influencer_name ?? live.plataforma} — ${STATUS_LABEL[live.status]}`}
        style={{
          display: "flex", alignItems: "center", gap: 6,
          padding: "5px 8px", borderRadius: 8, cursor: "pointer",
          background: `${PLAT_COLOR[live.plataforma]}22`,
          border: `1px solid ${PLAT_COLOR[live.plataforma]}44`,
          marginBottom: 4,
          width: "100%",
          textAlign: "left",
          lineHeight: 1,
        }}
      >
        <span style={{
          width: 8, height: 8, borderRadius: "50%",
          background: STATUS_COLOR[live.status], flexShrink: 0,
        }} />
        <span style={{ fontSize: 12, fontWeight: 500, color: t.text, fontFamily: FONT.body, whiteSpace: "nowrap", overflow: "hidden", textOverflow: "ellipsis" }}>
          {live.horario.slice(0, 5)}{live.influencer_name ? ` · ${live.influencer_name}` : ""}
        </span>
      </button>
    );
  }

  // ── View Mês ─────────────────────────────────────────────────────────────────
  function ViewMes() {
    const cells    = getMonthDays(current.getFullYear(), current.getMonth());
    const todayISO = toISO(new Date());
    return (
      <div className="app-agenda-cal-scroll">
        <div className="app-agenda-cal-scroll-inner">
        <div style={{ display: "grid", gridTemplateColumns: "repeat(7, 1fr)", gap: 4, marginBottom: 4 }}>
          {DAYS.map(d => (
            <div key={d} style={{ textAlign: "center", fontSize: 11, fontWeight: 700, color: t.textMuted, padding: "8px 0", fontFamily: FONT.body }}>
              {d}
            </div>
          ))}
        </div>
        <div style={{ display: "grid", gridTemplateColumns: "repeat(7, 1fr)", gridAutoRows: "minmax(140px, auto)", gap: 4 }}>
          {cells.map((date, i) => {
            if (!date) return <div key={i} />;
            const dayLives = livesForDay(date);
            return (
              <div
                key={i}
                style={{
                  minHeight: 140, padding: 8, borderRadius: 10,
                  display: "flex", flexDirection: "column", overflow: "hidden",
                  boxSizing: "border-box", transition: "background 0.15s",
                  ...dayStyle(date, todayISO),
                }}
              >
                <button
                  type="button"
                  onClick={() => { setCurrent(date); setView("dia"); }}
                  aria-label={`Ver lives de ${date.getDate()} de ${MONTHS[date.getMonth()]}`}
                  style={{
                    all: "unset",
                    cursor: "pointer",
                    width: "100%",
                    boxSizing: "border-box",
                    display: "flex",
                    justifyContent: "space-between",
                    alignItems: "center",
                    flexShrink: 0,
                    ...(dayLives.length === 0 ? { flex: 1, minHeight: 72 } : {}),
                  }}
                >
                  <span style={{ fontSize: 13, fontWeight: toISO(date) === todayISO ? 700 : 400, color: dayNumberColor(date, todayISO), fontFamily: FONT.body }}>
                    {date.getDate()}
                  </span>
                  {dayLives.length > 0 && (
                    <span
                      aria-label={`${dayLives.length} live${dayLives.length > 1 ? "s" : ""} neste dia`}
                      style={{ fontSize: 10, fontWeight: 700, color: "#fff", background: brand.accent, borderRadius: 10, padding: "1px 6px", fontFamily: FONT.body }}
                    >
                      {dayLives.length}
                    </span>
                  )}
                </button>
                <div className="agenda-day-scroll" style={{ marginTop: 4, flex: 1, minHeight: 0, overflowY: "auto" }}>
                  {dayLives.slice(0, 8).map(l => <LiveChip key={l.id} live={l} />)}
                  {dayLives.length > 8 && (
                    <button
                      type="button"
                      onClick={() => {
                        setCurrent(date);
                        setView("dia");
                      }}
                      aria-label={`Ver mais ${dayLives.length - 8} lives`}
                      style={{
                        fontSize: 11,
                        color: t.textMuted,
                        fontFamily: FONT.body,
                        background: "none",
                        border: "none",
                        cursor: "pointer",
                        padding: 0,
                        textDecoration: "underline",
                        textUnderlineOffset: 2,
                      }}
                    >
                      +{dayLives.length - 8} mais
                    </button>
                  )}
                </div>
              </div>
            );
          })}
        </div>
        </div>
      </div>
    );
  }

  // ── View Semana ──────────────────────────────────────────────────────────────
  function ViewSemana() {
    const week     = getWeekDays(current);
    const todayISO = toISO(new Date());
    return (
      <div className="app-agenda-cal-scroll">
        <div className="app-agenda-cal-scroll-inner">
      <div style={{ display: "grid", gridTemplateColumns: "repeat(7, 1fr)", gap: 8 }}>
        {week.map((date, i) => {
          const dayLives = livesForDay(date);
          return (
            <div key={i} style={{ borderRadius: 12, padding: "10px 8px", minHeight: 200, ...dayStyle(date, todayISO) }}>
              <div style={{ textAlign: "center", marginBottom: 8 }}>
                <div style={{ fontSize: 11, color: t.textMuted, fontFamily: FONT.body }}>{DAYS[date.getDay()]}</div>
                <div style={{ fontSize: 22, fontWeight: 700, color: dayNumberColor(date, todayISO), fontFamily: FONT_TITLE }}>
                  {date.getDate()}
                </div>
                {dayLives.length > 0 && (
                  <div
                    aria-label={`${dayLives.length} live${dayLives.length > 1 ? "s" : ""} neste dia`}
                    style={{ fontSize: 10, fontWeight: 700, color: "#fff", background: brand.accent, borderRadius: 10, padding: "1px 8px", display: "inline-block", fontFamily: FONT.body, marginTop: 2 }}
                  >
                    {dayLives.length} live{dayLives.length > 1 ? "s" : ""}
                  </div>
                )}
              </div>
              {dayLives.map(l => <LiveChip key={l.id} live={l} />)}
              {dayLives.length === 0 && (
                <div style={{ fontSize: 11, color: t.textMuted, textAlign: "center", marginTop: 12, fontFamily: FONT.body }}>—</div>
              )}
            </div>
          );
        })}
      </div>
        </div>
      </div>
    );
  }

  // ── View Dia ─────────────────────────────────────────────────────────────────
  function ViewDia() {
    const dayLives = livesForDay(current);
    const todayISO = toISO(new Date());
    const isToday  = toISO(current) === todayISO;

    return (
      <div>
        <div style={{ textAlign: "center", marginBottom: 20 }}>
          <span style={{ fontSize: 32, fontWeight: 900, color: isToday ? BRAND.azul : t.text, fontFamily: FONT_TITLE }}>
            {current.getDate()}
          </span>
          <span style={{ fontSize: 16, color: t.textMuted, marginLeft: 8, fontFamily: FONT.body }}>
            {DAYS[current.getDay()]}
          </span>
          {dayLives.length > 0 && (
            <span
              aria-label={`${dayLives.length} live${dayLives.length > 1 ? "s" : ""} neste dia`}
              style={{ fontSize: 12, fontWeight: 700, color: "#fff", background: brand.accent, borderRadius: 12, padding: "2px 10px", marginLeft: 10, fontFamily: FONT.body }}
            >
              {dayLives.length} live{dayLives.length > 1 ? "s" : ""}
            </span>
          )}
        </div>

        {dayLives.length === 0 ? (
          <div style={{ textAlign: "center", color: t.textMuted, fontSize: 14, padding: "40px 0", fontFamily: FONT.body }}>
            Nenhuma live agendada para este dia.
          </div>
        ) : (
          <div style={{ display: "flex", flexDirection: "column", gap: 12 }}>
            {dayLives.map(l => (
              <div key={l.id} style={{ display: "flex", flexDirection: "column", gap: 6 }}>
                <button
                  type="button"
                  onClick={() => setModal({ open: true, live: l })}
                  aria-label={`Abrir live de ${l.influencer_name ?? l.plataforma} — ${l.horario.slice(0, 5)}`}
                  style={{
                    all: "unset",
                    display: "flex",
                    alignItems: "center",
                    gap: 14,
                    padding: 16,
                    borderRadius: 12,
                    cursor: "pointer",
                    width: "100%",
                    boxSizing: "border-box",
                    border: `1.5px solid ${PLAT_COLOR[l.plataforma]}44`,
                    background: `${PLAT_COLOR[l.plataforma]}0d`,
                  }}
                >
                  <div style={{
                    width: 44, height: 44, borderRadius: 10, flexShrink: 0,
                    background: `${PLAT_COLOR[l.plataforma]}22`,
                    border: `1.5px solid ${PLAT_COLOR[l.plataforma]}44`,
                    display: "flex", alignItems: "center", justifyContent: "center",
                  }}>
                    <PlatLogo plataforma={l.plataforma} size={22} isDark={isDark ?? false} />
                  </div>

                  <div style={{ flex: 1, minWidth: 0 }}>
                    {l.influencer_name && (
                      <div style={{ fontSize: 13, fontWeight: 700, color: t.text, fontFamily: FONT.body, marginBottom: 4 }}>
                        {l.influencer_name}
                      </div>
                    )}
                    <div style={{ display: "flex", gap: 8, flexWrap: "wrap", alignItems: "center" }}>
                      <span style={{
                        display: "inline-flex", alignItems: "center", gap: 5,
                        fontSize: 11, background: `${PLAT_COLOR[l.plataforma]}22`,
                        color: PLAT_COLOR[l.plataforma], padding: "3px 9px",
                        borderRadius: 20, fontFamily: FONT.body, fontWeight: 600,
                      }}>
                        <PlatLogo plataforma={l.plataforma} size={11} isDark={isDark ?? false} />
                        {l.plataforma}
                      </span>
                      <span style={{
                        fontSize: 11, background: `${STATUS_COLOR[l.status]}22`,
                        color: STATUS_COLOR[l.status], padding: "3px 9px",
                        borderRadius: 20, fontFamily: FONT.body, fontWeight: 600,
                        border: `1px solid ${STATUS_COLOR[l.status]}44`,
                      }}>
                        {STATUS_LABEL[l.status]}
                      </span>
                      <span style={{ fontSize: 11, color: t.textMuted, fontFamily: FONT.body, display: "inline-flex", alignItems: "center", gap: 4 }}>
                        <Clock size={11} aria-hidden="true" />
                        {l.horario.slice(0, 5)}
                      </span>
                    </div>
                  </div>
                </button>
                {l.link && (
                  <a
                    href={l.link.startsWith("http") ? l.link : `https://${l.link}`}
                    target="_blank" rel="noopener noreferrer"
                    style={{
                      display: "inline-flex", alignItems: "center", gap: 4,
                      marginLeft: 58,
                      fontSize: 11, color: BRAND.azul, fontFamily: FONT.body, textDecoration: "none", wordBreak: "break-all",
                    }}
                  >
                    <Link2 size={11} aria-hidden="true" />
                    {l.link}
                  </a>
                )}
              </div>
            ))}
          </div>
        )}
      </div>
    );
  }

  const VIEW_OPTIONS = [
    { value: "mes",    label: "Mês"    },
    { value: "semana", label: "Semana" },
    { value: "dia",    label: "Dia"    },
  ];

  async function tentarAbrirNovaLive() {
    if (!user) return;
    if (user.role === "influencer") {
      setChecandoNovaLive(true);
      try {
        const gate = await verificarElegibilidadeAgendaLive(user.id);
        if (gate.perfilIncompleto || gate.faltaPlaybook) {
          setBloqueioNovaLive(gate);
          return;
        }
      } finally {
        setChecandoNovaLive(false);
      }
    }
    setModal({ open: true });
  }

  if (perm.canView === "nao") {
    return (
      <div style={{ padding: 24, textAlign: "center", color: t.textMuted, fontFamily: FONT.body }}>
        Você não tem permissão para visualizar este dashboard.
      </div>
    );
  }

  return (
    <div className="app-page-shell" style={{ background: t.bg, minHeight: "100vh", fontFamily: FONT.body }}>

      <DashboardPageHeader
        icon={<CalendarRange size={14} aria-hidden="true" />}
        title="Agenda de Lives"
        subtitle="Calendário central de lives — visualize, agende e acompanhe lives de todos os influencers."
        brand={brand}
        t={t}
        right={
          perm.canCriarOk ? (
            <button
              type="button"
              onClick={() => void tentarAbrirNovaLive()}
              disabled={checandoNovaLive}
              style={{
                display: "flex", alignItems: "center", gap: 6,
                padding: "10px 20px", borderRadius: 10, border: "none",
                cursor: checandoNovaLive ? "not-allowed" : "pointer",
                opacity: checandoNovaLive ? 0.75 : 1,
                background: "linear-gradient(135deg, var(--brand-action, #4a2082), var(--brand-contrast, #1e36f8))",
                color: "#fff", fontSize: 13, fontWeight: 700, fontFamily: FONT.body,
              }}
            >
              {checandoNovaLive ? (
                <>
                  <Loader2 size={14} className="app-lucide-spin" aria-hidden="true" />
                  Verificando...
                </>
              ) : (
                <>
                  <Plus size={14} aria-hidden="true" />
                  Nova Live
                </>
              )}
            </button>
          ) : undefined
        }
      />

      {/* ── BLOCO DE FILTROS (padrão Dashboards) ── */}
      <div style={{ marginBottom: 14 }}>
        <div style={{
          borderRadius: 14,
          border: `1px solid ${t.cardBorder}`,
          background: brand.blockBg,
          padding: "12px 20px",
        }}>
          {/* Linha principal — centralizada */}
          <div style={{ display: "flex", alignItems: "center", justifyContent: "center", gap: 18, flexWrap: "wrap" }}>
            <button type="button" onClick={prev} style={btnNav} aria-label="Período anterior">
              <ChevronLeft size={14} aria-hidden="true" />
            </button>
            <span style={{ fontSize: 18, fontWeight: 800, color: t.text, fontFamily: FONT.body, minWidth: 180, textAlign: "center" }}>
              {headerTitle()}
            </span>
            <button type="button" onClick={next} style={btnNav} aria-label="Próximo período">
              <ChevronRight size={14} aria-hidden="true" />
            </button>

            <button type="button" onClick={goToday} style={chipBase(false)}>Hoje</button>

            <SingleDropdown
              value={view}
              options={VIEW_OPTIONS}
              onChange={v => setView(v as ViewMode)}
              icon={<CalendarDays size={13} aria-hidden="true" />}
              t={t}
              accent={brand.accent}
            />

            {showFiltroInfluencer && influencerListVisiveis.length > 0 && (
              <InfluencerMultiSelect
                selected={filterInfluencers}
                onChange={setFilterInfluencers}
                influencers={influencerListVisiveis}
                t={t}
              />
            )}

            {showFiltroOperadora && operadorasList.length > 0 && (
              <SelectComIcone
                pill
                icon={<Shield size={13} aria-hidden="true" />}
                label="Filtrar por operadora"
                value={filterOperadora}
                onChange={setFilterOperadora}
                minWidth={200}
                style={{
                  border: `1px solid ${filterOperadora !== "todas" ? brand.accent : t.cardBorder}`,
                  background:
                    filterOperadora !== "todas"
                      ? (brand.useBrand ? "color-mix(in srgb, var(--brand-contrast, #1e36f8) 15%, transparent)" : `color-mix(in srgb, ${BRAND.roxoVivo} 14%, transparent)`)
                      : (t.inputBg ?? t.cardBg),
                  color: filterOperadora !== "todas" ? brand.accent : t.textMuted,
                  fontWeight: filterOperadora !== "todas" ? 700 : 400,
                }}
              >
                <option value="todas">Todas as operadoras</option>
                {operadorasList
                  .filter((o) => podeVerOperadora(o.slug))
                  .sort((a, b) => a.nome.localeCompare(b.nome, "pt-BR"))
                  .map((o) => <option key={o.slug} value={o.slug}>{o.nome}</option>)}
              </SelectComIcone>
            )}
          </div>

          {/* Status e Plataforma */}
          <div style={{ paddingTop: 12, marginTop: 12, borderTop: `1px solid ${t.cardBorder}`, display: "flex", flexDirection: "column", alignItems: "center", gap: 10 }}>
            <div style={{ display: "flex", alignItems: "center", gap: 10, flexWrap: "wrap", justifyContent: "center" }}>
              <span style={{ fontSize: 10, fontWeight: 700, color: t.textMuted, fontFamily: FONT.body, textTransform: "uppercase", letterSpacing: "0.1em" }}>Status</span>
              {Object.entries(STATUS_COLOR).map(([status, color]) => {
                const active = filterStatus === status;
                return (
                  <button
                    type="button"
                    key={status}
                    aria-pressed={active}
                    onClick={() => setFilterStatus(prev => prev === status ? null : status)}
                    style={{
                      display: "flex", alignItems: "center", gap: 6,
                      padding: "5px 12px", borderRadius: 999, cursor: "pointer",
                      border: `1px solid ${active ? color : color + "55"}`,
                      background: active ? `${color}22` : "transparent",
                      color: active ? color : t.textMuted, fontSize: 12, fontWeight: active ? 700 : 400,
                      fontFamily: FONT.body, transition: "all 0.15s",
                      lineHeight: 1,
                    }}
                  >
                    <span style={{ width: 8, height: 8, borderRadius: "50%", background: color, flexShrink: 0, alignSelf: "center" }} />
                    <span style={{ display: "inline-flex", alignItems: "center" }}>{STATUS_LABEL[status]}</span>
                    {active && <span style={{ display: "inline-flex", alignItems: "center", lineHeight: 0 }}><X size={9} aria-hidden="true" /></span>}
                  </button>
                );
              })}
            </div>
            <div style={{ display: "flex", alignItems: "center", gap: 10, flexWrap: "wrap", justifyContent: "center" }}>
              <span style={{ fontSize: 10, fontWeight: 700, color: t.textMuted, fontFamily: FONT.body, textTransform: "uppercase", letterSpacing: "0.1em" }}>Plataforma</span>
              {Object.entries(PLAT_COLOR).map(([plat, color]) => {
                const active = filterPlat === plat;
                return (
                  <button
                    type="button"
                    key={plat}
                    aria-pressed={active}
                    onClick={() => setFilterPlat(prev => prev === plat ? null : plat)}
                    style={{
                      display: "inline-flex", alignItems: "center", gap: 6,
                      padding: "5px 12px", borderRadius: 999, cursor: "pointer",
                      border: `1px solid ${active ? color : color + "55"}`,
                      background: active ? `${color}22` : `${color}11`,
                      color: active ? color : color + "cc",
                      fontSize: 12, fontWeight: active ? 700 : 500,
                      fontFamily: FONT.body, transition: "all 0.15s",
                      lineHeight: 1,
                    }}
                  >
                    <PlatLogo plataforma={plat} size={13} isDark={isDark ?? false} />
                    <span style={{ display: "inline-flex", alignItems: "center" }}>{plat}</span>
                    {active && <span style={{ display: "inline-flex", alignItems: "center", lineHeight: 0 }}><X size={9} aria-hidden="true" /></span>}
                  </button>
                );
              })}
            </div>
            {hasActiveFilters && (
              <button
                type="button"
                onClick={() => { setFilterStatus(null); setFilterPlat(null); setFilterInfluencers([]); setFilterOperadora("todas"); }}
                style={{
                  padding: "5px 14px", borderRadius: 999,
                  border: `1px solid ${BRAND.vermelho}44`,
                  background: `${BRAND.vermelho}11`,
                  color: BRAND.vermelho, fontSize: 12, fontWeight: 600,
                  fontFamily: FONT.body, cursor: "pointer",
                  display: "inline-flex",
                  alignItems: "center",
                  gap: 6,
                }}
              >
                <X size={12} aria-hidden="true" /> Limpar filtros
              </button>
            )}
          </div>
        </div>
      </div>

      {/* ── CALENDÁRIO ── */}
      <div style={card}>
        {loading ? (
          <div style={{ textAlign: "center", padding: 60, color: t.textMuted, fontFamily: FONT.body, display: "flex", alignItems: "center", justifyContent: "center", gap: 8 }}>
            <Loader2 size={16} className="app-lucide-spin" aria-hidden="true" />
            Carregando...
          </div>
        ) : (
          view === "mes" ? <ViewMes /> : view === "semana" ? <ViewSemana /> : <ViewDia />
        )}
      </div>

      {/* ── MODAL ── */}
      {modal.open && (
        <ModalLive
          live={modal.live}
          onClose={() => setModal({ open: false })}
          onSave={() => { setModal({ open: false }); loadLives(); }}
        />
      )}

      <ModalBloqueioAgendaLive
        open={bloqueioNovaLive !== null}
        onClose={() => setBloqueioNovaLive(null)}
        perfilIncompleto={bloqueioNovaLive?.perfilIncompleto ?? false}
        faltaPlaybook={bloqueioNovaLive?.faltaPlaybook ?? false}
        segundaPessoa
        onIrInfluencers={() => {
          setBloqueioNovaLive(null);
          setActivePage("influencers");
        }}
        onIrPlaybook={() => {
          setBloqueioNovaLive(null);
          setActivePage("playbook_influencers");
        }}
      />
    </div>
  );
}

import { useState, useEffect, useMemo, useRef, type CSSProperties } from "react";
import { useApp } from "../../../context/AppContext";
import { useDashboardFiltros } from "../../../hooks/useDashboardFiltros";
import { useDashboardBrand } from "../../../hooks/useDashboardBrand";
import { usePermission, type Permissoes } from "../../../hooks/usePermission";
import { FONT } from "../../../constants/theme";
import { FONT_TITLE, BRAND } from "../../../lib/dashboardConstants";
import { supabase } from "../../../lib/supabase";
import { Live, LiveResultado, LiveStatus } from "../../../types";
import {
  X, Pencil, Trash2, Calendar, User, ChevronLeft, ChevronRight, Loader2, Shield, MessageSquare,
} from "lucide-react";
import { PlatLogo } from "../../../components/PlatLogo";
import { InfluencerDropdown } from "../../../components/InfluencerDropdown";
import { DashboardPageHeader, SelectComIcone } from "../../../components/dashboard";

import { PLAT_COLOR } from "../../../constants/platforms";

// ─── CARROSSEL DE SEMANAS (a partir de 01/12/2025) ────────────────────────────
const MESES_ABREV = ["Jan","Fev","Mar","Abr","Mai","Jun","Jul","Ago","Set","Out","Nov","Dez"];

function getSemanasDisponiveis(): { start: Date; end: Date; label: string }[] {
  const lista: { start: Date; end: Date; label: string }[] = [];
  const inicioRef = new Date(2025, 10, 30); // domingo 30/11/2025 (semana com 01/12)
  const hoje = new Date();
  const dom = new Date(inicioRef);
  while (dom <= hoje) {
    const sab = new Date(dom);
    sab.setDate(dom.getDate() + 6);
    const label = `${dom.getDate()} ${MESES_ABREV[dom.getMonth()]} – ${sab.getDate()} ${MESES_ABREV[sab.getMonth()]} ${sab.getFullYear()}`;
    lista.push({ start: new Date(dom), end: sab, label });
    dom.setDate(dom.getDate() + 7);
  }
  return lista;
}

function getRangeSemana(semana: { start: Date; end: Date } | null, historico: boolean): { start: string; end: string } {
  const toISO = (d: Date) => d.toISOString().split("T")[0];
  const now = new Date();
  if (historico) return { start: "2000-01-01", end: toISO(now) };
  if (!semana) return { start: toISO(now), end: toISO(now) };
  return { start: toISO(semana.start), end: toISO(semana.end) };
}

// ─── STATUS (padrão Agenda: legenda + cores) ───────────────────────────────────
const STATUS_COLOR: Record<string, string> = {
  realizada:     BRAND.verde,
  nao_realizada: BRAND.vermelho,
  todos:         BRAND.ciano,
};
const STATUS_LABEL: Record<string, string> = {
  realizada:     "Realizada",
  nao_realizada: "Não Realizada",
  todos:         "Todos",
};

/** Stats no card de live — aceita `var(--brand-*)` ou hex (color-mix funciona com ambos nos browsers suportados). */
function statBox(color: string, isDark: boolean): CSSProperties {
  return {
    flex: 1,
    textAlign: "center",
    padding: "10px 8px",
    borderRadius: 10,
    minWidth: 0,
    background: `color-mix(in srgb, ${color} ${isDark ? "8%" : "6%"}, transparent)`,
    border: `1px solid color-mix(in srgb, ${color} 22%, transparent)`,
  };
}

// ─── HELPERS ──────────────────────────────────────────────────────────────────
function fmtData(iso: string): string {
  if (!iso) return "";
  const [y, m, d] = iso.split("-");
  return `${d}/${m}/${y.slice(2)}`;
}

// ─── TIPOS ────────────────────────────────────────────────────────────────────
interface LiveComObs extends Omit<Live, "observacao"> {
  observacao?: string | null;
}

interface LiveCardProps {
  live: LiveComObs;
  res: LiveResultado | undefined;
  brand: ReturnType<typeof useDashboardBrand>;
  t: ReturnType<typeof useApp>["theme"];
  isDark: boolean;
  perm: Permissoes;
  podeVerInfluencer: (id: string) => boolean;
  excluindo: LiveComObs | null;
  setExcluindo: (v: LiveComObs | null) => void;
  onEditar: (live: LiveComObs) => void;
  onRefresh: () => void;
}

function LiveCard({
  live,
  res,
  brand,
  t,
  isDark,
  perm,
  podeVerInfluencer,
  excluindo,
  setExcluindo,
  onEditar,
  onRefresh,
}: LiveCardProps) {
  const [confirmExcluir, setConfirmExcluir] = useState(false);
  const isRealizada = live.status === "realizada";
  const statusColor = isRealizada ? BRAND.verde : BRAND.vermelho;
  const platColor = PLAT_COLOR[live.plataforma];
  const podeEditar = perm.canEditarOk && (perm.canEditar !== "proprios" || podeVerInfluencer(live.influencer_id));
  const podeExcluir = perm.canExcluirOk && (perm.canExcluir !== "proprios" || podeVerInfluencer(live.influencer_id));
  const isExcluindo = excluindo?.id === live.id;
  const cardShadow = t.isDark ? "0 4px 20px rgba(0,0,0,0.25)" : "0 2px 8px rgba(0,0,0,0.07)";

  async function handleExcluirConfirmado() {
    if (!perm.canExcluirOk) return;
    setExcluindo(live);
    await supabase.from("live_resultados").delete().eq("live_id", live.id);
    const { error } = await supabase.from("lives").delete().eq("id", live.id);
    setExcluindo(null);
    setConfirmExcluir(false);
    if (!error) onRefresh();
  }

  return (
    <div
      style={{
        background: brand.blockBg,
        border: `1px solid ${t.cardBorder}`,
        borderRadius: 18,
        padding: 20,
        marginBottom: 10,
        borderLeft: `6px solid ${statusColor}`,
        boxShadow: cardShadow,
      }}
    >
      <div style={{ display: "flex", alignItems: "flex-start", gap: 14 }}>
        <div
          style={{
            width: 44,
            height: 44,
            borderRadius: 10,
            flexShrink: 0,
            background: `${platColor}22`,
            border: `1.5px solid ${platColor}44`,
            display: "flex",
            alignItems: "center",
            justifyContent: "center",
          }}
        >
          <PlatLogo plataforma={live.plataforma} size={20} isDark={isDark} />
        </div>

        <div style={{ flex: 1, minWidth: 0 }}>
          <div
            style={{
              display: "flex",
              alignItems: "center",
              gap: 6,
              fontSize: 14,
              fontWeight: 700,
              color: t.text,
              fontFamily: FONT.body,
              marginBottom: 4,
            }}
          >
            <Calendar size={13} aria-hidden="true" style={{ color: t.textMuted, flexShrink: 0 }} />
            {fmtData(live.data)} às {live.horario?.slice(0, 5)}
          </div>

          <div style={{ display: "flex", alignItems: "center", gap: 8, flexWrap: "wrap" }}>
            <span
              style={{
                display: "flex",
                alignItems: "center",
                gap: 5,
                fontSize: 12,
                color: t.textMuted,
                fontFamily: FONT.body,
              }}
            >
              <User size={12} aria-hidden="true" style={{ flexShrink: 0 }} />
              {live.influencer_name}
            </span>
            <span style={{ fontSize: 11, color: t.textMuted }}>·</span>
            <span
              style={{
                display: "inline-flex",
                alignItems: "center",
                gap: 5,
                fontSize: 11,
                padding: "3px 9px",
                borderRadius: 20,
                background: `${platColor}22`,
                color: platColor,
                fontWeight: 600,
                fontFamily: FONT.body,
              }}
            >
              <PlatLogo plataforma={live.plataforma} size={11} isDark={isDark} />
              {live.plataforma}
            </span>
          </div>
        </div>

        {(podeEditar || podeExcluir) && (
          <div style={{ display: "flex", gap: 8, flexShrink: 0 }}>
            {podeEditar && (
              <button
                type="button"
                onClick={() => onEditar(live)}
                style={{
                  display: "inline-flex",
                  alignItems: "center",
                  gap: 5,
                  padding: "6px 12px",
                  borderRadius: 8,
                  border: `1px solid ${t.cardBorder}`,
                  background: t.inputBg ?? t.cardBg,
                  color: t.text,
                  fontSize: 11,
                  fontWeight: 600,
                  cursor: "pointer",
                  fontFamily: FONT.body,
                }}
              >
                <Pencil size={11} aria-hidden="true" /> Editar
              </button>
            )}
            {podeExcluir && (
              <button
                type="button"
                onClick={() => {
                  if (!confirmExcluir) {
                    setConfirmExcluir(true);
                    return;
                  }
                  void handleExcluirConfirmado();
                }}
                onBlur={() => setConfirmExcluir(false)}
                disabled={isExcluindo}
                style={{
                  display: "inline-flex",
                  alignItems: "center",
                  gap: 5,
                  padding: "6px 12px",
                  borderRadius: 8,
                  border: `1px solid ${BRAND.vermelho}50`,
                  background: confirmExcluir ? BRAND.vermelho : `${BRAND.vermelho}10`,
                  color: confirmExcluir ? "#fff" : BRAND.vermelho,
                  fontSize: 11,
                  fontWeight: 600,
                  cursor: isExcluindo ? "not-allowed" : "pointer",
                  fontFamily: FONT.body,
                  opacity: isExcluindo ? 0.6 : 1,
                  transition: "all 0.15s",
                }}
              >
                <Trash2 size={11} aria-hidden="true" />
                {isExcluindo ? "..." : confirmExcluir ? "Confirmar?" : "Excluir"}
              </button>
            )}
          </div>
        )}
      </div>

      {live.observacao && (
        <div
          style={{
            marginTop: 14,
            padding: "10px 14px",
            borderRadius: 10,
            background: isDark ? "#ffffff08" : "#00000006",
            border: `1px solid ${t.cardBorder}`,
          }}
        >
          <span
            style={{
              fontSize: 11,
              fontWeight: 700,
              color: t.textMuted,
              fontFamily: FONT.body,
              textTransform: "uppercase",
              letterSpacing: "0.8px",
            }}
          >
            Observação:
          </span>
          <p style={{ margin: "4px 0 0", fontSize: 12, color: t.text, fontFamily: FONT.body, lineHeight: 1.5 }}>
            {live.observacao}
          </p>
        </div>
      )}

      {isRealizada && res && (
        <div style={{ display: "flex", gap: 8, marginTop: 14 }}>
          <div style={statBox("var(--brand-action, #7c3aed)", isDark)}>
            <div
              style={{
                fontSize: 16,
                fontWeight: 800,
                color: "var(--brand-action, #7c3aed)",
                fontFamily: FONT.body,
              }}
            >
              {res.duracao_horas}h {res.duracao_min}m
            </div>
            <div style={{ fontSize: 10, color: t.textMuted, fontFamily: FONT.body, marginTop: 2 }}>Duração</div>
          </div>
          <div style={statBox("var(--brand-contrast, #1e36f8)", isDark)}>
            <div
              style={{
                fontSize: 16,
                fontWeight: 800,
                color: "var(--brand-contrast, #1e36f8)",
                fontFamily: FONT.body,
              }}
            >
              {res.media_views.toLocaleString("pt-BR")}
            </div>
            <div style={{ fontSize: 10, color: t.textMuted, fontFamily: FONT.body, marginTop: 2 }}>Média Views</div>
          </div>
          <div style={statBox("var(--brand-icon-color)", isDark)}>
            <div
              style={{
                fontSize: 16,
                fontWeight: 800,
                color: "var(--brand-icon-color)",
                fontFamily: FONT.body,
              }}
            >
              {(res.max_views ?? 0).toLocaleString("pt-BR")}
            </div>
            <div style={{ fontSize: 10, color: t.textMuted, fontFamily: FONT.body, marginTop: 2 }}>Pico Views</div>
          </div>
        </div>
      )}
    </div>
  );
}

// ─── COMPONENTE PRINCIPAL ─────────────────────────────────────────────────────
export default function Feedback() {
  const { theme: t, isDark } = useApp();
  const brand = useDashboardBrand();
  const { showFiltroInfluencer, showFiltroOperadora, podeVerInfluencer, escoposVisiveis, operadoraSlugsForcado } = useDashboardFiltros();
  const perm = usePermission("feedback");

  const semanasDisponiveis = useMemo(() => getSemanasDisponiveis(), []);
  const hoje = new Date();
  const idxInicial = semanasDisponiveis.findIndex(
    (s) => s.start <= hoje && s.end >= hoje
  );
  const [idxSemana,   setIdxSemana]   = useState(idxInicial >= 0 ? idxInicial : semanasDisponiveis.length - 1);
  const [historico,   setHistorico]   = useState(false);
  const [statusFiltro, setStatusFiltro] = useState<LiveStatus | "todos">("todos");
  const [influencerFiltros, setInfluencerFiltros] = useState<string[]>([]);
  const [filterOperadora,   setFilterOperadora]   = useState<string>("todas");
  const [operadorasList,    setOperadorasList]    = useState<{ slug: string; nome: string }[]>([]);
  const [lives,             setLives]             = useState<LiveComObs[]>([]);
  const [resultados,        setResultados]        = useState<Record<string, LiveResultado>>({});
  const [influencers,       setInfluencers]       = useState<{ id: string; name: string }[]>([]);
  const [loading,           setLoading]           = useState(true);
  const [editando,          setEditando]          = useState<LiveComObs | null>(null);
  const [excluindo,         setExcluindo]         = useState<LiveComObs | null>(null);
  const [livesAll,          setLivesAll]          = useState<LiveComObs[]>([]);
  const [resultadosAll,     setResultadosAll]     = useState<Record<string, LiveResultado>>({});

  const semanaSelecionada = semanasDisponiveis[idxSemana];

  async function loadData() {
    setLoading(true);
    const { start, end } = getRangeSemana(semanaSelecionada ?? null, historico);

    let baseQuery = supabase
      .from("lives")
      .select("*, profiles!lives_influencer_id_fkey(name)")
      .gte("data", start).lte("data", end)
      .in("status", ["realizada", "nao_realizada"])
      .order("data", { ascending: false })
      .order("horario", { ascending: true });

    if (operadoraSlugsForcado?.length) baseQuery = baseQuery.in("operadora_slug", operadoraSlugsForcado);
    if (influencerFiltros.length > 0) baseQuery = baseQuery.in("influencer_id", influencerFiltros);

    const { data: allData } = await baseQuery;

    if (allData) {
      const mappedAll: LiveComObs[] = allData
        .map((l: { profiles?: { name: string }; [k: string]: unknown }) => ({ ...l, influencer_name: l.profiles?.name })) as LiveComObs[];
      const visiveis = mappedAll.filter((l) => podeVerInfluencer(l.influencer_id));
      setLivesAll(visiveis);

      const unique = Array.from(
        new Map(visiveis.map(l => [l.influencer_id, { id: l.influencer_id, name: l.influencer_name ?? l.influencer_id }])).values()
      ).filter((i) => podeVerInfluencer(i.id)).sort((a, b) => (a.name ?? "").localeCompare(b.name ?? "", "pt-BR"));
      setInfluencers(unique);

      const allIds = visiveis.map(l => l.id);
      const resMapAll: Record<string, LiveResultado> = {};
      if (allIds.length > 0) {
        const { data: resAll } = await supabase.from("live_resultados").select("*").in("live_id", allIds);
        if (resAll) resAll.forEach((r: LiveResultado) => { resMapAll[r.live_id] = r; });
      }
      setResultadosAll(resMapAll);

      const filtered = statusFiltro === "todos" ? visiveis : visiveis.filter(l => l.status === statusFiltro);
      setLives(filtered);

      const filteredIds = filtered.map(l => l.id);
      const resMap: Record<string, LiveResultado> = {};
      if (filteredIds.length > 0) {
        const { data: resData } = await supabase.from("live_resultados").select("*").in("live_id", filteredIds);
        if (resData) resData.forEach((r: LiveResultado) => { resMap[r.live_id] = r; });
      }
      setResultados(resMap);
    }
    setLoading(false);
  }

  useEffect(() => { loadData(); }, [idxSemana, historico, semanaSelecionada, statusFiltro, influencerFiltros, podeVerInfluencer, operadoraSlugsForcado]);

  useEffect(() => {
    supabase.from("operadoras").select("slug, nome").order("nome")
      .then(({ data }) => { if (data) setOperadorasList(data); });
  }, []);

  const livesAllFiltered = useMemo(() => {
    if (operadoraSlugsForcado?.length) return livesAll.filter((l) => l.operadora_slug && operadoraSlugsForcado.includes(l.operadora_slug));
    if (!filterOperadora || filterOperadora === "todas") return livesAll;
    return livesAll.filter((l) => l.operadora_slug === filterOperadora);
  }, [livesAll, filterOperadora, operadoraSlugsForcado]);

  const livesFiltered = useMemo(() => {
    if (operadoraSlugsForcado?.length) return lives.filter((l) => l.operadora_slug && operadoraSlugsForcado.includes(l.operadora_slug));
    if (!filterOperadora || filterOperadora === "todas") return lives;
    return lives.filter((l) => l.operadora_slug === filterOperadora);
  }, [lives, filterOperadora, operadoraSlugsForcado]);

  // ── Cálculos dos quadros ──────────────────────────────────────────────────
  const totalLives         = livesAllFiltered.length;
  const totalRealizadas    = livesAllFiltered.filter(l => l.status === "realizada").length;
  const totalNaoRealizadas = livesAllFiltered.filter(l => l.status === "nao_realizada").length;
  const realizadasComRes   = livesAllFiltered.filter(l => l.status === "realizada" && resultadosAll[l.id]);

  const totalHoras = realizadasComRes.reduce((acc, l) => {
    const r = resultadosAll[l.id];
    return acc + (r.duracao_horas ?? 0) + (r.duracao_min ?? 0) / 60;
  }, 0);
  const horasInt    = Math.floor(totalHoras);
  const minutosRest = Math.round((totalHoras - horasInt) * 60);

  const mediaViews = realizadasComRes.length > 0
    ? Math.round(realizadasComRes.reduce((acc, l) => acc + (resultadosAll[l.id]?.media_views ?? 0), 0) / realizadasComRes.length)
    : 0;

  // ── Estilos (padrão Agenda) ───────────────────────────────────────────────
  const btnNav: CSSProperties = {
    width: 30, height: 30, borderRadius: "50%",
    border: `1px solid ${t.cardBorder}`,
    background: "transparent", color: t.text, cursor: "pointer",
    display: "flex", alignItems: "center", justifyContent: "center",
  };
  const isPrimeiro = idxSemana === 0;
  const isUltimo = idxSemana === semanasDisponiveis.length - 1;

  const cardShadow = t.isDark ? "0 4px 20px rgba(0,0,0,0.25)" : "0 2px 8px rgba(0,0,0,0.07)";

  // ── Render ────────────────────────────────────────────────────────────────
  if (perm.canView === "nao") {
    return (
      <div style={{ padding: 24, textAlign: "center", color: t.textMuted, fontFamily: FONT.body }}>
        Você não tem permissão para visualizar este dashboard.
      </div>
    );
  }

  return (
    <div className="app-page-shell" style={{ background: t.bg, minHeight: "100vh", fontFamily: FONT.body }}>

      <DashboardPageHeader
        icon={<MessageSquare size={14} aria-hidden="true" />}
        title="Feedback de Lives"
        subtitle="Resultado final das lives validadas em Resultados."
        brand={brand}
        t={t}
      />

      {/* ── BLOCO DE FILTROS (carrossel de semanas + Histórico + Status padrão Agenda) ── */}
      <div style={{ marginBottom: 14 }}>
        <div style={{
          borderRadius: 14,
          border: `1px solid ${t.cardBorder}`,
          background: brand.blockBg,
          padding: "12px 20px",
        }}>
          {/* Linha 1: Carrossel de semanas, Histórico, Influencer e Operadora — alinhado ao Overview Influencer */}
          <div style={{ display: "flex", alignItems: "center", justifyContent: "center", gap: 10, flexWrap: "wrap" }}>
            <button
              type="button"
              style={{ ...btnNav, opacity: historico || isPrimeiro ? 0.35 : 1, cursor: historico || isPrimeiro ? "not-allowed" : "pointer" }}
              onClick={() => { setHistorico(false); setIdxSemana((i) => Math.max(0, i - 1)); }}
              disabled={historico || isPrimeiro}
              aria-label="Semana anterior"
            >
              <ChevronLeft size={14} aria-hidden="true" />
            </button>
            <span style={{ fontSize: 18, fontWeight: 800, color: t.text, fontFamily: FONT.body, minWidth: "clamp(140px, 45vw, 200px)", textAlign: "center" }}>
              {historico ? "Todo o período" : semanaSelecionada?.label}
            </span>
            <button
              type="button"
              style={{ ...btnNav, opacity: historico || isUltimo ? 0.35 : 1, cursor: historico || isUltimo ? "not-allowed" : "pointer" }}
              onClick={() => { setHistorico(false); setIdxSemana((i) => Math.min(semanasDisponiveis.length - 1, i + 1)); }}
              disabled={historico || isUltimo}
              aria-label="Próxima semana"
            >
              <ChevronRight size={14} aria-hidden="true" />
            </button>
            <button
              type="button"
              aria-pressed={historico}
              aria-label={historico ? "Desativar modo histórico" : "Ativar modo histórico — ver todo o período"}
              onClick={() => {
                if (historico) {
                  setHistorico(false);
                  setIdxSemana(idxInicial >= 0 ? idxInicial : semanasDisponiveis.length - 1);
                } else {
                  setHistorico(true);
                }
              }}
              style={{
                display: "flex", alignItems: "center", gap: 6,
                padding: "6px 14px", minHeight: 44, borderRadius: 999, cursor: "pointer",
                fontFamily: FONT.body, fontSize: 13,
                border: historico ? `1px solid ${brand.accent}` : `1px solid ${t.cardBorder}`,
                background: historico ? (brand.useBrand ? "color-mix(in srgb, var(--brand-contrast, #1e36f8) 15%, transparent)" : `${BRAND.roxoVivo}18`) : "transparent",
                color: historico ? brand.accent : t.textMuted,
                fontWeight: historico ? 700 : 400,
                transition: "all 0.15s",
                lineHeight: 1,
              }}
            >
              <span style={{ display: "inline-flex", alignItems: "center", lineHeight: 0 }}>
                <Calendar size={15} aria-hidden="true" />
              </span>
              <span style={{ display: "inline-flex", alignItems: "center" }}>Histórico</span>
            </button>

            {showFiltroInfluencer && influencers.length > 0 && (
              <InfluencerDropdown items={influencers} selected={influencerFiltros} onChange={setInfluencerFiltros} accent={brand.accent} />
            )}
            {showFiltroOperadora && operadorasList.length > 0 && (
              <SelectComIcone
                pill
                icon={<Shield size={15} aria-hidden="true" />}
                label="Filtrar por operadora"
                value={filterOperadora}
                onChange={setFilterOperadora}
                minWidth={200}
                style={{
                  border: `1px solid ${filterOperadora !== "todas" ? brand.accent : t.cardBorder}`,
                  background:
                    filterOperadora !== "todas"
                      ? brand.useBrand
                        ? "color-mix(in srgb, var(--brand-contrast, #1e36f8) 15%, transparent)"
                        : `${BRAND.roxoVivo}18`
                      : (t.inputBg ?? t.cardBg),
                  color: filterOperadora !== "todas" ? brand.accent : t.textMuted,
                  fontWeight: filterOperadora !== "todas" ? 700 : 400,
                }}
              >
                <option value="todas">Todas as operadoras</option>
                {operadorasList
                  .filter((o) => escoposVisiveis.operadorasVisiveis.length === 0 || escoposVisiveis.operadorasVisiveis.includes(o.slug))
                  .sort((a, b) => a.nome.localeCompare(b.nome, "pt-BR"))
                  .map((o) => (
                    <option key={o.slug} value={o.slug}>
                      {o.nome}
                    </option>
                  ))}
              </SelectComIcone>
            )}
          </div>

          {/* Linha 2: Status (padrão Agenda — legenda + cores) */}
          <div style={{ paddingTop: 12, marginTop: 12, borderTop: `1px solid ${t.cardBorder}`, display: "flex", alignItems: "center", gap: 18, flexWrap: "wrap", justifyContent: "center" }}>
            <span style={{ fontSize: 10, fontWeight: 700, color: t.textMuted, fontFamily: FONT.body, textTransform: "uppercase", letterSpacing: "0.1em" }}>Status</span>
            {(["realizada", "nao_realizada", "todos"] as const).map((status) => {
              const active = statusFiltro === status;
              const color = STATUS_COLOR[status];
              return (
                <button
                  type="button"
                  key={status}
                  aria-pressed={active}
                  onClick={() => setStatusFiltro(status)}
                  style={{
                    display: "flex", alignItems: "center", gap: 6,
                    padding: "5px 12px", borderRadius: 999, cursor: "pointer",
                    border: `1px solid ${active ? color : color + "55"}`,
                    background: active ? `${color}22` : "transparent",
                    color: active ? color : t.textMuted, fontSize: 12, fontWeight: active ? 700 : 400,
                    fontFamily: FONT.body, transition: "all 0.15s",
                    lineHeight: 1,
                  }}
                >
                  <span style={{ width: 8, height: 8, borderRadius: "50%", background: color, flexShrink: 0, alignSelf: "center" }} />
                  <span style={{ display: "inline-flex", alignItems: "center" }}>{STATUS_LABEL[status]}</span>
                  {active && <span style={{ display: "inline-flex", alignItems: "center", lineHeight: 0 }}><X size={9} aria-hidden="true" /></span>}
                </button>
              );
            })}
          </div>
        </div>
      </div>

      {/* ── QUADROS DE RESUMO ── */}
      {!loading && (
        <div className="app-grid-kpi-3" style={{ marginBottom: 24 }}>
          {/* Total de lives */}
          <div style={{ background: brand.blockBg, border: `1px solid ${t.cardBorder}`, borderRadius: 18, padding: "16px 18px", boxShadow: cardShadow }}>
            <div style={{ fontSize: 28, fontWeight: 900, color: t.text, fontFamily: FONT_TITLE, lineHeight: 1 }}>
              {totalLives}
            </div>
            <div style={{ fontSize: 11, fontWeight: 700, color: t.textMuted, fontFamily: FONT.body, textTransform: "uppercase", letterSpacing: "0.8px", marginTop: 4 }}>
              Total de Lives
            </div>
            <div style={{ display: "flex", gap: 8, marginTop: 10, flexWrap: "wrap" }}>
              <span style={{ display: "inline-flex", alignItems: "center", gap: 5, fontSize: 11, fontWeight: 600, fontFamily: FONT.body, color: BRAND.verde }}>
                <span style={{ width: 7, height: 7, borderRadius: "50%", background: BRAND.verde, display: "inline-block" }} />
                {totalRealizadas} realizadas
              </span>
              <span style={{ display: "inline-flex", alignItems: "center", gap: 5, fontSize: 11, fontWeight: 600, fontFamily: FONT.body, color: BRAND.vermelho }}>
                <span style={{ width: 7, height: 7, borderRadius: "50%", background: BRAND.vermelho, display: "inline-block" }} />
                {totalNaoRealizadas} não realizadas
              </span>
            </div>
          </div>

          {/* Horas realizadas — accent */}
          <div style={{ background: brand.blockBg, border: `1px solid ${t.cardBorder}`, borderRadius: 18, padding: "16px 18px", boxShadow: cardShadow }}>
            <div style={{ fontSize: 28, fontWeight: 900, color: brand.accent, fontFamily: FONT_TITLE, lineHeight: 1 }}>
              {horasInt}h{minutosRest > 0 ? ` ${minutosRest}m` : ""}
            </div>
            <div style={{ fontSize: 11, fontWeight: 700, color: t.textMuted, fontFamily: FONT.body, textTransform: "uppercase", letterSpacing: "0.8px", marginTop: 4 }}>
              Horas Realizadas
            </div>
            <div style={{ marginTop: 10 }}>
              <span style={{ fontSize: 11, fontWeight: 600, fontFamily: FONT.body, color: t.textMuted }}>
                em {realizadasComRes.length} live{realizadasComRes.length !== 1 ? "s" : ""}
              </span>
            </div>
          </div>

          {/* Média de views — accent */}
          <div style={{ background: brand.blockBg, border: `1px solid ${t.cardBorder}`, borderRadius: 18, padding: "16px 18px", boxShadow: cardShadow }}>
            <div style={{ fontSize: 28, fontWeight: 900, color: brand.accent, fontFamily: FONT_TITLE, lineHeight: 1 }}>
              {mediaViews > 0 ? mediaViews.toLocaleString("pt-BR") : "—"}
            </div>
            <div style={{ fontSize: 11, fontWeight: 700, color: t.textMuted, fontFamily: FONT.body, textTransform: "uppercase", letterSpacing: "0.8px", marginTop: 4 }}>
              Média de Views
            </div>
            <div style={{ marginTop: 10 }}>
              <span style={{ fontSize: 11, fontWeight: 600, fontFamily: FONT.body, color: t.textMuted }}>
                média das médias por live
              </span>
            </div>
          </div>
        </div>
      )}

      {/* Contador */}
      {!loading && livesFiltered.length > 0 && (
        <div style={{ fontSize: 12, color: t.textMuted, fontFamily: FONT.body, marginBottom: 14 }}>
          {livesFiltered.length} live(s) encontrada(s)
          {influencerFiltros.length > 0 && (
            <span style={{ marginLeft: 8, color: brand.accent, fontWeight: 600 }}>
              · {influencerFiltros.length} influencer(s) selecionado(s)
            </span>
          )}
        </div>
      )}

      {/* Lista */}
      {loading ? (
        <div style={{ textAlign: "center", padding: 60, color: t.textMuted, fontFamily: FONT.body, display: "flex", alignItems: "center", justifyContent: "center", gap: 8 }}>
          <Loader2 size={16} className="app-lucide-spin" aria-hidden="true" />
          Carregando...
        </div>
      ) : livesFiltered.length === 0 ? (
        <div style={{ background: brand.blockBg, border: `1px solid ${t.cardBorder}`, borderRadius: 16, padding: 48, textAlign: "center", color: t.textMuted, fontFamily: FONT.body }}>
          Sem dados para o período selecionado.
        </div>
      ) : (
        livesFiltered.map((l) => (
          <LiveCard
            key={l.id}
            live={l}
            res={resultados[l.id]}
            brand={brand}
            t={t}
            isDark={isDark ?? false}
            perm={perm}
            podeVerInfluencer={podeVerInfluencer}
            excluindo={excluindo}
            setExcluindo={setExcluindo}
            onEditar={setEditando}
            onRefresh={loadData}
          />
        ))
      )}

      {/* Modal Editar */}
      {editando && (
        <ModalFeedbackEdit
          live={editando}
          res={resultadosAll[editando.id]}
          operadorasList={operadorasList}
          t={t}
          isDark={isDark ?? false}
          onClose={() => setEditando(null)}
          onSalvo={() => { setEditando(null); loadData(); }}
        />
      )}
    </div>
  );
}

// ─── MODAL EDITAR FEEDBACK ────────────────────────────────────────────────────
function ModalFeedbackEdit({ live, res, operadorasList, t, isDark: _isDark, onClose, onSalvo }: {
  live: LiveComObs; res?: LiveResultado;
  operadorasList: { slug: string; nome: string }[];
  t: ReturnType<typeof useApp>["theme"]; isDark: boolean;
  onClose: () => void; onSalvo: () => void;
}) {
  const brand = useDashboardBrand();
  const containerRef = useRef<HTMLDivElement>(null);
  const [observacao,   setObservacao]   = useState(live.observacao ?? "");
  const [operadoraSlug, setOperadoraSlug] = useState(live.operadora_slug ?? "");
  const [status,       setStatus]       = useState<LiveStatus>(
    live.status === "agendada" ? "realizada" : (live.status as LiveStatus)
  );
  const [duracaoHoras, setDuracaoHoras] = useState(res?.duracao_horas ?? 0);
  const [duracaoMin,   setDuracaoMin]   = useState(res?.duracao_min   ?? 0);
  const [mediaViews,   setMediaViews]   = useState(res?.media_views   ?? 0);
  const [maxViews,     setMaxViews]     = useState(res?.max_views     ?? 0);
  const [saving,       setSaving]       = useState(false);
  const [error,        setError]        = useState("");

  const showResultFields = status === "realizada";

  useEffect(() => {
    const id = window.setTimeout(() => containerRef.current?.focus(), 50);
    return () => window.clearTimeout(id);
  }, []);

  async function handleSave() {
    setError("");
    if (showResultFields) {
      if (!operadoraSlug?.trim()) {
        setError("Selecione a operadora. É obrigatório para lives realizadas (Financeiro)."); return;
      }
      if (duracaoHoras === 0 && duracaoMin === 0) {
        setError("Informe a duração da live para lives realizadas."); return;
      }
      if ((duracaoHoras > 0 || duracaoMin > 0) && maxViews < mediaViews) {
        setError("Pico de views não pode ser menor que a média."); return;
      }
    }
    setSaving(true);

    const liveUpdate: Record<string, unknown> = { observacao: observacao.trim() || null, status };
    if (operadoraSlug?.trim()) (liveUpdate as Record<string, string>).operadora_slug = operadoraSlug.trim();

    const { error: upErr } = await supabase.from("lives")
      .update(liveUpdate).eq("id", live.id);
    if (upErr) { setError("Erro ao salvar. Tente novamente."); setSaving(false); return; }

    if (showResultFields) {
      const payload = { live_id: live.id, duracao_horas: duracaoHoras, duracao_min: duracaoMin, media_views: mediaViews, max_views: maxViews };
      const { error: resErr } = res
        ? await supabase.from("live_resultados").update(payload).eq("live_id", live.id)
        : await supabase.from("live_resultados").insert(payload);
      if (resErr) { setError("Erro ao salvar resultado. Tente novamente."); setSaving(false); return; }
    }

    setSaving(false);
    onSalvo();
  }

  const inputStyle: CSSProperties = {
    width: "100%", boxSizing: "border-box", padding: "10px 14px",
    borderRadius: 10, border: `1px solid ${t.inputBorder ?? t.cardBorder}`,
    background: t.inputBg ?? t.cardBg, color: t.inputText ?? t.text,
    fontSize: 13, fontFamily: FONT.body, outline: "none",
  };
  const labelStyle: CSSProperties = {
    display: "block", fontSize: 10, fontWeight: 700, letterSpacing: "1.2px",
    textTransform: "uppercase", color: t.textMuted, marginBottom: 5, fontFamily: FONT.body,
  };

  const ctaSalvarBg = "linear-gradient(135deg, var(--brand-action, #4a2082), var(--brand-contrast, #1e36f8))";

  return (
    <div style={{ position: "fixed", inset: 0, background: "#00000088", display: "flex", alignItems: "center", justifyContent: "center", zIndex: 1000, padding: "clamp(16px, 4vw, 28px)" }}>
      <div
        ref={containerRef}
        tabIndex={-1}
        role="dialog"
        aria-modal="true"
        aria-labelledby="modal-feedback-title"
        style={{
          background: brand.blockBg,
          border: `1px solid ${t.cardBorder}`,
          borderRadius: 20,
          padding: "clamp(16px, 4vw, 28px)",
          width: "100%",
          maxWidth: 480,
          maxHeight: "90dvh",
          overflowY: "auto",
        }}
      >

        {/* Cabeçalho — primária */}
        <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 6 }}>
          <div style={{ display: "flex", alignItems: "center", gap: 8 }}>
            <span style={{
              width: 28, height: 28, borderRadius: 8,
              background: brand.primaryIconBg, border: brand.primaryIconBorder,
              display: "flex", alignItems: "center", justifyContent: "center", color: brand.primaryIconColor,
            }}>
              <Pencil size={13} aria-hidden="true" />
            </span>
            <h2 id="modal-feedback-title" style={{ margin: 0, fontSize: 15, fontWeight: 800, color: brand.primary, fontFamily: FONT_TITLE, letterSpacing: "0.05em", textTransform: "uppercase" }}>
              Editar Feedback
            </h2>
          </div>
          <button type="button" onClick={onClose} aria-label="Fechar" style={{ background: "none", border: "none", cursor: "pointer", color: t.textMuted, display: "flex", alignItems: "center", padding: 4 }}>
            <X size={18} aria-hidden="true" />
          </button>
        </div>

        <div style={{ fontSize: 13, color: t.textMuted, fontFamily: FONT.body, marginBottom: 20 }}>
          {live.influencer_name} · {fmtData(live.data)} {live.horario?.slice(0, 5)}
        </div>

        {error && (
          <div
            role="alert"
            aria-live="polite"
            style={{
              background: `${BRAND.vermelho}18`,
              border: `1px solid ${BRAND.vermelho}44`,
              color: BRAND.vermelho,
              borderRadius: 10,
              padding: "10px 14px",
              fontSize: 13,
              marginBottom: 14,
              fontFamily: FONT.body,
              display: "flex",
              alignItems: "center",
              justifyContent: "space-between",
              gap: 8,
            }}
          >
            <span>{error}</span>
            <button
              type="button"
              onClick={() => setError("")}
              aria-label="Fechar erro"
              style={{ background: "none", border: "none", cursor: "pointer", color: BRAND.vermelho, display: "flex", flexShrink: 0 }}
            >
              <X size={14} aria-hidden="true" />
            </button>
          </div>
        )}

        {/* Status — paleta oficial */}
        <div style={{ marginBottom: 14 }}>
          <label style={labelStyle}>Status</label>
          <div style={{ display: "flex", gap: 10 }}>
            <button
              type="button"
              aria-pressed={status === "realizada"}
              onClick={() => setStatus("realizada")}
              style={{ flex: 1, padding: 10, borderRadius: 10, border: `2px solid ${status === "realizada" ? BRAND.verde : t.cardBorder}`, background: status === "realizada" ? `${BRAND.verde}18` : (t.inputBg ?? t.cardBg), color: status === "realizada" ? BRAND.verde : t.textMuted, fontSize: 12, fontWeight: 700, cursor: "pointer", fontFamily: FONT.body, transition: "all 0.15s" }}
            >
              Realizada
            </button>
            <button
              type="button"
              aria-pressed={status === "nao_realizada"}
              onClick={() => setStatus("nao_realizada")}
              style={{ flex: 1, padding: 10, borderRadius: 10, border: `2px solid ${status === "nao_realizada" ? BRAND.vermelho : t.cardBorder}`, background: status === "nao_realizada" ? `${BRAND.vermelho}18` : (t.inputBg ?? t.cardBg), color: status === "nao_realizada" ? BRAND.vermelho : t.textMuted, fontSize: 12, fontWeight: 700, cursor: "pointer", fontFamily: FONT.body, transition: "all 0.15s" }}
            >
              Não realizada
            </button>
          </div>
        </div>

        {operadorasList.length > 0 && (
          <div style={{ marginBottom: 14 }}>
            <label style={labelStyle}>
              Operadora {showResultFields && <span style={{ color: BRAND.vermelho }}>*</span>}
            </label>
            <select
              value={operadoraSlug}
              onChange={e => setOperadoraSlug(e.target.value)}
              style={{
                width: "100%", boxSizing: "border-box", padding: "10px 14px",
                borderRadius: 10, border: `1px solid ${t.inputBorder ?? t.cardBorder}`,
                background: t.inputBg ?? t.cardBg, color: t.inputText ?? t.text,
                fontSize: 13, fontFamily: FONT.body, outline: "none", cursor: "pointer",
              }}
            >
              <option value="">Selecione a operadora...</option>
              {[...operadorasList].sort((a, b) => a.nome.localeCompare(b.nome, "pt-BR")).map(o => <option key={o.slug} value={o.slug}>{o.nome}</option>)}
            </select>
          </div>
        )}

        {/* Observação */}
        <div style={{ marginBottom: 14 }}>
          <label style={labelStyle}>Observação</label>
          <textarea value={observacao} onChange={e => setObservacao(e.target.value)} rows={3} style={{ ...inputStyle, resize: "vertical" }} placeholder="Feedback ou observação sobre a live..." />
        </div>

        {/* Campos de resultado */}
        {showResultFields && (
          <>
            <div className="app-grid-2-tight" style={{ marginBottom: 14 }}>
              <div>
                <label style={labelStyle}>Duração (horas)</label>
                <input aria-label="Duração em horas" type="number" min={0} value={duracaoHoras} onChange={e => setDuracaoHoras(Math.max(0, parseInt(e.target.value, 10) || 0))} style={inputStyle} />
              </div>
              <div>
                <label style={labelStyle}>Duração (min)</label>
                <input aria-label="Duração em minutos" type="number" min={0} max={59} value={duracaoMin} onChange={e => setDuracaoMin(Math.max(0, Math.min(59, parseInt(e.target.value, 10) || 0)))} style={inputStyle} />
              </div>
            </div>
            <div className="app-grid-2-tight" style={{ marginBottom: 14 }}>
              <div>
                <label style={labelStyle}>Média de views</label>
                <input aria-label="Média de views" type="number" min={0} value={mediaViews} onChange={e => setMediaViews(Math.max(0, parseInt(e.target.value, 10) || 0))} style={inputStyle} />
              </div>
              <div>
                <label style={labelStyle}>Pico de views</label>
                <input aria-label="Pico de views" type="number" min={0} value={maxViews} onChange={e => setMaxViews(Math.max(0, parseInt(e.target.value, 10) || 0))} style={inputStyle} />
              </div>
            </div>
          </>
        )}

        {/* Botões */}
        <div style={{ display: "flex", gap: 10, justifyContent: "flex-end", marginTop: 20 }}>
          <button type="button" onClick={onClose} style={{ padding: "10px 20px", borderRadius: 10, border: `1px solid ${t.cardBorder}`, background: "none", color: t.text, cursor: "pointer", fontFamily: FONT.body, fontSize: 13 }}>
            Cancelar
          </button>
          <button
            type="button"
            onClick={() => void handleSave()}
            disabled={saving}
            style={{
              padding: "10px 20px",
              borderRadius: 10,
              border: "none",
              background: ctaSalvarBg,
              color: "#fff",
              cursor: saving ? "not-allowed" : "pointer",
              fontFamily: FONT.body,
              fontSize: 13,
              fontWeight: 600,
              opacity: saving ? 0.7 : 1,
              display: "inline-flex",
              alignItems: "center",
              gap: 8,
            }}
          >
            {saving ? (
              <>
                <Loader2 size={14} className="app-lucide-spin" aria-hidden="true" />
                Salvando…
              </>
            ) : (
              "Salvar"
            )}
          </button>
        </div>
      </div>
    </div>
  );
}

