// ─── BLUR EM DADOS SENSÍVEIS ──────────────────────────────────────────────────
function SensitiveField({
  value, label, labelStyle, textStyle, editMode = false,
}: {
  value?: string;   label?: string; labelStyle?: CSSProperties;
  textStyle?: CSSProperties; editMode?: boolean;
}) {
  const [visible, setVisible] = useState(editMode);
  const timerRef = useRef<ReturnType<typeof setTimeout> | null>(null);
  const { theme: t } = useApp();

  function reveal() {
    setVisible(true);
    if (!editMode) {
      if (timerRef.current) clearTimeout(timerRef.current);
      timerRef.current = setTimeout(() => setVisible(false), 10000);
    }
  }

  useEffect(() => () => { if (timerRef.current) clearTimeout(timerRef.current); }, []);

  const display = value || "—";

  return (
    <div>
      {label && <span style={labelStyle}>{label}</span>}
      <div style={{ display: "flex", alignItems: "center", gap: 8 }}>
        <span style={{
          ...textStyle,
          filter: visible ? "none" : "blur(5px)",
          userSelect: visible ? "auto" : "none",
          transition: "filter 0.2s",
          cursor: visible ? "text" : "default",
        }}>
          {display}
        </span>
        <button
          type="button"
          onClick={() => visible ? setVisible(false) : reveal()}
          aria-label={visible ? `Ocultar ${label ?? "dado sensível"}` : `Revelar ${label ?? "dado sensível"}`}
          style={{
            background: "none", border: "none", cursor: "pointer",
            color: t.textMuted, padding: 2, flexShrink: 0,
            display: "flex", alignItems: "center",
            opacity: 0.7,
          }}
        >
          {visible ? <EyeOff size={13} aria-hidden="true" /> : <Eye size={13} aria-hidden="true" />}
        </button>
      </div>
    </div>
  );
}

// ─── STATUS ───────────────────────────────────────────────────────────────────
type StatusInfluencer = "ativo" | "inativo" | "cancelado";
const STATUS_OPTS: StatusInfluencer[] = ["ativo", "inativo", "cancelado"];
const STATUS_COLOR: Record<StatusInfluencer, string> = {
  ativo:      BRAND.verde,
  inativo:    BRAND.amarelo,
  cancelado:  BRAND.vermelho,
};
const STATUS_LABEL: Record<StatusInfluencer, string> = {
  ativo: "Ativo", inativo: "Inativo", cancelado: "Cancelado",
};

interface Perfil {
  id:               string;
  nome_artistico?:  string;
  nome_completo?:   string;
  status?:          StatusInfluencer;
  telefone?:        string;
  cpf?:             string;
  canais?:          Plataforma[];
  link_twitch?:     string;
  link_youtube?:    string;
  link_kick?:       string;
  link_instagram?:  string;
  link_tiktok?:     string;
  link_discord?:    string;
  link_whatsapp?:   string;
  link_telegram?:   string;
  cache_hora?:      number;
  banco?:           string;
  agencia?:         string;
  conta?:           string;
  chave_pix?:       string;
  created_at?:      string;
  updated_at?:      string;
  status_alterado_em?: string;
}

interface Influencer {
  id:         string;
  name:       string;
  email:      string;
  perfil:     Perfil | null;
  operadoras: InfluencerOperadora[];
}

const emptyPerfil = (id: string): Perfil => ({
  id, nome_artistico: "", nome_completo: "", status: "ativo", telefone: "", cpf: "",
  canais: [], link_twitch: "", link_youtube: "", link_kick: "", link_instagram: "", link_tiktok: "", link_discord: "", link_whatsapp: "", link_telegram: "",
  cache_hora: 0, banco: "", agencia: "", conta: "", chave_pix: "",
});

// ─── StatusBadge ─────────────────────────────────────────────────────────────
interface StatusBadgeProps {
  value:     StatusInfluencer;
  onChange:  (v: StatusInfluencer) => void;
  readonly?: boolean;
}

function StatusBadge({ value, onChange, readonly }: StatusBadgeProps) {
  const { theme: t } = useApp();
  const [open, setOpen] = useState(false);
  const color = STATUS_COLOR[value] ?? "#888";
  return (
    <div style={{ position: "relative", display: "inline-block" }}>
      <button
        type="button"
        onClick={() => { if (!readonly) setOpen((o) => !o); }}
        {...(!readonly ? { "aria-haspopup": "menu" as const, "aria-expanded": open } : {})}
        aria-label={`Status: ${STATUS_LABEL[value]}`}
        style={{
          padding: "4px 12px", borderRadius: "20px",
          border: `1.5px solid ${color}`, background: `${color}18`, color,
          fontSize: "12px", fontWeight: 700, fontFamily: FONT.body,
          cursor: readonly ? "default" : "pointer",
          display: "flex", alignItems: "center", gap: "5px",
        }}
      >
        {STATUS_LABEL[value]}
        {!readonly && <ChevronDown size={9} style={{ opacity: 0.7 }} aria-hidden="true" />}
      </button>
      {open && (
        <div
          role="menu"
          style={{
          position: "absolute", top: "calc(100% + 4px)", left: 0,
          background: t.cardBg, border: `1px solid ${t.cardBorder}`,
          borderRadius: 10, boxShadow: "0 8px 24px rgba(0,0,0,0.3)",
          zIndex: 200, minWidth: 140, overflow: "hidden",
        }}
        >
          {STATUS_OPTS.map((s) => (
            <button key={s} type="button" role="menuitem" onClick={() => { onChange(s); setOpen(false); }}
              style={{
                display: "block", width: "100%", padding: "9px 14px", border: "none",
                background: s === value ? `${STATUS_COLOR[s]}18` : "transparent",
                color: STATUS_COLOR[s], fontSize: "12px", fontWeight: 700,
                cursor: "pointer", textAlign: "left", fontFamily: FONT.body,
              }}
            >
              {STATUS_LABEL[s]}
            </button>
          ))}
        </div>
      )}
    </div>
  );
}

// ─── Componente Principal ─────────────────────────────────────────────────────
export default function Influencers() {
  const { theme: t, user, isDark, escoposVisiveis: _escoposVisiveis, podeVerInfluencer, podeVerOperadora } = useApp();
  const brand = useDashboardBrand();
  const { operadoraSlugsForcado, showFiltroOperadora } = useDashboardFiltros();
  const perm = usePermission("influencers");
  const showManagementUI = user?.role !== "influencer";
  // "proprios": ações apenas em registros do escopo do usuário
  const podeEditarInf = (infId: string) =>
    perm.canEditarOk && (perm.canEditar !== "proprios" || podeVerInfluencer(infId));
  // Status só pode ser alterado por Admin ou Gestor
  const podeAlterarStatus = user?.role === "admin" || user?.role === "gestor";

  const [list,           setList]           = useState<Influencer[]>([]);
  const [operadorasList, setOperadorasList] = useState<Operadora[]>([]);

  const operadorasNoEscopo = operadorasList.filter((o) => podeVerOperadora(o.slug));
  /** Sem cor salva: omitir — `OperadoraTag` aplica `--brand-action` via color-mix (não passar `var()` aqui: quebraria o sufixo `18` do componente). */
  const opsColorMap = Object.fromEntries(
    operadorasList.map((o) => [o.slug, o.brand_action?.trim() || undefined])
  );
  const [loading,        setLoading]        = useState(true);
  const [modal,          setModal]          = useState<{ mode: "visualizar" | "editar"; inf?: Influencer } | null>(null);

  // Filtros
  const [search,        setSearch]        = useState("");
  const [filterStatus,  setFilterStatus]  = useState<string>("todos");
  const [filterPlat,    setFilterPlat]    = useState<string>("todas");
  const [filterOp,      setFilterOp]      = useState<string>("todas");
  const [cacheMax,      setCacheMax]      = useState(5000);
  const [cacheLimit,    setCacheLimit]    = useState(5000);
  const [statusError,   setStatusError]   = useState("");

  async function loadData() {
    setLoading(true);
    const { data: opsList } = await supabase.from("operadoras").select("*").order("nome");
    setOperadorasList(opsList ?? []);
    const opsMap = Object.fromEntries((opsList ?? []).map((o: Operadora) => [o.slug, o.nome]));

    if (showManagementUI) {
      const { data: profiles } = await supabase
        .from("profiles").select("id, name, email").eq("role", "influencer").order("name");
      if (profiles) {
        const ids = profiles.map((p: any) => p.id);
        const [perfisRes, opsRes] = await Promise.all([
          ids.length > 0 ? supabase.from("influencer_perfil").select("*").in("id", ids) : { data: [] },
          ids.length > 0 ? supabase.from("influencer_operadoras").select("*").in("influencer_id", ids) : { data: [] },
        ]);
        const perfisMap: Record<string, Perfil> = {};
        (perfisRes.data ?? []).forEach((p: Perfil) => { perfisMap[p.id] = p; });
        const opsPorInf: Record<string, InfluencerOperadora[]> = {};
        (opsRes.data ?? []).forEach((o: InfluencerOperadora) => {
          if (!opsPorInf[o.influencer_id]) opsPorInf[o.influencer_id] = [];
          opsPorInf[o.influencer_id].push({ ...o, operadora_nome: opsMap[o.operadora_slug] ?? o.operadora_nome });
        });
        const mapped = profiles.map((p: any) => ({
          id: p.id,
          name: p.name ?? p.email,
          email: p.email,
          perfil: perfisMap[p.id] ?? null,
          operadoras: opsPorInf[p.id] ?? [],
        }));
        setList(mapped);

        const caches = mapped
          .map((i: Influencer) => i.perfil?.cache_hora ?? 0)
          .filter((v: number) => v > 0);
        if (caches.length > 0) {
          const mx = Math.max(...caches);
          setCacheMax(mx);
          setCacheLimit(mx);
        } else {
          setCacheMax(5000);
          setCacheLimit(5000);
        }
      }
    } else {
      if (!user) return;
      const [perfilRes, opsRes] = await Promise.all([
        supabase.from("influencer_perfil").select("*").eq("id", user.id).single(),
        supabase.from("influencer_operadoras").select("*").eq("influencer_id", user.id),
      ]);
      const perfil = perfilRes.data ?? null;
      const operadoras = ((opsRes.data ?? []) as InfluencerOperadora[]).map((o) => ({
        ...o,
        operadora_nome: opsMap[o.operadora_slug] ?? o.operadora_nome,
      }));
      setList([{
        id: user.id,
        name: user.name,
        email: user.email,
        perfil,
        operadoras,
      }]);
    }
    setLoading(false);
  }

  useEffect(() => { loadData(); }, []);

  async function handleStatusChange(infId: string, newStatus: StatusInfluencer) {
    if (!podeAlterarStatus) return;
    const previousStatus = list.find((i) => i.id === infId)?.perfil?.status;

    const agoraIso = new Date().toISOString();
    setList((prev) =>
      prev.map((i) =>
        i.id === infId
          ? {
              ...i,
              perfil: {
                ...(i.perfil ?? emptyPerfil(i.id)),
                status: newStatus,
                ...(previousStatus !== newStatus ? { status_alterado_em: agoraIso } : {}),
              },
            }
          : i
      )
    );

    const upsertPatch: Record<string, unknown> = { id: infId, status: newStatus };
    if (previousStatus !== newStatus) upsertPatch.status_alterado_em = agoraIso;

    const { error } = await supabase
      .from("influencer_perfil")
      .upsert(upsertPatch, { onConflict: "id" });

    if (error) {
      setList((prev) =>
        prev.map((i) =>
          i.id === infId
            ? { ...i, perfil: { ...(i.perfil ?? emptyPerfil(i.id)), status: previousStatus ?? "ativo" } }
            : i
        )
      );
      setStatusError("Erro ao salvar status. Tente novamente.");
    }
  }

  const filtered = list.filter((inf) => {
    if (!podeVerInfluencer(inf.id)) return false;
    const p = inf.perfil;
    const searchLower = search.toLowerCase();
    const nomeExibicao = p?.nome_artistico?.trim() || inf.name || "";
    if (search && !(
      nomeExibicao.toLowerCase().includes(searchLower) ||
      inf.name?.toLowerCase().includes(searchLower) ||
      inf.email?.toLowerCase().includes(searchLower)
    )) return false;
    if (filterStatus !== "todos" && (p?.status ?? "ativo") !== filterStatus) return false;
    if (filterPlat !== "todas" && !(p?.canais ?? []).includes(filterPlat as Plataforma)) return false;
    if (operadoraSlugsForcado?.length) {
      const temOp = inf.operadoras?.some((o) => operadoraSlugsForcado.includes(o.operadora_slug));
      if (!temOp) return false;
    } else if (filterOp !== "todas") {
      const temOp = inf.operadoras?.some((o) => o.operadora_slug === filterOp);
      if (!temOp) return false;
    }
    const cache = p?.cache_hora ?? 0;
    if (cacheLimit < cacheMax) {
      if (cache > cacheLimit) return false;
    }
    return true;
  });

  // Base para quadros: mesmo filtro de operadora que a lista (operador vê só sua operadora)
  const listNoEscopo = list.filter((i) => {
    if (!podeVerInfluencer(i.id)) return false;
    if (operadoraSlugsForcado?.length) {
      const temOp = i.operadoras?.some((o) => operadoraSlugsForcado.includes(o.operadora_slug));
      if (!temOp) return false;
    }
    return true;
  });

  // ── CORREÇÃO 2: apenas influencers ATIVOS no escopo entram no quadro de incompletos ──
  const incompletos = listNoEscopo.filter((i) =>
    (i.perfil?.status ?? "ativo") === "ativo" &&
    isPerfilIncompleto(i.perfil, i.perfil?.nome_artistico ?? i.name ?? "")
  );

  const porStatus: Record<StatusInfluencer, number> = { ativo: 0, inativo: 0, cancelado: 0 };
  const porPlat: Record<string, number> = {};
  listNoEscopo.forEach((inf) => {
    const s = inf.perfil?.status ?? "ativo";
    porStatus[s]++;
    (inf.perfil?.canais ?? []).forEach((c) => { porPlat[c] = (porPlat[c] ?? 0) + 1; });
  });

  const cardShadow = t.isDark ? "0 4px 20px rgba(0,0,0,0.25)" : "0 2px 8px rgba(0,0,0,0.07)";
  const ctaGradient = "linear-gradient(135deg, var(--brand-action, #4a2082), var(--brand-contrast, #1e36f8))";
  const sliderTrackGradient = "linear-gradient(90deg, var(--brand-action, #4a2082), var(--brand-contrast, #1e36f8))";
  const sliderThumbGradient = "linear-gradient(135deg, var(--brand-action, #4a2082), var(--brand-contrast, #1e36f8))";

  // ── Styles ──
  const cardStyle: CSSProperties = {
    background: brand.blockBg, border: `1px solid ${t.cardBorder}`,
    borderRadius: 18, padding: "18px 20px", marginBottom: "10px",
    display: "flex", alignItems: "center", justifyContent: "space-between",
    gap: "12px", flexWrap: "wrap",
    boxShadow: cardShadow,
  };
  if (perm.canView === "nao") {
    return (
      <div style={{ padding: 24, textAlign: "center", color: t.textMuted, fontFamily: FONT.body }}>
        Você não tem permissão para visualizar este dashboard.
      </div>
    );
  }

  return (
    <div className="app-page-shell" style={{ background: t.bg, minHeight: "100vh", fontFamily: FONT.body }}>

      <DashboardPageHeader
        icon={<Mic size={14} aria-hidden="true" />}
        title="Influencers"
        subtitle={showManagementUI ? "Gerencie o cadastro completo dos influencers parceiros." : "Seu perfil completo na plataforma."}
        brand={brand}
        t={t}
      />

      {/* Quadros resumo (quem gerencia múltiplos) */}
      {showManagementUI && (
        <div className="app-grid-2" style={{ gap: "16px", marginBottom: "20px" }}>
          <div style={{ background: brand.blockBg, border: `1px solid ${t.cardBorder}`, borderRadius: 18, padding: 20, boxShadow: cardShadow }}>
            <div style={{ display: "flex", alignItems: "center", gap: 6, fontSize: 11, fontWeight: 700, color: brand.secondary, letterSpacing: "1px", textTransform: "uppercase", fontFamily: FONT.body, marginBottom: 6 }}>
              <Users size={13} aria-hidden="true" style={{ color: brand.secondary }} /> Total de Influencers
            </div>
            <div style={{ fontSize: 36, fontWeight: 900, color: t.text, fontFamily: FONT_TITLE, marginBottom: 12, lineHeight: 1 }}>
              {listNoEscopo.length}
            </div>
            <div style={{ display: "flex", flexDirection: "column", gap: "5px" }}>
              {STATUS_OPTS.map((s) => (
                <div key={s} style={{ display: "flex", justifyContent: "space-between", alignItems: "center" }}>
                  <span style={{ fontSize: "12px", color: t.textMuted, fontFamily: FONT.body }}>{STATUS_LABEL[s]}</span>
                  <span style={{ fontSize: "13px", fontWeight: 700, color: STATUS_COLOR[s], fontFamily: FONT.body }}>{porStatus[s]}</span>
                </div>
              ))}
            </div>
          </div>

          <div style={{ background: brand.blockBg, border: `1px solid ${BRAND.vermelho}33`, borderRadius: 18, padding: 20, boxShadow: cardShadow }}>
            <div style={{ display: "flex", alignItems: "center", gap: 6, fontSize: 11, fontWeight: 700, color: BRAND.vermelho, letterSpacing: "1px", textTransform: "uppercase", fontFamily: FONT.body, marginBottom: 6 }}>
              <AlertCircle size={13} aria-hidden="true" /> Perfil Incompleto
            </div>
            <div style={{ fontSize: 36, fontWeight: 900, color: BRAND.vermelho, fontFamily: FONT_TITLE, marginBottom: 12, lineHeight: 1 }}>
              {incompletos.length}
            </div>
            {incompletos.length === 0 ? (
              <div style={{ display: "flex", alignItems: "center", gap: 6, fontSize: 13, color: BRAND.verde, fontFamily: FONT.body }}>
                <CheckCircle size={14} aria-hidden="true" /> Todos os perfis ativos estão completos!
              </div>
            ) : (
              <div style={{ display: "flex", flexDirection: "column", gap: 6 }}>
                {incompletos.map((inf) => {
                  const nomeInf = inf.perfil?.nome_artistico || inf.name;
                  return podeEditarInf(inf.id) ? (
                    <button type="button" key={inf.id} onClick={() => setModal({ mode: "editar", inf })}
                      style={{ background: "none", border: "none", cursor: "pointer", padding: 0, textAlign: "left", fontSize: 13, color: BRAND.azul, fontFamily: FONT.body, textDecoration: "underline", fontWeight: 500 }}>
                      {nomeInf}
                    </button>
                  ) : (
                    <span key={inf.id} style={{ fontSize: 13, color: t.textMuted, fontFamily: FONT.body }}>{nomeInf}</span>
                  );
                })}
              </div>
            )}
          </div>
        </div>
      )}

      {/* Bloco de filtros consolidado (estilo Agenda, sem carrossel) */}
      {showManagementUI && (
        <div style={{ marginBottom: 20 }}>
          <div style={{
            borderRadius: 14,
            border: `1px solid ${t.cardBorder}`,
            background: brand.blockBg,
            padding: "12px 20px",
          }}>
            {/* Linha 1: Status / Operadora */}
            <div style={{ display: "flex", alignItems: "center", gap: 10, flexWrap: "wrap", justifyContent: "flex-start" }}>
              <span style={{ fontSize: 10, fontWeight: 700, color: t.textMuted, fontFamily: FONT.body, textTransform: "uppercase", letterSpacing: "0.1em", marginRight: 4 }}>Status</span>
              {STATUS_OPTS.map((s) => {
                const active = filterStatus === s;
                const color = STATUS_COLOR[s];
                return (
                  <button key={s} type="button" onClick={() => setFilterStatus(active ? "todos" : s)}
                    style={{
                      display: "flex", alignItems: "center", gap: 6,
                      padding: "5px 12px", borderRadius: 999, cursor: "pointer",
                      border: `1px solid ${active ? color : color + "55"}`,
                      background: active ? `${color}22` : "transparent",
                      color: active ? color : t.textMuted, fontSize: 12, fontWeight: active ? 700 : 400,
                      fontFamily: FONT.body, transition: "all 0.15s",
                      lineHeight: 1,
                    }}
                  >
                    <span style={{ width: 8, height: 8, borderRadius: "50%", background: color, flexShrink: 0, alignSelf: "center" }} />
                    <span style={{ display: "inline-flex", alignItems: "center" }}>{STATUS_LABEL[s]}</span>
                    {active && <span style={{ display: "inline-flex", alignItems: "center", lineHeight: 0 }}><X size={9} aria-hidden="true" /></span>}
                  </button>
                );
              })}
              {showFiltroOperadora && operadorasNoEscopo.length > 0 && (
                <>
                  <span style={{ width: 1, height: 16, background: t.cardBorder, margin: "0 4px", flexShrink: 0 }} />
                  <span style={{ fontSize: 10, fontWeight: 700, color: t.textMuted, fontFamily: FONT.body, textTransform: "uppercase", letterSpacing: "0.1em", marginRight: 4 }}>Operadora</span>
                  <SelectComIcone
                    pill
                    icon={<Shield size={15} aria-hidden="true" />}
                    label="Filtrar por operadora"
                    value={filterOp}
                    onChange={setFilterOp}
                    minWidth={200}
                    style={{
                      border: `1px solid ${filterOp !== "todas" ? brand.accent : t.cardBorder}`,
                      background:
                        filterOp !== "todas"
                          ? brand.useBrand
                            ? "color-mix(in srgb, var(--brand-contrast, #1e36f8) 15%, transparent)"
                            : `${BRAND.roxoVivo}18`
                          : (t.inputBg ?? t.cardBg),
                      color: filterOp !== "todas" ? brand.accent : t.textMuted,
                      fontWeight: filterOp !== "todas" ? 700 : 400,
                    }}
                  >
                    <option value="todas">Todas as operadoras</option>
                    {operadorasNoEscopo.map((o) => (
                      <option key={o.slug} value={o.slug}>{o.nome}</option>
                    ))}
                  </SelectComIcone>
                </>
              )}
            </div>

            {/* Linha 2: Plataforma */}
            <div style={{ display: "flex", alignItems: "center", gap: 10, flexWrap: "wrap", justifyContent: "flex-start", paddingTop: 12, marginTop: 12, borderTop: `1px solid ${t.cardBorder}` }}>
              <span style={{ fontSize: 10, fontWeight: 700, color: t.textMuted, fontFamily: FONT.body, textTransform: "uppercase", letterSpacing: "0.1em", marginRight: 4 }}>Plataforma</span>
              {PLATAFORMAS.map((plat) => {
                const active = filterPlat === plat;
                const color = PLAT_COLOR[plat as Plataforma] ?? "#94a3b8";
                const nPlat = porPlat[plat] ?? 0;
                return (
                  <button key={plat} type="button" onClick={() => setFilterPlat(active ? "todas" : plat)}
                    style={{
                      display: "inline-flex", alignItems: "center", gap: 6,
                      padding: "5px 12px", borderRadius: 999, cursor: "pointer",
                      border: `1px solid ${active ? color : color + "55"}`,
                      background: active ? `${color}22` : `${color}11`,
                      color: active ? color : color + "cc",
                      fontSize: 12, fontWeight: active ? 700 : 500,
                      fontFamily: FONT.body, transition: "all 0.15s",
                      lineHeight: 1,
                    }}
                  >
                    <PlatLogo plataforma={plat} size={13} isDark={isDark ?? false} />
                    <span style={{ whiteSpace: "nowrap", display: "inline-flex", alignItems: "center" }}>{plat}</span>
                    <span style={{ width: 1, height: 10, background: `${color}44`, flexShrink: 0, alignSelf: "center" }} aria-hidden />
                    <span style={{ fontSize: 12, fontWeight: 800, color: nPlat > 0 ? t.text : t.textMuted, fontFamily: FONT_TITLE, flexShrink: 0, lineHeight: 1, display: "inline-flex", alignItems: "center" }}>
                      {nPlat}
                    </span>
                    {active && <span style={{ display: "inline-flex", alignItems: "center", lineHeight: 0 }}><X size={9} aria-hidden="true" /></span>}
                  </button>
                );
              })}
            </div>

            {/* Linha 3: Filtro de Cachê */}
            {cacheMax > 0 && (
              <div style={{
                paddingTop: 12, marginTop: 12, borderTop: `1px solid ${t.cardBorder}`,
                paddingBottom: 12,
              }}>
                <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 10 }}>
                  <span style={{ display: "flex", alignItems: "center", gap: 6, fontSize: 11, fontWeight: 700, letterSpacing: "1.2px", textTransform: "uppercase", color: brand.secondary, fontFamily: FONT.body }}>
                    <Coins size={13} aria-hidden="true" style={{ color: brand.secondary }} /> Cachê por Hora — até
                  </span>
                  <span style={{ fontSize: 13, fontWeight: 700, color: brand.accent, fontFamily: FONT.body }}>
                    {cacheLimit >= cacheMax ? "Todos" : fmtBRL(cacheLimit) + "/h"}
                  </span>
                </div>
                <div style={{ position: "relative", height: 20, display: "flex", alignItems: "center" }}>
                  <div style={{ position: "absolute", left: 0, right: 0, height: 4, borderRadius: 2, background: t.cardBorder }} />
                  <div style={{ position: "absolute", left: 0, width: `${(cacheLimit / cacheMax) * 100}%`, height: 4, borderRadius: 2, background: sliderTrackGradient }} />
                  <input
                    type="range"
                    min={0}
                    max={cacheMax}
                    step={50}
                    value={cacheLimit}
                    onChange={(e) => setCacheLimit(Number(e.target.value))}
                    aria-label="Filtrar por cachê máximo por hora"
                    aria-valuemin={0}
                    aria-valuemax={cacheMax}
                    aria-valuenow={cacheLimit}
                    aria-valuetext={cacheLimit >= cacheMax ? "Todos" : `Até ${fmtBRL(cacheLimit)}/h`}
                    style={{ position: "absolute", width: "100%", opacity: 0, cursor: "pointer", height: 20, zIndex: 2 }}
                  />
                  <div style={{ position: "absolute", left: `calc(${(cacheLimit / cacheMax) * 100}% - 8px)`, width: 16, height: 16, borderRadius: "50%", background: sliderThumbGradient, border: "2px solid white", boxShadow: "0 2px 6px rgba(0,0,0,0.3)", pointerEvents: "none", zIndex: 3 }} />
                </div>
                <div style={{ display: "flex", justifyContent: "space-between", marginTop: "8px" }}>
                  <span style={{ fontSize: "11px", color: t.textMuted, fontFamily: FONT.body }}>R$ 0</span>
                  <span style={{ fontSize: "11px", color: t.textMuted, fontFamily: FONT.body }}>{fmtBRL(cacheMax)}/h</span>
                </div>
              </div>
            )}

            {/* Linha 4: Barra de Pesquisa */}
            <div style={{ paddingTop: 12, marginTop: 12, borderTop: `1px solid ${t.cardBorder}` }}>
              <input
                value={search} onChange={(e) => setSearch(e.target.value)}
                placeholder="Buscar por nome artístico ou e-mail..."
                style={{
                  width: "100%", boxSizing: "border-box", padding: "10px 16px",
                  borderRadius: 12, border: `1px solid ${t.cardBorder}`,
                  background: t.inputBg ?? t.cardBg, color: t.text, fontSize: 13,
                  fontFamily: FONT.body, outline: "none",
                }}
              />
            </div>

            {(filterStatus !== "todos" || filterPlat !== "todas" || filterOp !== "todas" || search || (cacheMax > 0 && cacheLimit < cacheMax)) && (
              <div style={{ marginTop: 12, display: "flex", justifyContent: "center" }}>
                <button
                  type="button"
                  onClick={() => { setFilterStatus("todos"); setFilterPlat("todas"); setFilterOp("todas"); setSearch(""); setCacheLimit(cacheMax); }}
                  style={{
                    padding: "5px 14px", borderRadius: 999,
                    border: `1px solid ${BRAND.vermelho}44`,
                    background: `${BRAND.vermelho}11`,
                    color: BRAND.vermelho, fontSize: 12, fontWeight: 600,
                    fontFamily: FONT.body, cursor: "pointer",
                    display: "inline-flex",
                    alignItems: "center",
                    gap: 6,
                  }}
                >
                  <X size={12} aria-hidden="true" /> Limpar filtros
                </button>
              </div>
            )}
          </div>
        </div>
      )}

      {/* Contador */}
      {!loading && showManagementUI && (
        <div style={{ fontSize: "12px", color: t.textMuted, fontFamily: FONT.body, marginBottom: "14px" }}>
          <span style={{ color: brand.accent, fontWeight: 700 }}>{filtered.length}</span> influencer(s)
        </div>
      )}

      {statusError && (
        <div
          style={{
            background: `${BRAND.vermelho}18`,
            border: `1px solid ${BRAND.vermelho}44`,
            color: BRAND.vermelho,
            borderRadius: 10,
            padding: "10px 14px",
            fontSize: 13,
            marginBottom: 14,
            fontFamily: FONT.body,
            display: "flex",
            alignItems: "center",
            justifyContent: "space-between",
          }}
          role="alert"
          aria-live="polite"
        >
          {statusError}
          <button
            type="button"
            onClick={() => setStatusError("")}
            aria-label="Fechar erro"
            style={{ background: "none", border: "none", cursor: "pointer", color: BRAND.vermelho, display: "flex" }}
          >
            <X size={14} aria-hidden="true" />
          </button>
        </div>
      )}

      {/* Lista */}
      {loading ? (
        <div style={{ textAlign: "center", padding: "60px", color: t.textMuted, fontFamily: FONT.body, display: "flex", alignItems: "center", justifyContent: "center", gap: 8 }}>
          <Loader2 size={16} className="app-lucide-spin" aria-hidden="true" />
          Carregando...
        </div>
      ) : filtered.length === 0 ? (
        <div style={{ background: brand.blockBg, border: `1px solid ${t.cardBorder}`, borderRadius: 18, padding: 48, textAlign: "center", color: t.textMuted, fontFamily: FONT.body, boxShadow: cardShadow }}>
          Nenhum influencer encontrado.
        </div>
      ) : (
        filtered.map((inf) => {
          const p          = inf.perfil;
          const canais     = p?.canais ?? [];
          const opsAtivas  = (inf.operadoras ?? []).filter((o) => o.ativo);
          const incompleto = isPerfilIncompleto(p, inf.name);
          const status: StatusInfluencer = p?.status ?? "ativo";
          return (
            <div key={inf.id} style={cardStyle}>
              <div style={{ display: "flex", alignItems: "center", gap: "14px", flex: 1, minWidth: 0 }}>
                <div style={{
                  width: 44, height: 44, borderRadius: "50%", flexShrink: 0,
                  background: ctaGradient,
                  display: "flex", alignItems: "center", justifyContent: "center",
                  color: "#fff", fontWeight: 800, fontSize: 16, fontFamily: FONT.body,
                }}>
                  {((p?.nome_artistico || inf.name) || inf.email)[0]?.toUpperCase()}
                </div>
                <div style={{ minWidth: 0, flex: 1 }}>
                  <div style={{
                    display: "flex", alignItems: "center",
                    gap: "16px", rowGap: "8px",
                    flexWrap: "wrap", marginBottom: "10px",
                  }}>
                    <span style={{ fontSize: "14px", fontWeight: 700, color: t.text, fontFamily: FONT.body }}>
                      {p?.nome_artistico || inf.name}
                    </span>
                    <StatusBadge value={status} onChange={(v) => handleStatusChange(inf.id, v)} readonly={!podeAlterarStatus} />
                    {incompleto && status === "ativo" && (
                      <span style={{ display: "inline-flex", alignItems: "center", gap: 4, fontSize: 11, padding: "3px 9px", borderRadius: 20, background: `${BRAND.vermelho}22`, color: BRAND.vermelho, fontWeight: 600, fontFamily: FONT.body }}>
                        <AlertCircle size={10} aria-hidden="true" /> Perfil incompleto
                      </span>
                    )}
                  </div>
                  {p?.cache_hora && p.cache_hora > 0 && (
                    <div style={{ display: "flex", alignItems: "center", gap: 5, fontSize: 12, color: t.textMuted, fontFamily: FONT.body, marginBottom: 5 }}>
                      <Coins size={12} aria-hidden="true" style={{ color: brand.secondary }} /> {fmtBRL(p.cache_hora)}/h
                    </div>
                  )}
                  {canais.length > 0 && (
                    <div style={{ display: "flex", flexDirection: "column", gap: "3px", marginBottom: "6px" }}>
                      {canais.map((c) => {
                        const link = p?.[`link_${c.toLowerCase()}` as keyof Perfil] as string;
                        const content = (
                          <span style={{ display: "inline-flex", alignItems: "center", gap: 5, fontSize: 12, color: PLAT_COLOR[c], fontFamily: FONT.body, lineHeight: 1 }}>
                            <PlatLogo plataforma={c} size={12} isDark={isDark ?? false} />
                            <span style={{ display: "inline-flex", alignItems: "center" }}>{c}</span>
                            {link && <span style={{ fontSize: 10, opacity: 0.7, display: "inline-flex", alignItems: "center" }}>↗</span>}
                          </span>
                        );
                        return link ? (
                          <a
                            key={c}
                            href={link.startsWith("http") ? link : `https://${link}`}
                            target="_blank"
                            rel="noopener noreferrer"
                            aria-label={`Ver canal ${c} do influencer (abre em nova aba)`}
                            onClick={(e) => e.stopPropagation()}
                            style={{ textDecoration: "none" }}
                          >
                            {content}
                          </a>
                        ) : <span key={c}>{content}</span>;
                      })}
                    </div>
                  )}
                  {opsAtivas.length > 0 && user?.role !== "operador" && (
                    <div style={{ display: "flex", gap: 5, flexWrap: "wrap" }}>
                      {opsAtivas.map((o) => (
                        <OperadoraTag
                          key={o.operadora_slug}
                          label={o.operadora_nome ?? o.operadora_slug}
                          corPrimaria={opsColorMap[o.operadora_slug]}
                          icon={<Building2 size={11} aria-hidden="true" />}
                        />
                      ))}
                    </div>
                  )}
                </div>
              </div>
              <div style={{ display: "flex", gap: 8, flexShrink: 0 }}>
                <button
                  type="button"
                  onClick={() => setModal({ mode: "visualizar", inf })}
                  aria-label={`Ver perfil de ${p?.nome_artistico || inf.name}`}
                  style={{
                    display: "inline-flex", alignItems: "center", gap: 6,
                    padding: "8px 14px", borderRadius: 10,
                    border: `1px solid ${t.cardBorder}`, background: t.inputBg ?? t.cardBg,
                    color: t.textMuted, fontSize: 12, fontWeight: 700, fontFamily: FONT.body, cursor: "pointer",
                    lineHeight: 1,
                  }}
                >
                  <span style={{ display: "inline-flex", alignItems: "center", lineHeight: 0 }}><Eye size={13} aria-hidden="true" /></span>
                  <span style={{ display: "inline-flex", alignItems: "center" }}>Ver</span>
                </button>
                {podeEditarInf(inf.id) && (
                  <button
                    type="button"
                    onClick={() => setModal({ mode: "editar", inf })}
                    aria-label={`Editar perfil de ${p?.nome_artistico || inf.name}`}
                    style={{
                      display: "inline-flex", alignItems: "center", gap: 6,
                      padding: "8px 14px", borderRadius: 10, border: "none", cursor: "pointer",
                      background: ctaGradient,
                      color: "#fff", fontSize: 12, fontWeight: 700, fontFamily: FONT.body,
                      lineHeight: 1,
                    }}
                  >
                    <span style={{ display: "inline-flex", alignItems: "center", lineHeight: 0 }}><Pencil size={13} aria-hidden="true" /></span>
                    <span style={{ display: "inline-flex", alignItems: "center" }}>Editar</span>
                  </button>
                )}
              </div>
            </div>
          );
        })
      )}

      {modal?.mode === "visualizar" && modal.inf && (
        <ModalVisualizar
          influencer={modal.inf}
          operadorasList={operadorasNoEscopo}
          onClose={() => setModal(null)}
          isDark={isDark}
        />
      )}
      {modal?.mode === "editar" && modal.inf && (
        <ModalPerfil
          influencer={modal.inf}
          operadorasList={operadorasNoEscopo}
          onClose={() => setModal(null)}
          onSaved={() => { setModal(null); loadData(); }}
          isDark={isDark}
        />
      )}
    </div>
  );
}

// ─── Modal Visualizar ─────────────────────────────────────────────────────────
function ModalVisualizar({ influencer, operadorasList, onClose, isDark }: {
  influencer: Influencer; operadorasList: Operadora[]; onClose: () => void; isDark?: boolean;
}) {
  const { theme: t } = useApp();
  const brand = useDashboardBrand();
  const containerRef = useRef<HTMLDivElement>(null);
  const p = influencer.perfil;
  const [tab, setTab] = useState<"cadastral" | "canais" | "financeiro" | "operadoras" | "historico">("cadastral");

  useEffect(() => {
    const id = window.setTimeout(() => containerRef.current?.focus(), 50);
    return () => window.clearTimeout(id);
  }, []);

  const tabs = [
    { key: "cadastral"   as const, label: "Cadastral"  },
    { key: "canais"      as const, label: "Canais"     },
    { key: "financeiro"  as const, label: "Financeiro" },
    { key: "operadoras"  as const, label: "Operadoras" },
    { key: "historico"   as const, label: "Histórico" },
  ];

  function fmtTs(iso?: string | null) {
    if (!iso) return "—";
    try {
      return new Date(iso).toLocaleString("pt-BR", { dateStyle: "short", timeStyle: "short" });
    } catch {
      return "—";
    }
  }

  const labelStyle: CSSProperties = {
    display: "block", fontSize: 11, fontWeight: 700, letterSpacing: "1.1px",
    textTransform: "uppercase", color: t.textMuted, marginBottom: 5, fontFamily: FONT.body,
  };
  const row: CSSProperties = { marginBottom: 14 };
  const tabActiveBg = brand.useBrand ? "var(--brand-action-12)" : "color-mix(in srgb, var(--brand-action, #7c3aed) 15%, transparent)";
  const val = (v?: string | number) => (
    <span style={{ fontSize: "13px", color: v ? t.text : t.textMuted, fontFamily: FONT.body }}>
      {v || "—"}
    </span>
  );

  return (
    <div className="app-modal-overlay-pad" style={{ position: "fixed", inset: 0, background: "#00000088", display: "flex", alignItems: "center", justifyContent: "center", zIndex: 1000 }}
      onClick={(e) => { if (e.target === e.currentTarget) onClose(); }}>
      <div
        ref={containerRef}
        tabIndex={-1}
        role="dialog"
        aria-modal="true"
        aria-labelledby="modal-visualizar-title"
        style={{ background: brand.blockBg, border: `1px solid ${t.cardBorder}`, borderRadius: "20px", padding: "28px", width: "100%", maxWidth: "520px", maxHeight: "92vh", overflowY: "auto" }}
      >

        <div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-start", marginBottom: "18px" }}>
          <div>
            <div style={{ display: "flex", alignItems: "center", gap: "12px", flexWrap: "wrap", marginBottom: "4px" }}>
              <h2 id="modal-visualizar-title" style={{ margin: 0, fontSize: 17, fontWeight: 800, color: t.text, fontFamily: FONT_TITLE, letterSpacing: "0.03em" }}>
                {p?.nome_artistico || influencer.name}
              </h2>
              {p?.status && <StatusBadge value={p.status} onChange={() => {}} readonly />}
            </div>
            <div style={{ fontSize: "12px", color: t.textMuted, fontFamily: FONT.body }}>{influencer.email}</div>
          </div>
          <button type="button" onClick={onClose} aria-label="Fechar" style={{ background: "none", border: "none", cursor: "pointer", color: t.textMuted, display: "flex", alignItems: "center", padding: 4 }}>
            <X size={18} aria-hidden="true" />
          </button>
        </div>

        <div style={{ display: "flex", alignItems: "center", gap: 8, padding: "8px 14px", borderRadius: 10, background: brand.useBrand ? "var(--brand-action-12)" : `${BRAND.azul}0d`, border: `1px solid ${brand.useBrand ? "var(--brand-action-border)" : `${BRAND.azul}30`}`, fontSize: 12, color: t.textMuted, fontFamily: FONT.body, marginBottom: 18 }}>
          <Eye size={13} aria-hidden="true" style={{ color: brand.primary, flexShrink: 0 }} />
          <span>Modo visualização — somente leitura. Dados sensíveis protegidos.</span>
        </div>

        <div style={{ display: "flex", gap: 6, marginBottom: 20, flexWrap: "nowrap", overflowX: "auto", WebkitOverflowScrolling: "touch", paddingBottom: 2 }}>
          {tabs.map((tb) => (
            <button
              key={tb.key}
              type="button"
              aria-pressed={tab === tb.key}
              onClick={() => setTab(tb.key)}
              style={{
                padding: "7px 14px", borderRadius: 20, flexShrink: 0,
                border: `1px solid ${tab === tb.key ? brand.primary : t.cardBorder}`,
                background: tab === tb.key ? tabActiveBg : (t.inputBg ?? t.cardBg),
                color: tab === tb.key ? brand.primary : t.textMuted, fontSize: 12, fontWeight: 600, cursor: "pointer", fontFamily: FONT.body,
              }}
            >
              {tb.label}
            </button>
          ))}
        </div>

        {tab === "cadastral" && (
          <>
            <div style={row}><label style={labelStyle}>Nome Completo</label>{val(p?.nome_completo)}</div>
            <div style={row}><label style={labelStyle}>Nome Artístico</label>{val(p?.nome_artistico ?? influencer.name)}</div>
            <div style={row}><label style={labelStyle}>E-mail</label>{val(influencer.email)}</div>
            <div style={row}><label style={labelStyle}>Telefone</label>{val(p?.telefone)}</div>
            <div style={row}>
              <SensitiveField value={p?.cpf} label="CPF" labelStyle={labelStyle} textStyle={{ fontSize: 13, color: t.text, fontFamily: FONT.body }} />
            </div>
          </>
        )}

        {tab === "canais" && (
          <div style={row}>
            <label style={labelStyle}>Plataformas Ativas</label>
            <div style={{ display: "flex", flexDirection: "column", gap: "8px" }}>
              {(p?.canais ?? []).length === 0 ? (
                <span style={{ color: t.textMuted, fontSize: "13px", fontFamily: FONT.body }}>—</span>
              ) : (
                (p?.canais ?? []).map((c) => {
                  const link = p?.[`link_${c.toLowerCase()}` as keyof Perfil] as string;
                  const inner = (
                    <span style={{ display: "inline-flex", alignItems: "center", gap: 7, padding: "6px 12px", borderRadius: 20, border: `2px solid ${PLAT_COLOR[c]}`, background: `${PLAT_COLOR[c]}18`, color: PLAT_COLOR[c], fontSize: 12, fontWeight: 700, fontFamily: FONT.body, lineHeight: 1 }}>
                      <PlatLogo plataforma={c} size={13} isDark={isDark ?? false} />
                      <span style={{ display: "inline-flex", alignItems: "center" }}>{c}</span>
                      {link && <span style={{ fontSize: 10, opacity: 0.7, display: "inline-flex", alignItems: "center" }}>↗</span>}
                    </span>
                  );
                  return link ? (
                    <a
                      key={c}
                      href={link.startsWith("http") ? link : `https://${link}`}
                      target="_blank"
                      rel="noopener noreferrer"
                      aria-label={`Ver canal ${c} do influencer (abre em nova aba)`}
                      style={{ textDecoration: "none" }}
                    >
                      {inner}
                    </a>
                  ) : <span key={c}>{inner}</span>;
                })
              )}
            </div>
          </div>
        )}

        {tab === "financeiro" && (
          <>
            <div style={row}><label style={labelStyle}>Cachê por Hora</label>{val(p?.cache_hora ? fmtBRL(p.cache_hora) : "")}</div>
            <div style={row}>
              <SensitiveField value={p?.chave_pix} label="Chave PIX" labelStyle={labelStyle} textStyle={{ fontSize: 13, color: t.text, fontFamily: FONT.body }} />
            </div>
            <div style={row}>
              <SensitiveField value={p?.banco} label="Banco" labelStyle={labelStyle} textStyle={{ fontSize: 13, color: t.text, fontFamily: FONT.body }} />
            </div>
            <div className="app-grid-2-tight" style={{ ...row, gap: 12 }}>
              <SensitiveField value={p?.agencia} label="Agência" labelStyle={labelStyle} textStyle={{ fontSize: 13, color: t.text, fontFamily: FONT.body }} />
              <SensitiveField value={p?.conta} label="Conta" labelStyle={labelStyle} textStyle={{ fontSize: 13, color: t.text, fontFamily: FONT.body }} />
            </div>
          </>
        )}

        {tab === "operadoras" && (
          <>
            {operadorasList.length === 0 ? (
              <p style={{ fontSize: "13px", color: t.textMuted, fontFamily: FONT.body }}>Nenhuma operadora cadastrada na plataforma.</p>
            ) : (
              operadorasList.map((op) => {
                const vinculo = influencer.operadoras?.find((o) => o.operadora_slug === op.slug);
                const ativo = !!vinculo?.ativo;
                const id = vinculo?.id_operadora;
                const opColor = op.brand_action?.trim() || "var(--brand-action, #7c3aed)";
                return (
                  <div key={op.slug} style={{ marginBottom: 14, padding: 14, borderRadius: 12, border: `1px solid ${ativo ? `color-mix(in srgb, ${opColor} 40%, transparent)` : t.cardBorder}`, background: ativo ? `color-mix(in srgb, ${opColor} 12%, transparent)` : "transparent" }}>
                    <div style={{ display: "flex", alignItems: "center", justifyContent: "space-between" }}>
                      <span style={{ display: "flex", alignItems: "center", gap: 6, fontSize: 13, fontWeight: 700, color: t.text, fontFamily: FONT.body }}>
                        <Building2 size={13} aria-hidden="true" style={{ color: opColor }} /> {op.nome}
                      </span>
                      <span style={{ padding: "4px 12px", borderRadius: 20, border: `1px solid ${ativo ? `color-mix(in srgb, ${opColor} 45%, transparent)` : t.cardBorder}`, background: ativo ? `color-mix(in srgb, ${opColor} 22%, transparent)` : (t.inputBg ?? t.cardBg), color: ativo ? opColor : t.textMuted, fontSize: 11, fontWeight: 700, fontFamily: FONT.body }}>
                        {ativo ? "Ativo" : "Inativo"}
                      </span>
                    </div>
                    {ativo && id && <div style={{ marginTop: "8px", fontSize: "13px", color: t.text, fontFamily: FONT.body }}>ID: {id}</div>}
                  </div>
                );
              })
            )}
          </>
        )}

        {tab === "historico" && (
          <>
            <div style={row}><label style={labelStyle}>Data de criação (cadastro)</label>{val(fmtTs(p?.created_at))}</div>
            <div style={row}><label style={labelStyle}>Data da última atualização</label>{val(fmtTs(p?.updated_at))}</div>
            <div style={row}><label style={labelStyle}>Data da última alteração de status</label>{val(fmtTs(p?.status_alterado_em))}</div>
            <p style={{ fontSize: 11, color: t.textMuted, fontFamily: FONT.body, margin: 0, lineHeight: 1.45 }}>
              As datas vêm do cadastro do influencer. A alteração de status é registrada a partir desta versão do sistema.
            </p>
          </>
        )}
      </div>
    </div>
  );
}

// ─── Modal Editar ─────────────────────────────────────────────────────────────
type OperadorasFormState = Record<string, { ativo: boolean; id_operadora: string }>;

function ModalPerfil({ influencer, operadorasList, onClose, onSaved, isDark }: {
  influencer: Influencer; operadorasList: Operadora[]; onClose: () => void; onSaved: () => void; isDark?: boolean;
}) {
  const { theme: t, user } = useApp();
  const brand = useDashboardBrand();
  const containerRef = useRef<HTMLDivElement>(null);
  const existing = influencer.perfil;
  const tabActiveBg = brand.useBrand ? "var(--brand-action-12)" : "color-mix(in srgb, var(--brand-action, #7c3aed) 15%, transparent)";
  const ctaSalvar = "linear-gradient(135deg, var(--brand-action, #4a2082), var(--brand-contrast, #1e36f8))";

  useEffect(() => {
    const id = window.setTimeout(() => containerRef.current?.focus(), 50);
    return () => window.clearTimeout(id);
  }, []);
  // Status e Cachê somente Gestores e Admin podem alterar
  const podeAlterarStatusCache = user?.role === "admin" || user?.role === "gestor";

  const inicialOperadoras: OperadorasFormState = {};
  operadorasList.forEach((o) => {
    const v = influencer.operadoras?.find((vinc) => vinc.operadora_slug === o.slug);
    inicialOperadoras[o.slug] = v
      ? { ativo: !!v.ativo, id_operadora: v.id_operadora ?? "" }
      : { ativo: false, id_operadora: "" };
  });

  const [editNomeCompleto, setEditNomeCompleto] = useState(influencer.perfil?.nome_completo ?? "");
  const [form,           setForm]           = useState<Perfil>(existing ?? emptyPerfil(influencer.id));
  const [operadorasForm, setOperadorasForm] = useState<OperadorasFormState>(inicialOperadoras);
  const [saving,         setSaving]         = useState(false);
  const [error,          setError]          = useState("");
  const [tab,            setTab]            = useState<"cadastral" | "canais" | "financeiro" | "operadoras">("cadastral");

  const set = (key: keyof Perfil, val: any) => setForm((f) => ({ ...f, [key]: val }));

  const setOp = (slug: string, patch: Partial<{ ativo: boolean; id_operadora: string }>) => {
    setOperadorasForm((prev) => {
      const cur = prev[slug] ?? { ativo: false, id_operadora: "" };
      return { ...prev, [slug]: { ...cur, ...patch } };
    });
  };

  const toggleCanal = (c: Plataforma) => {
    const cur = form.canais ?? [];
    set("canais", cur.includes(c) ? cur.filter((x) => x !== c) : [...cur, c]);
  };

  async function handleSave() {
    setError("");

    const temCanalSemLink = (form.canais ?? []).some((c) => {
      const link = form[`link_${c.toLowerCase()}` as keyof Perfil] as string;
      return !link?.trim();
    });
    if (temCanalSemLink) return setError("Preencha o link de cada canal selecionado.");

    const opsAtivas = Object.entries(operadorasForm).filter(([_, st]) => st.ativo);
    const temOpSemId = opsAtivas.some(([_, st]) => !st.id_operadora?.trim());
    if (temOpSemId) return setError("Preencha o ID de cada operadora ativa.");

    setSaving(true);

    if (form.nome_artistico?.trim()) {
      await supabase.from("profiles").update({ name: form.nome_artistico.trim() }).eq("id", influencer.id);
    }

    const payload: Perfil & { nome_completo: string; updated_at: string; status_alterado_em?: string } = {
      ...form,
      nome_completo: editNomeCompleto.trim(),
      updated_at: new Date().toISOString(),
    };
    // Impede alteração de status e cache por usuários sem permissão (backend defense)
    if (!podeAlterarStatusCache && existing) {
      payload.status = existing.status ?? "ativo";
      payload.cache_hora = existing.cache_hora ?? 0;
    } else if (existing && (payload.cache_hora == null || Number.isNaN(Number(payload.cache_hora)))) {
      payload.cache_hora = existing.cache_hora ?? 0;
    }
    if (existing && podeAlterarStatusCache && form.status !== existing.status) {
      payload.status_alterado_em = new Date().toISOString();
    }
    const { error: err } = existing
      ? await supabase.from("influencer_perfil").update(payload).eq("id", influencer.id)
      : await supabase.from("influencer_perfil").insert(payload);
    if (err) { setError(err.message); setSaving(false); return; }

    const slugsGeridos = new Set(operadorasList.map((o) => o.slug));
    for (const slug of slugsGeridos) {
      const st = operadorasForm[slug] ?? { ativo: false, id_operadora: "" };
      await supabase.from("influencer_operadoras").delete().eq("influencer_id", influencer.id).eq("operadora_slug", slug);
      if (st.ativo && st.id_operadora?.trim()) {
        await supabase.from("influencer_operadoras").insert({
          influencer_id: influencer.id,
          operadora_slug: slug,
          id_operadora: st.id_operadora.trim(),
          ativo: true,
        });
      }
    }

    setSaving(false);
    onSaved();
  }

  const inputStyle: CSSProperties = {
    width: "100%", boxSizing: "border-box", padding: "10px 14px",
    borderRadius: 10, border: `1px solid ${t.cardBorder}`,
    background: t.inputBg ?? t.cardBg, color: t.text,
    fontSize: 13, fontFamily: FONT.body, outline: "none",
  };
  const labelStyle: CSSProperties = {
    display: "block", fontSize: 10, fontWeight: 700, letterSpacing: "1.1px",
    textTransform: "uppercase", color: t.textMuted, marginBottom: 5, fontFamily: FONT.body,
  };
  const row: CSSProperties = { marginBottom: 14 };
  const tabs = [
    { key: "cadastral"   as const, label: "Cadastral"  },
    { key: "canais"      as const, label: "Canais"     },
    { key: "financeiro"  as const, label: "Financeiro" },
    { key: "operadoras"  as const, label: "Operadoras" },
  ];

  return (
    <div className="app-modal-overlay-pad" style={{ position: "fixed", inset: 0, background: "#00000088", display: "flex", alignItems: "center", justifyContent: "center", zIndex: 1000 }}
      onClick={(e) => { if (e.target === e.currentTarget) onClose(); }}>
      <div
        ref={containerRef}
        tabIndex={-1}
        role="dialog"
        aria-modal="true"
        aria-labelledby="modal-perfil-title"
        style={{ background: brand.blockBg, border: `1px solid ${t.cardBorder}`, borderRadius: "20px", padding: "28px", width: "100%", maxWidth: "520px", maxHeight: "92vh", overflowY: "auto" }}
      >

        <div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-start", marginBottom: "18px" }}>
          <div>
            <div style={{ display: "flex", alignItems: "center", gap: "12px", flexWrap: "wrap", marginBottom: "4px" }}>
              <h2 id="modal-perfil-title" style={{ margin: 0, fontSize: 17, fontWeight: 800, color: t.text, fontFamily: FONT_TITLE, letterSpacing: "0.03em" }}>
                {form.nome_artistico?.trim() || influencer.name}
              </h2>
              <StatusBadge value={form.status ?? "ativo"} onChange={(v) => set("status", v)} readonly={!podeAlterarStatusCache} />
            </div>
            <div style={{ fontSize: "12px", color: t.textMuted, fontFamily: FONT.body }}>{influencer.email}</div>
          </div>
          <button type="button" onClick={onClose} aria-label="Fechar" style={{ background: "none", border: "none", cursor: "pointer", color: t.textMuted, display: "flex", alignItems: "center", padding: 4 }}>
            <X size={18} aria-hidden="true" />
          </button>
        </div>

        <div style={{ display: "flex", gap: 6, marginBottom: 20, flexWrap: "nowrap", overflowX: "auto", WebkitOverflowScrolling: "touch", paddingBottom: 2 }}>
          {tabs.map((tb) => (
            <button
              key={tb.key}
              type="button"
              aria-pressed={tab === tb.key}
              onClick={() => setTab(tb.key)}
              style={{
                padding: "7px 14px", borderRadius: 20, flexShrink: 0,
                border: `1px solid ${tab === tb.key ? brand.primary : t.cardBorder}`,
                background: tab === tb.key ? tabActiveBg : (t.inputBg ?? t.cardBg),
                color: tab === tb.key ? brand.primary : t.textMuted, fontSize: 12, fontWeight: 600, cursor: "pointer", fontFamily: FONT.body,
              }}
            >
              {tb.label}
            </button>
          ))}
        </div>

        {error && (
          <div
            role="alert"
            aria-live="polite"
            style={{
              background: `${BRAND.vermelho}18`,
              border: `1px solid ${BRAND.vermelho}44`,
              color: BRAND.vermelho,
              borderRadius: 10,
              padding: "10px 14px",
              fontSize: 13,
              marginBottom: 14,
              fontFamily: FONT.body,
              display: "flex",
              alignItems: "center",
              justifyContent: "space-between",
              gap: 8,
            }}
          >
            <span>{error}</span>
            <button type="button" onClick={() => setError("")} aria-label="Fechar erro" style={{ background: "none", border: "none", cursor: "pointer", color: BRAND.vermelho, display: "flex", flexShrink: 0 }}>
              <X size={14} aria-hidden="true" />
            </button>
          </div>
        )}

        {tab === "cadastral" && (
          <>
            <div style={row}>
              <label style={labelStyle}>Nome Artístico</label>
              <input value={form.nome_artistico ?? ""} onChange={(e) => set("nome_artistico", e.target.value)} style={inputStyle} placeholder="Ex: NeryXLS" />
            </div>
            <div style={row}>
              <label style={labelStyle}>Nome Completo</label>
              <input value={editNomeCompleto} onChange={(e) => setEditNomeCompleto(e.target.value)} style={inputStyle} placeholder="Nome completo (nome real)" />
            </div>
            <div style={row}>
              <label style={labelStyle}>E-mail</label>
              <input value={influencer.email} disabled style={{ ...inputStyle, opacity: 0.6 }} />
            </div>
            <div style={row}>
              <label style={labelStyle}>Telefone</label>
              <input value={form.telefone ?? ""} onChange={(e) => set("telefone", e.target.value)} style={inputStyle} placeholder="(11) 99999-9999" />
            </div>
            <div style={row}>
              <label style={labelStyle}>CPF <span style={{ fontSize: 9, color: BRAND.vermelho, fontWeight: 400 }}>(dado sensível)</span></label>
              <input value={form.cpf ?? ""} onChange={(e) => set("cpf", e.target.value)} style={{ ...inputStyle, fontFamily: "monospace", letterSpacing: "0.1em" }} placeholder="000.000.000-00" />
            </div>
          </>
        )}

        {tab === "canais" && (
          <>
            <div style={row}>
              <label style={labelStyle}>Plataformas Ativas</label>
              <div style={{ display: "flex", gap: "8px", flexWrap: "wrap" }}>
                {PLATAFORMAS.map((p) => {
                  const ativo = (form.canais ?? []).includes(p);
                  return (
                    <button key={p} type="button" onClick={() => toggleCanal(p)}
                      style={{ display: "inline-flex", alignItems: "center", gap: 7, padding: "8px 14px", borderRadius: 20, cursor: "pointer", border: `2px solid ${ativo ? PLAT_COLOR[p] : t.cardBorder}`, background: ativo ? `${PLAT_COLOR[p]}22` : (t.inputBg ?? t.cardBg), color: ativo ? PLAT_COLOR[p] : t.textMuted, fontSize: 12, fontWeight: 700, fontFamily: FONT.body, lineHeight: 1 }}>
                      <PlatLogo plataforma={p} size={13} isDark={isDark ?? false} />
                      <span style={{ display: "inline-flex", alignItems: "center" }}>{p}</span>
                    </button>
                  );
                })}
              </div>
            </div>
            {(form.canais ?? []).map((c) => {
              const linkKey = `link_${c.toLowerCase()}` as keyof Perfil;
              return (
                <div key={c} style={row}>
                  <label style={labelStyle}>
                    Link {c} <span style={{ color: BRAND.vermelho }}>*</span>
                  </label>
                  <input value={(form[linkKey] as string) ?? ""} onChange={(e) => set(linkKey, e.target.value)} style={inputStyle} placeholder={`https://${c.toLowerCase()}.com/seu-canal`} />
                </div>
              );
            })}
            {(form.canais ?? []).length === 0 && (
              <p style={{ fontSize: "13px", color: t.textMuted, fontFamily: FONT.body }}>Selecione ao menos uma plataforma acima.</p>
            )}
          </>
        )}

        {tab === "financeiro" && (
          <>
            <div style={row}>
              <label style={labelStyle}>Cachê por Hora (R$) {!podeAlterarStatusCache && <span style={{ fontSize: 10, color: t.textMuted, fontWeight: 400 }}>(somente Gestor/Admin)</span>}</label>
              <CurrencyInput value={form.cache_hora ?? 0} onChange={(v) => set("cache_hora", Math.max(0, v))} style={inputStyle} disabled={!podeAlterarStatusCache} />
            </div>
            {[
              { key: "chave_pix" as keyof Perfil, label: "Chave PIX", placeholder: "CPF, e-mail, telefone ou chave aleatória" },
              { key: "banco"     as keyof Perfil, label: "Banco",     placeholder: "Ex: Nubank, Itaú, Bradesco" },
            ].map(({ key, label, placeholder }) => (
              <div key={key as string} style={row}>
                <label style={labelStyle}>{label} <span style={{ fontSize: 9, color: BRAND.vermelho, fontWeight: 400 }}>(dado sensível)</span></label>
                <input value={(form[key] as string) ?? ""} onChange={(e) => set(key, e.target.value)} style={inputStyle} placeholder={placeholder} />
              </div>
            ))}
            <div className="app-grid-2-tight" style={{ ...row, gap: 12 }}>
              {[
                { key: "agencia" as keyof Perfil, label: "Agência", placeholder: "0000" },
                { key: "conta"   as keyof Perfil, label: "Conta",   placeholder: "00000-0" },
              ].map(({ key, label, placeholder }) => (
                <div key={key as string}>
                  <label style={labelStyle}>{label} <span style={{ fontSize: 9, color: BRAND.vermelho, fontWeight: 400 }}>(sensível)</span></label>
                  <input value={(form[key] as string) ?? ""} onChange={(e) => set(key, e.target.value)} style={inputStyle} placeholder={placeholder} />
                </div>
              ))}
            </div>
          </>
        )}

        {tab === "operadoras" && (
          <>
            {operadorasList.length === 0 ? (
              <p style={{ fontSize: "13px", color: t.textMuted, fontFamily: FONT.body }}>Nenhuma operadora cadastrada. Acesse Gestão de Operadoras primeiro.</p>
            ) : (
              operadorasList.map((op) => {
                const st = operadorasForm[op.slug] ?? { ativo: false, id_operadora: "" };
                const ativo = st.ativo;
                const opColor = op.brand_action?.trim() || "var(--brand-action, #7c3aed)";
                return (
                  <div key={op.slug} style={{ ...row, padding: 14, borderRadius: 12, border: `1px solid ${ativo ? `color-mix(in srgb, ${opColor} 40%, transparent)` : t.cardBorder}`, background: ativo ? `color-mix(in srgb, ${opColor} 12%, transparent)` : "transparent" }}>
                    <div style={{ display: "flex", alignItems: "center", justifyContent: "space-between", marginBottom: ativo ? 12 : 0 }}>
                      <span style={{ display: "flex", alignItems: "center", gap: 6, fontSize: 13, fontWeight: 700, color: t.text, fontFamily: FONT.body }}>
                        <Building2 size={13} aria-hidden="true" style={{ color: opColor }} /> {op.nome}
                      </span>
                      <button type="button" onClick={() => setOp(op.slug, { ativo: !ativo })}
                        style={{ padding: "5px 14px", borderRadius: 20, border: `1px solid ${ativo ? `color-mix(in srgb, ${opColor} 45%, transparent)` : t.cardBorder}`, background: ativo ? `color-mix(in srgb, ${opColor} 22%, transparent)` : (t.inputBg ?? t.cardBg), color: ativo ? opColor : t.textMuted, fontSize: 11, fontWeight: 700, cursor: "pointer", fontFamily: FONT.body }}>
                        {ativo ? "Ativo" : "Inativo"}
                      </button>
                    </div>
                    {ativo && (
                      <div>
                        <label style={{ display: "block", fontSize: 11, fontWeight: 700, letterSpacing: "1.1px", textTransform: "uppercase", color: t.textMuted, marginBottom: 5, fontFamily: FONT.body }}>
                          ID {op.nome} <span style={{ color: BRAND.vermelho }}>*</span>
                        </label>
                        <input
                          value={st.id_operadora}
                          onChange={(e) => setOp(op.slug, { id_operadora: e.target.value })}
                          style={{ width: "100%", boxSizing: "border-box", padding: "10px 14px", borderRadius: 10, border: `1px solid ${t.cardBorder}`, background: t.inputBg ?? t.cardBg, color: t.text, fontSize: 13, fontFamily: FONT.body, outline: "none" }}
                          placeholder={`ID do influencer na ${op.nome}`}
                        />
                      </div>
                    )}
                  </div>
                );
              })
            )}
          </>
        )}

        <button
          type="button"
          onClick={() => void handleSave()}
          disabled={saving}
          style={{
            width: "100%", marginTop: 8, padding: 13, borderRadius: 10, border: "none",
            cursor: saving ? "not-allowed" : "pointer", opacity: saving ? 0.7 : 1,
            background: ctaSalvar, color: "#fff", fontSize: 13, fontWeight: 700, fontFamily: FONT.body,
            display: "flex", alignItems: "center", justifyContent: "center", gap: 8,
          }}
        >
          {saving ? (
            <>
              <Loader2 size={14} className="app-lucide-spin" aria-hidden="true" />
              Salvando…
            </>
          ) : (
            "Salvar Perfil"
          )}
        </button>
      </div>
    </div>
  );
}

import { useState, useEffect, useMemo, useRef } from "react";
import { useApp } from "../../../context/AppContext";
import { useDashboardFiltros } from "../../../hooks/useDashboardFiltros";
import { useDashboardBrand } from "../../../hooks/useDashboardBrand";
import { usePermission } from "../../../hooks/usePermission";
import { FONT } from "../../../constants/theme";
import { BRAND, FONT_TITLE } from "../../../lib/dashboardConstants";
import { supabase } from "../../../lib/supabase";
import { Live, LiveResultado, LiveStatus } from "../../../types";
// Dívida técnica (B6): migrar para InfluencerDropdown na refatoração de filtros.
import InfluencerMultiSelect from "../../../components/InfluencerMultiSelect";
import { PlatLogo } from "../../../components/PlatLogo";
import { DashboardPageHeader, SelectComIcone } from "../../../components/dashboard";
import {
  AlertTriangle,
  Shield,
  Check,
  CheckCircle,
  ClipboardList,
  Info,
  Loader2,
  Trash2,
  X,
} from "lucide-react";

import { PLAT_COLOR } from "../../../constants/platforms";

// ─── STATUS ───────────────────────────────────────────────────────────────────
const STATUS_OPTS: { value: LiveStatus; label: string; color: string }[] = [
  { value: "realizada",     label: "Realizada",     color: BRAND.verde    },
  { value: "nao_realizada", label: "Não Realizada", color: BRAND.vermelho },
];

// ─── HELPERS ──────────────────────────────────────────────────────────────────
/** Data local YYYY-MM-DD (alinhado a data + horário agendados da live). */
function todayISOLocal(): string {
  const d = new Date();
  const y = d.getFullYear();
  const m = String(d.getMonth() + 1).padStart(2, "0");
  const day = String(d.getDate()).padStart(2, "0");
  return `${y}-${m}-${day}`;
}

function parseLiveLocal(data: string, horario: string): Date {
  const [y, mo, d] = data.split("-").map((x) => parseInt(x, 10));
  const parts = (horario || "00:00").split(":");
  const hh = parseInt(parts[0] ?? "0", 10) || 0;
  const mm = parseInt(parts[1] ?? "0", 10) || 0;
  const ss = parseInt(parts[2] ?? "0", 10) || 0;
  return new Date(y, mo - 1, d, hh, mm, ss);
}

/** Só entram lives cujo horário agendado já passou há mais de 5h (fuso local). */
const RESULTADOS_JANELA_MS = 5 * 60 * 60 * 1000;

function fmtData(iso: string): string {
  if (!iso) return "";
  const [y, m, d] = iso.split("-");
  return `${d}/${m}/${y.slice(2)}`;
}

type ThemeTokens = ReturnType<typeof useApp>["theme"];
type DashboardBrand = ReturnType<typeof useDashboardBrand>;
type PermResultados = ReturnType<typeof usePermission>;
type EscoposVisiveis = ReturnType<typeof useDashboardFiltros>["escoposVisiveis"];

const ctaGradient = (_brand: DashboardBrand) =>
  "linear-gradient(135deg, var(--brand-action, #4a2082), var(--brand-contrast, #1e36f8))";

interface LiveCardProps {
  live: Live;
  brand: DashboardBrand;
  t: ThemeTokens;
  isDark: boolean | undefined;
  perm: PermResultados;
  podeVerInfluencer: (id: string) => boolean;
  showInfluencerName: boolean;
  nomeCompletos: Record<string, string>;
  excluindo: Live | null;
  setExcluindo: (v: Live | null) => void;
  onValidar: (live: Live) => void;
  onLiveDeleted: (live: Live) => void;
}

function LiveCard({
  live,
  brand,
  t,
  isDark,
  perm,
  podeVerInfluencer,
  showInfluencerName,
  nomeCompletos,
  excluindo,
  setExcluindo,
  onValidar,
  onLiveDeleted,
}: LiveCardProps) {
  const [confirmExcluir, setConfirmExcluir] = useState(false);
  const nomeCompleto = nomeCompletos[live.influencer_id] ?? "";
  const platColor = PLAT_COLOR[live.plataforma];
  const podeExcluir = perm.canExcluirOk && (perm.canExcluir !== "proprios" || podeVerInfluencer(live.influencer_id));
  const isExcluindo = excluindo?.id === live.id;

  async function handleExcluirConfirmado() {
    if (!perm.canExcluirOk) return;
    setExcluindo(live);
    await supabase.from("live_resultados").delete().eq("live_id", live.id);
    const { error } = await supabase.from("lives").delete().eq("id", live.id);
    setExcluindo(null);
    setConfirmExcluir(false);
    if (!error) onLiveDeleted(live);
  }

  return (
    <div style={{
      background: brand.blockBg,
      border: `1px solid ${t.cardBorder}`,
      borderRadius: 18,
      padding: 20,
      marginBottom: 12,
      boxShadow: "0 4px 20px rgba(0,0,0,0.18)",
    }}>
      <div style={{ display: "flex", alignItems: "flex-start", justifyContent: "space-between", flexWrap: "wrap", gap: 10 }}>
        <div style={{ display: "flex", alignItems: "center", gap: 12, minWidth: 0, flex: 1 }}>
          <div style={{
            width: 42, height: 42, borderRadius: 10, flexShrink: 0,
            background: `${platColor}22`,
            border: `1.5px solid ${platColor}44`,
            display: "flex", alignItems: "center", justifyContent: "center",
          }}>
            <PlatLogo plataforma={live.plataforma} size={20} isDark={isDark ?? false} />
          </div>

          <div style={{ minWidth: 0 }}>
            <div style={{ fontSize: 14, fontWeight: 700, color: t.text, fontFamily: FONT.body }}>
              {live.influencer_name}
            </div>
            <div style={{ fontSize: 12, color: t.textMuted, fontFamily: FONT.body, marginTop: 2, overflow: "hidden", textOverflow: "ellipsis", whiteSpace: "nowrap" }}>
              {showInfluencerName && nomeCompleto && <span>{nomeCompleto} · </span>}
              {fmtData(live.data)} · {live.horario?.slice(0, 5)}
            </div>
            <div style={{ display: "flex", gap: 6, marginTop: 6, flexWrap: "wrap" }}>
              <span style={{
                display: "inline-flex", alignItems: "center", gap: 5,
                fontSize: 11, padding: "3px 9px", borderRadius: 20,
                background: `${platColor}22`, color: platColor,
                fontWeight: 600, fontFamily: FONT.body,
              }}>
                <PlatLogo plataforma={live.plataforma} size={11} isDark={isDark ?? false} />
                {live.plataforma}
              </span>
              <span style={{
                display: "inline-flex", alignItems: "center", gap: 5,
                fontSize: 11, padding: "3px 9px", borderRadius: 20,
                background: `${BRAND.amarelo}22`, color: BRAND.amarelo,
                fontWeight: 600, fontFamily: FONT.body,
                border: `1px solid ${BRAND.amarelo}44`,
              }}>
                <AlertTriangle size={10} aria-hidden="true" />
                Pendente validação
              </span>
            </div>
          </div>
        </div>

        <div style={{ display: "flex", gap: 8, flexShrink: 0, flexWrap: "wrap", alignItems: "center" }}>
          {perm.canEditarOk && (perm.canEditar !== "proprios" || podeVerInfluencer(live.influencer_id)) && (
            <button
              type="button"
              onClick={() => onValidar(live)}
              style={{
                display: "inline-flex", alignItems: "center", gap: 6,
                padding: "8px 16px", borderRadius: 10, border: "none",
                cursor: "pointer",
                background: ctaGradient(brand),
                color: "#fff", fontSize: 12, fontWeight: 700, fontFamily: FONT.body,
              }}
            >
              <Check size={13} aria-hidden="true" />
              Validar
            </button>
          )}
          {podeExcluir && (
            <button
              type="button"
              onClick={() => {
                if (!confirmExcluir) { setConfirmExcluir(true); return; }
                void handleExcluirConfirmado();
              }}
              onBlur={() => setConfirmExcluir(false)}
              disabled={isExcluindo}
              style={{
                display: "inline-flex", alignItems: "center", gap: 5,
                padding: "8px 16px", borderRadius: 10,
                border: `1px solid ${BRAND.vermelho}50`,
                background: confirmExcluir ? BRAND.vermelho : `${BRAND.vermelho}10`,
                color: confirmExcluir ? "#fff" : BRAND.vermelho,
                fontSize: 12, fontWeight: 600,
                cursor: isExcluindo ? "not-allowed" : "pointer",
                fontFamily: FONT.body, opacity: isExcluindo ? 0.6 : 1,
                transition: "all 0.15s",
              }}
            >
              <Trash2 size={12} aria-hidden="true" />
              {isExcluindo ? "..." : confirmExcluir ? "Confirmar?" : "Excluir"}
            </button>
          )}
        </div>
      </div>
    </div>
  );
}

interface ModalValidacaoProps {
  live: Live;
  brand: DashboardBrand;
  t: ThemeTokens;
  resultados: Record<string, LiveResultado>;
  operadorasList: { slug: string; nome: string }[];
  escoposVisiveis: EscoposVisiveis;
  onClose: () => void;
  onSaved: () => Promise<void>;
}

function ModalValidacao({
  live,
  brand,
  t,
  resultados,
  operadorasList,
  escoposVisiveis,
  onClose,
  onSaved,
}: ModalValidacaoProps) {
  const existing = resultados[live.id];
  const [status, setStatus] = useState<LiveStatus>("realizada");
  const [operadoraSlug, setOperadoraSlug] = useState(live.operadora_slug ?? "");
  const [observacao, setObservacao] = useState(live.observacao ?? "");
  const [horarioReal, setHorarioReal] = useState(live.horario?.slice(0, 5) ?? "");
  const [duracaoHoras, setDuracaoHoras] = useState(existing?.duracao_horas ?? 0);
  const [duracaoMin, setDuracaoMin] = useState(existing?.duracao_min ?? 0);
  const [mediaViews, setMediaViews] = useState(existing?.media_views ?? 0);
  const [maxViews, setMaxViews] = useState(existing?.max_views ?? 0);
  const [saving, setSaving] = useState(false);
  const [error, setError] = useState("");
  const containerRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const id = window.requestAnimationFrame(() => {
      containerRef.current?.focus();
    });
    return () => window.cancelAnimationFrame(id);
  }, [live.id]);

  const showResultFields = status === "realizada";

  async function handleSave() {
    setError("");
    if (!operadoraSlug?.trim())
      return setError("Selecione a operadora. É obrigatório para salvar a validação (realizada ou não realizada).");
    if (showResultFields) {
      if (duracaoHoras === 0 && duracaoMin === 0)
        return setError("Informe a duração da live.");
      if (maxViews < mediaViews)
        return setError("Máximo não pode ser menor que a média.");
    }

    setSaving(true);
    const liveUpdate: Record<string, unknown> = {
      status,
      observacao: observacao || null,
      operadora_slug: operadoraSlug.trim(),
    };
    if (showResultFields && horarioReal) (liveUpdate as Record<string, string>).horario = horarioReal;

    const { error: updateError } = await supabase.from("lives").update(liveUpdate).eq("id", live.id);
    if (updateError) { setError("Erro ao salvar. Tente novamente."); setSaving(false); return; }

    if (showResultFields) {
      const payload = { live_id: live.id, duracao_horas: duracaoHoras, duracao_min: duracaoMin, media_views: mediaViews, max_views: maxViews };
      const { error: resultError } = existing
        ? await supabase.from("live_resultados").update(payload).eq("live_id", live.id)
        : await supabase.from("live_resultados").insert(payload);
      if (resultError) { setError("Erro ao salvar resultado. Tente novamente."); setSaving(false); return; }
    }

    setSaving(false);
    onClose();
    await onSaved();
  }

  const inputStyle: React.CSSProperties = {
    width: "100%", boxSizing: "border-box", padding: "10px 14px",
    borderRadius: 10, border: `1px solid ${t.inputBorder ?? t.cardBorder}`,
    background: t.inputBg ?? t.cardBg, color: t.inputText ?? t.text,
    fontSize: 13, fontFamily: FONT.body, outline: "none",
  };
  const labelStyle: React.CSSProperties = {
    display: "block", fontSize: 10, fontWeight: 700, letterSpacing: "1.2px",
    textTransform: "uppercase", color: t.textMuted, marginBottom: 5, fontFamily: FONT.body,
  };
  const row: React.CSSProperties = { marginBottom: 14 };

  return (
    <div style={{ position: "fixed", inset: 0, background: "#00000088", display: "flex", alignItems: "center", justifyContent: "center", zIndex: 1000, padding: 20 }}>
      <div
        ref={containerRef}
        tabIndex={-1}
        role="dialog"
        aria-modal="true"
        aria-labelledby="modal-validacao-title"
        style={{
          background: t.cardBg,
          border: `1px solid ${t.cardBorder}`,
          borderRadius: 20,
          padding: "clamp(16px, 4vw, 28px)",
          width: "100%",
          maxWidth: 480,
          maxHeight: "90vh",
          overflowY: "auto",
          outline: "none",
        }}
      >

        <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 6 }}>
          <div style={{ display: "flex", alignItems: "center", gap: 8 }}>
            <span style={{
              width: 28, height: 28, borderRadius: 8,
              background: brand.primaryIconBg,
              border: brand.primaryIconBorder,
              display: "flex", alignItems: "center", justifyContent: "center",
              color: brand.primaryIconColor,
            }}>
              <CheckCircle size={13} aria-hidden="true" />
            </span>
            <h2 id="modal-validacao-title" style={{ margin: 0, fontSize: 15, fontWeight: 800, color: brand.primary, fontFamily: FONT_TITLE, letterSpacing: "0.05em", textTransform: "uppercase" }}>
              Validar Live
            </h2>
          </div>
          <button type="button" onClick={onClose} aria-label="Fechar" style={{ background: "none", border: "none", cursor: "pointer", color: t.textMuted, display: "flex", alignItems: "center", padding: 4 }}>
            <X size={18} aria-hidden="true" />
          </button>
        </div>

        <div style={{ fontSize: 13, color: t.textMuted, fontFamily: FONT.body, marginBottom: 20 }}>
          {live.influencer_name} · {fmtData(live.data)} {live.horario?.slice(0, 5)}
        </div>

        {error && (
          <div
            role="alert"
            aria-live="polite"
            style={{
              background: `${BRAND.vermelho}18`,
              border: `1px solid ${BRAND.vermelho}44`,
              color: BRAND.vermelho,
              borderRadius: 10,
              padding: "10px 14px",
              fontSize: 13,
              marginBottom: 14,
              fontFamily: FONT.body,
              display: "flex",
              alignItems: "center",
              justifyContent: "space-between",
              gap: 8,
            }}
          >
            <span>{error}</span>
            <button
              type="button"
              onClick={() => setError("")}
              aria-label="Fechar erro"
              style={{ background: "none", border: "none", cursor: "pointer", color: BRAND.vermelho, display: "flex", flexShrink: 0 }}
            >
              <X size={14} aria-hidden="true" />
            </button>
          </div>
        )}

        <div style={row}>
          <label style={labelStyle}>Status da Live</label>
          <div style={{ display: "flex", gap: 10 }}>
            {STATUS_OPTS.map(opt => (
              <button
                key={opt.value}
                type="button"
                aria-pressed={status === opt.value}
                onClick={() => setStatus(opt.value)}
                style={{
                  flex: 1, padding: 10, borderRadius: 10,
                  border: `2px solid ${status === opt.value ? opt.color : t.cardBorder}`,
                  background: status === opt.value ? `${opt.color}18` : (t.inputBg ?? t.cardBg),
                  color: status === opt.value ? opt.color : t.textMuted,
                  fontSize: 12, fontWeight: 700, cursor: "pointer",
                  fontFamily: FONT.body, transition: "all 0.15s",
                }}
              >
                {opt.label}
              </button>
            ))}
          </div>
        </div>

        {status === "nao_realizada" && (
          <div style={{
            background: `${BRAND.amarelo}12`,
            border: `1px solid ${BRAND.amarelo}35`,
            color: BRAND.amarelo,
            borderRadius: 10,
            padding: "10px 14px",
            fontSize: 12,
            marginBottom: 14,
            fontFamily: FONT.body,
          }}>
            Live marcada como Não Realizada — nenhum resultado será registrado.
          </div>
        )}

        {operadorasList.length > 0 && (
          <div style={row}>
            <label style={labelStyle}>Operadora <span style={{ color: BRAND.vermelho }}>*</span></label>
            <select
              value={operadoraSlug}
              onChange={e => setOperadoraSlug(e.target.value)}
              style={{ ...inputStyle, cursor: "pointer" }}
            >
              <option value="">Selecione a operadora...</option>
              {operadorasList
                .filter((o) => escoposVisiveis.operadorasVisiveis.length === 0 || escoposVisiveis.operadorasVisiveis.includes(o.slug))
                .sort((a, b) => a.nome.localeCompare(b.nome, "pt-BR"))
                .map(o => <option key={o.slug} value={o.slug}>{o.nome}</option>)}
            </select>
            <span style={{ fontSize: 11, color: t.textMuted, fontFamily: FONT.body, marginTop: 4, display: "block" }}>
              Obrigatório para salvar. Em lives realizadas, o Financeiro usa a operadora no cálculo de pagamentos.
            </span>
          </div>
        )}

        <div style={row}>
          <label style={labelStyle}>Observação</label>
          <textarea value={observacao} onChange={e => setObservacao(e.target.value)}
            rows={3} placeholder="Comentários sobre a live..."
            style={{ ...inputStyle, resize: "vertical", lineHeight: 1.5 }} />
        </div>

        {showResultFields && (
          <>
            <div style={row}>
              <label style={labelStyle}>Horário Real de Início</label>
              <input type="time" value={horarioReal} onChange={e => setHorarioReal(e.target.value)} style={inputStyle} />
              <span style={{ fontSize: 11, color: t.textMuted, fontFamily: FONT.body, marginTop: 4, display: "block" }}>
                Pré-preenchido com o horário agendado. Altere se a live começou em outro horário.
              </span>
            </div>

            <div style={row}>
              <label style={labelStyle}>Duração</label>
              <div className="app-grid-2-tight" style={{ gap: 10 }}>
                <div>
                  <input
                    aria-label="Duração em horas"
                    type="number"
                    min={0}
                    max={24}
                    value={duracaoHoras}
                    onChange={e => setDuracaoHoras(Math.max(0, Math.min(24, Number(e.target.value) || 0)))}
                    style={inputStyle}
                    placeholder="0"
                  />
                  <span style={{ fontSize: 11, color: t.textMuted, fontFamily: FONT.body }}>horas</span>
                </div>
                <div>
                  <input
                    aria-label="Duração em minutos"
                    type="number"
                    min={0}
                    max={59}
                    value={duracaoMin}
                    onChange={e => setDuracaoMin(Math.max(0, Math.min(59, Number(e.target.value) || 0)))}
                    style={inputStyle}
                    placeholder="0"
                  />
                  <span style={{ fontSize: 11, color: t.textMuted, fontFamily: FONT.body }}>min</span>
                </div>
              </div>
            </div>

            <div style={row}>
              <label style={labelStyle}>Média de Views</label>
              <input type="number" min={0} value={mediaViews} onChange={e => setMediaViews(Number(e.target.value) || 0)} style={inputStyle} placeholder="0" />
            </div>

            <div style={row}>
              <label style={labelStyle}>Máximo de Views</label>
              <input type="number" min={0} value={maxViews} onChange={e => setMaxViews(Math.max(0, Number(e.target.value) || 0))} style={inputStyle} placeholder="0" />
            </div>

            <div style={{
              display: "flex", alignItems: "flex-start", gap: 8,
              padding: "10px 12px", borderRadius: 10, marginBottom: 16,
              background: `${BRAND.azul}0d`,
              border: `1px solid ${BRAND.azul}30`,
            }}>
              <Info size={13} color={BRAND.azul} aria-hidden="true" style={{ flexShrink: 0, marginTop: 1 }} />
              <span style={{ fontSize: 11, color: t.textMuted, fontFamily: FONT.body, lineHeight: 1.5 }}>
                Salvar irá marcar a live como <strong style={{ color: BRAND.verde }}>Realizada</strong> automaticamente.
              </span>
            </div>
          </>
        )}

        <button
          type="button"
          onClick={() => void handleSave()}
          disabled={saving}
          style={{
            width: "100%", padding: 13, borderRadius: 10, border: "none",
            cursor: saving ? "not-allowed" : "pointer",
            opacity: saving ? 0.7 : 1,
            background: ctaGradient(brand),
            color: "#fff", fontSize: 13, fontWeight: 700, fontFamily: FONT.body,
            display: "flex", alignItems: "center", justifyContent: "center", gap: 6,
          }}
        >
          {saving ? (
            <>
              <Loader2 size={14} className="app-lucide-spin" aria-hidden="true" />
              Salvando...
            </>
          ) : (
            <>
              <Check size={14} aria-hidden="true" />
              Salvar Validação
            </>
          )}
        </button>
      </div>
    </div>
  );
}

// ─── COMPONENTE PRINCIPAL ─────────────────────────────────────────────────────
export default function Resultados() {
  const { theme: t, isDark } = useApp();
  const brand = useDashboardBrand();
  const { showFiltroInfluencer, showFiltroOperadora, podeVerInfluencer, podeVerOperadora, escoposVisiveis, operadoraSlugsForcado } = useDashboardFiltros();
  const perm = usePermission("resultados");

  const [lives,          setLives]          = useState<Live[]>([]);
  const [resultados,     setResultados]     = useState<Record<string, LiveResultado>>({});
  const [nomeCompletos,  setNomeCompletos]  = useState<Record<string, string>>({});
  const [loading,        setLoading]        = useState(true);
  const [modal,          setModal]          = useState<Live | null>(null);
  const [filterInfluencers, setFilterInfluencers] = useState<string[]>([]);
  const [filterOperadora,   setFilterOperadora]   = useState<string>("todas");
  const [influencerList,    setInfluencerList]    = useState<{ id: string; name: string }[]>([]);
  const [operadorasList,    setOperadorasList]    = useState<{ slug: string; nome: string }[]>([]);
  const [excluindo,         setExcluindo]         = useState<Live | null>(null);

  const influencerListVisiveis = useMemo(
    () => influencerList.filter((i) => podeVerInfluencer(i.id)),
    [influencerList, podeVerInfluencer]
  );
  const showInfluencerName = influencerListVisiveis.length > 1;

  async function loadData() {
    setLoading(true);
    const hojeLocal = todayISOLocal();
    const agora = Date.now();
    let q = supabase
      .from("lives")
      .select("*, profiles!lives_influencer_id_fkey(name)")
      .lte("data", hojeLocal)
      .eq("status", "agendada")
      .order("data", { ascending: false })
      .order("horario", { ascending: true });
    if (operadoraSlugsForcado?.length) q = q.in("operadora_slug", operadoraSlugsForcado);
    const { data: livesData } = await q;

    if (livesData) {
      const mapped = livesData.map((l: { profiles?: { name: string }; [k: string]: unknown }) => ({ ...l, influencer_name: l.profiles?.name })) as Live[];
      const visiveis = mapped
        .filter((l) => podeVerInfluencer(l.influencer_id))
        .filter((l) => agora - parseLiveLocal(l.data, l.horario).getTime() > RESULTADOS_JANELA_MS);
      setLives(visiveis);

      const ids = visiveis.map((l) => l.id);
      if (ids.length > 0) {
        const { data: resData } = await supabase.from("live_resultados").select("*").in("live_id", ids);
        if (resData) {
          const map: Record<string, LiveResultado> = {};
          resData.forEach((r: LiveResultado) => { map[r.live_id] = r; });
          setResultados(map);
        }
      }

      const influencerIds = [...new Set(visiveis.map((l) => l.influencer_id).filter(Boolean))];
      if (influencerIds.length > 1) {
        const { data: perfisData } = await supabase
          .from("influencer_perfil").select("id, nome_completo").in("id", influencerIds);
        if (perfisData) {
          const nomesMap: Record<string, string> = {};
          perfisData.forEach((p: Record<string, string>) => { nomesMap[p.id] = p.nome_completo ?? ""; });
          setNomeCompletos(nomesMap);
        }
      }
    }
    setLoading(false);
  }

  useEffect(() => { loadData(); }, [podeVerInfluencer, operadoraSlugsForcado]);

  useEffect(() => {
    supabase.from("profiles").select("id, name").eq("role", "influencer")
      .then(({ data }) => { if (data) setInfluencerList(data); });
  }, []);

  useEffect(() => {
    supabase.from("operadoras").select("slug, nome").order("nome")
      .then(({ data }) => { if (data) setOperadorasList(data); });
  }, []);

  const livesFiltered = useMemo(() => {
    let out = lives;
    if (filterInfluencers.length > 0)
      out = out.filter((l) => filterInfluencers.includes(l.influencer_id));
    if (operadoraSlugsForcado?.length)
      out = out.filter((l) => l.operadora_slug && operadoraSlugsForcado.includes(l.operadora_slug));
    else if (filterOperadora && filterOperadora !== "todas")
      out = out.filter((l) => l.operadora_slug === filterOperadora);
    return out;
  }, [lives, filterInfluencers, filterOperadora, operadoraSlugsForcado]);

  function handleLiveDeleted(deleted: Live) {
    if (modal?.id === deleted.id) setModal(null);
    void loadData();
  }

  // ── Render ────────────────────────────────────────────────────────────────────
  if (perm.canView === "nao") {
    return (
      <div style={{ padding: 24, textAlign: "center", color: t.textMuted, fontFamily: FONT.body }}>
        Você não tem permissão para visualizar este dashboard.
      </div>
    );
  }

  return (
    <div className="app-page-shell" style={{ background: t.bg, minHeight: "100vh", fontFamily: FONT.body }}>

      <DashboardPageHeader
        icon={<ClipboardList size={14} aria-hidden="true" />}
        title="Resultado de Lives"
        subtitle="Lives agendadas cujo horário já passou há mais de 5 horas, pendentes de validação."
        brand={brand}
        t={t}
      />

      {/* ── FILTROS (padrão Dashboards) ── */}
      {(showFiltroInfluencer || showFiltroOperadora) && (
        <div style={{ marginBottom: 14 }}>
          <div style={{
            borderRadius: 14,
            border: `1px solid ${t.cardBorder}`,
            background: brand.blockBg,
            padding: "12px 20px",
          }}>
            <div style={{ display: "flex", alignItems: "center", justifyContent: "center", gap: 18, flexWrap: "wrap" }}>
              {showFiltroInfluencer && influencerListVisiveis.length > 0 && (
                <InfluencerMultiSelect
                  selected={filterInfluencers}
                  onChange={setFilterInfluencers}
                  influencers={influencerListVisiveis}
                  t={t}
                />
              )}
              {showFiltroOperadora && operadorasList.length > 0 && (
                <SelectComIcone
                  pill
                  icon={<Shield size={13} aria-hidden="true" />}
                  label="Filtrar por operadora"
                  value={filterOperadora}
                  onChange={setFilterOperadora}
                  minWidth={200}
                  style={{
                    border: `1px solid ${filterOperadora !== "todas" ? brand.accent : t.cardBorder}`,
                    background:
                      filterOperadora !== "todas"
                        ? "var(--brand-action-12)"
                        : (t.inputBg ?? t.cardBg),
                    color: filterOperadora !== "todas" ? brand.accent : t.textMuted,
                    fontWeight: filterOperadora !== "todas" ? 700 : 400,
                  }}
                >
                  <option value="todas">Todas as operadoras</option>
                  {operadorasList
                    .filter((o) => podeVerOperadora(o.slug))
                    .sort((a, b) => a.nome.localeCompare(b.nome, "pt-BR"))
                    .map((o) => <option key={o.slug} value={o.slug}>{o.nome}</option>)}
                </SelectComIcone>
              )}
            </div>
          </div>
        </div>
      )}

      {/* ── CONTEÚDO ── */}
      {loading ? (
        <div style={{ textAlign: "center", padding: 60, color: t.textMuted, fontFamily: FONT.body, display: "flex", alignItems: "center", justifyContent: "center", gap: 8 }}>
          <Loader2 size={16} className="app-lucide-spin" aria-hidden="true" />
          Carregando...
        </div>
      ) : livesFiltered.length === 0 ? (
        <div style={{
          background: brand.blockBg, border: `1px solid ${t.cardBorder}`,
          borderRadius: 16, padding: 48,
          textAlign: "center", color: t.textMuted, fontFamily: FONT.body,
        }}>
          <CheckCircle size={24} style={{ marginBottom: 8, color: BRAND.verde }} aria-hidden="true" />
          <div style={{ fontSize: 14, fontWeight: 600 }}>Nenhuma live pendente de validação.</div>
        </div>
      ) : (
        <>
          {/* Contador com BRAND.amarelo */}
          <div style={{
            display: "flex", alignItems: "center", gap: 6,
            fontSize: 13, color: BRAND.amarelo,
            fontFamily: FONT.body, marginBottom: 16, fontWeight: 600,
          }}>
            <AlertTriangle size={15} aria-hidden="true" />
            {livesFiltered.length} live{livesFiltered.length !== 1 ? "s" : ""} aguardando validação
          </div>
          {livesFiltered.map(l => (
            <LiveCard
              key={l.id}
              live={l}
              brand={brand}
              t={t}
              isDark={isDark}
              perm={perm}
              podeVerInfluencer={podeVerInfluencer}
              showInfluencerName={showInfluencerName}
              nomeCompletos={nomeCompletos}
              excluindo={excluindo}
              setExcluindo={setExcluindo}
              onValidar={setModal}
              onLiveDeleted={handleLiveDeleted}
            />
          ))}
        </>
      )}

      {modal && (
        <ModalValidacao
          key={modal.id}
          live={modal}
          brand={brand}
          t={t}
          resultados={resultados}
          operadorasList={operadorasList}
          escoposVisiveis={escoposVisiveis}
          onClose={() => setModal(null)}
          onSaved={loadData}
        />
      )}
    </div>
  );
}

import { useState, useEffect, useCallback } from "react";
import { useApp } from "../../../context/AppContext";
import { useDashboardBrand } from "../../../hooks/useDashboardBrand";
import { useDashboardFiltros } from "../../../hooks/useDashboardFiltros";
import { usePermission } from "../../../hooks/usePermission";
import { useMediaQuery } from "../../../hooks/useMediaQuery";
import { FONT } from "../../../constants/theme";
import { supabase } from "../../../lib/supabase";
import { UtmAlias } from "../../../types";
import { Link2, EyeOff, RotateCcw, AlertCircle, Shield } from "lucide-react";
import { GiLinkedRings } from "react-icons/gi";
import { PageHeader } from "../../../components/PageHeader";
import { ModalBase, ModalHeader, ModalConfirmDelete } from "../../../components/OperacoesModal";

// ─── BRAND ────────────────────────────────────────────────────────────────────
const BRAND = {
  roxo:     "#4a2082",
  roxoVivo: "#7c3aed",
  azul:     "#1e36f8",
  vermelho: "#e84025",
  ciano:    "#70cae4",
  verde:    "#22c55e",
  amarelo:  "#f59e0b",
} as const;

function calcGgr(alias: { total_deposit?: number; total_withdrawal?: number; ggr?: number }): number {
  if (alias.ggr != null) return alias.ggr;
  return (alias.total_deposit ?? 0) - (alias.total_withdrawal ?? 0);
}

function fmt(value: number): string {
  return value.toLocaleString("pt-BR", { style: "currency", currency: "BRL" });
}

function fmtData(iso: string): string {
  if (!iso) return "—";
  const [y, m, d] = iso.split("-");
  return `${d}/${m}/${y}`;
}

interface InfluencerOpcao { id: string; nome_artistico: string; status: string; }
interface CampanhaOpcao { id: string; nome: string; ativo: boolean; }
type Aba = "pendentes" | "mapeados" | "ignorados";
type TipoMapeamento = "influencer" | "campanha";

export default function GestaoLinks() {
  const { theme, user, podeVerInfluencer, isDark } = useApp();
  const brand = useDashboardBrand();
  const narrowMobile = useMediaQuery("(max-width: 479px)");
  const hideDepGgr = narrowMobile;
  const perm = usePermission("gestao_links");
  const { showFiltroOperadora } = useDashboardFiltros();

  const podeMapearAlias   = () => perm.canEditarOk;
  const podeReativarAlias = (alias: UtmAlias) =>
    perm.canEditarOk && (
      perm.canEditar !== "proprios" ||
      (alias.campanha_id ? true : !alias.influencer_id || podeVerInfluencer(alias.influencer_id!))
    );

  const [aba, setAba] = useState<Aba>("pendentes");
  const [operadoraFiltro, setOperadoraFiltro] = useState("todas");
  const [operadorasList, setOperadorasList] = useState<{ slug: string; nome: string }[]>([]);
  const [aliases, setAliases] = useState<UtmAlias[]>([]);
  const [loading, setLoading] = useState(true);
  const [influencers, setInfluencers] = useState<InfluencerOpcao[]>([]);
  const [modalAberto, setModalAberto] = useState(false);
  const [aliasSelecionado, setAliasSelecionado] = useState<UtmAlias | null>(null);
  const [influencerSelecionado, setInfluencerSelecionado] = useState("");
  const [campanhaSelecionada, setCampanhaSelecionada] = useState("");
  const [tipoMapeamento, setTipoMapeamento] = useState<TipoMapeamento>("influencer");
  const [campanhas, setCampanhas] = useState<CampanhaOpcao[]>([]);
  const [salvando, setSalvando] = useState(false);
  const [erroModal, setErroModal] = useState<string | null>(null);
  const [confirmFechar, setConfirmFechar] = useState(false);

  const cardShadow = isDark ? "0 4px 20px rgba(0,0,0,0.25)" : "0 2px 8px rgba(0,0,0,0.07)";

  function fecharModalLimpo() {
    setModalAberto(false);
    setConfirmFechar(false);
    setAliasSelecionado(null);
    setInfluencerSelecionado("");
    setCampanhaSelecionada("");
    setErroModal(null);
  }

  function solicitarFecharModal() {
    if (salvando) return;
    const dirty = influencerSelecionado !== "" || campanhaSelecionada !== "";
    if (dirty) setConfirmFechar(true);
    else fecharModalLimpo();
  }

  const carregar = useCallback(async () => {
    setLoading(true);
    const statusFiltro: Record<Aba, string> = { pendentes: "pendente", mapeados: "mapeado", ignorados: "ignorado" };
    let query = supabase.from("utm_aliases").select("*").eq("status", statusFiltro[aba]).order("total_ftds", { ascending: false });
    if (operadoraFiltro !== "todas") query = query.eq("operadora_slug", operadoraFiltro);
    const { data, error } = await query;
    if (error) { console.error("Erro ao carregar utm_aliases:", error.message); setAliases([]); setLoading(false); return; }
    const aliasData = data ?? [];
    let infNomeMap = new Map<string, string>();
    let campanhaNomeMap = new Map<string, string>();
    if (aba === "mapeados") {
      const influencerIds = aliasData.map((r: any) => r.influencer_id).filter(Boolean);
      if (influencerIds.length > 0) {
        const { data: infData } = await supabase.from("influencer_perfil").select("id, nome_artistico").in("id", influencerIds);
        infNomeMap = new Map((infData ?? []).map((i: any) => [i.id, i.nome_artistico]));
      }
      const campanhaIds = aliasData.map((r: any) => r.campanha_id).filter(Boolean);
      if (campanhaIds.length > 0) {
        const { data: campData } = await supabase.from("campanhas").select("id, nome").in("id", campanhaIds);
        campanhaNomeMap = new Map((campData ?? []).map((c: any) => [c.id, c.nome]));
      }
    }
    setAliases(aliasData.map((r: any) => ({
      ...r,
      influencer_name: r.influencer_id ? (infNomeMap.get(r.influencer_id) ?? "—") : null,
      campanha_nome: r.campanha_id ? (campanhaNomeMap.get(r.campanha_id) ?? "—") : null,
    })));
    setLoading(false);
  }, [aba, operadoraFiltro]);

  useEffect(() => { carregar(); }, [carregar]);
  useEffect(() => { supabase.from("operadoras").select("slug, nome").order("nome").then(({ data }) => setOperadorasList(data ?? [])); }, []);
  useEffect(() => { supabase.from("influencer_perfil").select("id, nome_artistico, status").order("nome_artistico").then(({ data }) => setInfluencers(data ?? [])); }, []);
  useEffect(() => { supabase.from("campanhas").select("id, nome, ativo").eq("ativo", true).order("nome").then(({ data }) => setCampanhas(data ?? [])); }, []);

  const [totalPendentes, setTotalPendentes] = useState(0);
  useEffect(() => {
    let q = supabase.from("utm_aliases").select("id", { count: "exact", head: true }).eq("status", "pendente");
    if (operadoraFiltro !== "todas") q = q.eq("operadora_slug", operadoraFiltro);
    q.then(({ count }) => setTotalPendentes(count ?? 0));
  }, [aliases, operadoraFiltro]);

  function abrirModal(alias: UtmAlias) {
    setAliasSelecionado(alias);
    setInfluencerSelecionado("");
    setCampanhaSelecionada("");
    setTipoMapeamento("influencer");
    setErroModal(null);
    setConfirmFechar(false);
    setModalAberto(true);
  }

  async function confirmarMapeamento() {
    if (!aliasSelecionado) return;
    const isInfluencer = tipoMapeamento === "influencer";
    const idSelecionado = isInfluencer ? influencerSelecionado : campanhaSelecionada;
    if (!idSelecionado) return;
    if (isInfluencer && perm.canEditar === "proprios" && !podeVerInfluencer(idSelecionado)) return;

    setSalvando(true); setErroModal(null);

    const updatePayload = isInfluencer
      ? { influencer_id: idSelecionado, campanha_id: null, status: "mapeado", mapeado_por: user?.id ?? null, mapeado_em: new Date().toISOString(), atualizado_em: new Date().toISOString() }
      : { campanha_id: idSelecionado, influencer_id: null, status: "mapeado", mapeado_por: user?.id ?? null, mapeado_em: new Date().toISOString(), atualizado_em: new Date().toISOString() };

    const { error } = await supabase.from("utm_aliases").update(updatePayload).eq("id", aliasSelecionado.id);
    if (error) { setSalvando(false); setErroModal(`Erro ao salvar: ${error.message}`); return; }

    // RPC: copia utm_metricas_diarias → influencer_metricas (apenas para mapeamento influencer)
    let linhasCopiadas = 0;
    if (isInfluencer) {
      try {
        const { data: rpcData, error: rpcErr } = await supabase.rpc("aplicar_mapeamento_utm", {
          p_utm_source: aliasSelecionado.utm_source,
          p_influencer_id: idSelecionado,
        });
        if (!rpcErr && Array.isArray(rpcData) && rpcData.length > 0) {
          const row = rpcData[0] as { linhas_copiadas?: number };
          linhasCopiadas = Number(row?.linhas_copiadas ?? 0);
        }
      } catch (_e) { /* RPC pode não existir ainda */ }

      // Se utm_metricas_diarias estava vazio, dispara sync (fallback)
      if (linhasCopiadas === 0) {
        const dataInicio = (aliasSelecionado.primeiro_visto ?? "2025-12-01").split("T")[0];
        const dataFim = (aliasSelecionado.ultimo_visto ?? new Date().toISOString().split("T")[0]).split("T")[0];
        try {
          await supabase.functions.invoke("sync-metricas-cda", {
            body: { data_inicio: dataInicio, data_fim: dataFim, utm_source: aliasSelecionado.utm_source, skip_orfaos: true },
          });
        } catch (e) {
          console.warn("[GestaoLinks] Sync fallback:", e);
        }
      }
    }

    setSalvando(false);
    fecharModalLimpo();
    carregar();
  }

  async function ignorar(alias: UtmAlias) {
    const { error } = await supabase.from("utm_aliases").update({ status: "ignorado", atualizado_em: new Date().toISOString() }).eq("id", alias.id);
    if (!error) carregar();
  }

  async function reativar(alias: UtmAlias) {
    const { error } = await supabase.from("utm_aliases").update({
      status: "pendente",
      influencer_id: null,
      campanha_id: null,
      mapeado_por: null,
      mapeado_em: null,
      atualizado_em: new Date().toISOString(),
    }).eq("id", alias.id);
    if (!error) carregar();
  }

  // ─── Estilos ──────────────────────────────────────────────────────────────
  // th e td sem whiteSpace nowrap — cada coluna controla individualmente
  const th: React.CSSProperties = {
    textAlign: "left", padding: "10px 14px", color: theme.textMuted,
    fontWeight: 700, fontSize: 11, textTransform: "uppercase",
    letterSpacing: "0.08em", fontFamily: FONT.body,
    background: brand.useBrand ? "color-mix(in srgb, var(--brand-secondary) 12%, transparent)" : "rgba(74,32,130,0.10)", borderBottom: `1px solid ${theme.cardBorder}`,
  };
  const td: React.CSSProperties = {
    padding: "12px 14px", color: theme.text, fontFamily: FONT.body,
    fontSize: 13, verticalAlign: "middle",
    borderBottom: `1px solid ${theme.cardBorder}`,
    whiteSpace: "nowrap", // colunas numéricas e de data não quebram
  };
  const tdMuted: React.CSSProperties = { ...td, color: theme.textMuted, fontSize: 12 };
  // coluna UTM Source: permite quebra, tem maxWidth
  const tdUtm: React.CSSProperties = {
    ...td,
    whiteSpace: "normal",
    wordBreak: "break-all",
    maxWidth: 220,
  };

  const emptyMessages: Record<Aba, string> = {
    pendentes: "Nenhum link pendente. Tudo mapeado!",
    mapeados:  "Nenhum link mapeado ainda.",
    ignorados: "Nenhum link ignorado.",
  };

  if (perm.canView === "nao") {
    return <div style={{ padding: 24, textAlign: "center", color: theme.textMuted, fontFamily: FONT.body }}>Você não tem permissão para visualizar a Gestão de Links.</div>;
  }

  return (
    <div className="app-page-shell">

      <PageHeader
        icon={<GiLinkedRings size={14} aria-hidden />}
        title="Gestão de Links"
        subtitle="Links de rastreio detectados nas operadoras que não estão associados a nenhum influencer."
        actions={
          totalPendentes > 0 ? (
            <span style={{ background: BRAND.vermelho, color: "#fff", borderRadius: 10, padding: "2px 9px", fontSize: 11, fontWeight: 700, fontFamily: FONT.body }}>
              {totalPendentes} pendente{totalPendentes !== 1 ? "s" : ""}
            </span>
          ) : undefined
        }
      />

      <div style={{ marginTop: 12, marginBottom: 18, padding: "10px 14px", borderRadius: 10, background: `${BRAND.ciano}15`, border: `1px solid ${BRAND.ciano}40`, fontSize: 12, color: theme.text, fontFamily: FONT.body }}>
        Ao mapear um link, os dados históricos são sincronizados automaticamente nos dashboards. Novos dados chegam diariamente até as 4h.
      </div>

      {showFiltroOperadora && operadorasList.length > 0 && (
        <div style={{ marginBottom: 18 }}>
          <div style={{ borderRadius: 14, border: brand.primaryTransparentBorder, background: brand.primaryTransparentBg, padding: "10px 16px" }}>
            <div style={{ display: "flex", alignItems: "center", justifyContent: "center", gap: 10, flexWrap: "wrap" }}>
              <span style={{ position: "relative", display: "flex", alignItems: "center" }}>
                <Shield size={13} aria-hidden style={{ position: "absolute", left: 10, color: theme.textMuted, pointerEvents: "none" }} />
                <select
                  value={operadoraFiltro}
                  onChange={(e) => setOperadoraFiltro(e.target.value)}
                  style={{
                    padding: "6px 14px 6px 30px",
                    borderRadius: 999,
                    border: `1px solid ${operadoraFiltro !== "todas" ? brand.accent : theme.cardBorder}`,
                    background: theme.inputBg ?? theme.cardBg,
                    color: operadoraFiltro !== "todas" ? brand.accent : theme.textMuted,
                    fontSize: 13,
                    fontWeight: operadoraFiltro !== "todas" ? 700 : 400,
                    fontFamily: FONT.body,
                    cursor: "pointer",
                    outline: "none",
                    appearance: "none",
                  }}
                >
                  <option value="todas">Todas as operadoras</option>
                  {[...operadorasList].sort((a, b) => a.nome.localeCompare(b.nome, "pt-BR")).map((op) => (
                    <option key={op.slug} value={op.slug}>{op.nome}</option>
                  ))}
                </select>
              </span>
            </div>
          </div>
        </div>
      )}

      <div role="tablist" aria-label="Status dos links" style={{ display: "flex", gap: 6, marginBottom: 24, flexWrap: "wrap" }}>
        {(["pendentes", "mapeados", "ignorados"] as Aba[]).map((a) => {
          const ativa = aba === a;
          return (
            <button key={a} type="button" role="tab" aria-selected={ativa} onClick={() => setAba(a)}
              style={{ display: "inline-flex", alignItems: "center", gap: 6, padding: "7px 16px", borderRadius: 20, cursor: "pointer", border: `1px solid ${ativa ? brand.accent : theme.cardBorder}`, background: ativa ? (brand.useBrand ? "color-mix(in srgb, var(--brand-accent) 15%, transparent)" : `${BRAND.roxoVivo}22`) : (theme.inputBg ?? theme.cardBg), color: ativa ? brand.accent : theme.textMuted, fontSize: 13, fontWeight: ativa ? 700 : 400, fontFamily: FONT.body, transition: "all 0.15s" }}>
              {a.charAt(0).toUpperCase() + a.slice(1)}
              {a === "pendentes" && totalPendentes > 0 && (
                <span style={{ background: BRAND.vermelho, color: "#fff", borderRadius: 10, padding: "0px 6px", fontSize: 10, fontWeight: 700 }}>{totalPendentes}</span>
              )}
            </button>
          );
        })}
      </div>

      {/* ─── Tabela ──────────────────────────────────────────────────────────── */}
      {loading ? (
        <div style={{ textAlign: "center", padding: "60px 0", color: theme.textMuted, fontFamily: FONT.body }}>
          Carregando...
        </div>
      ) : aliases.length === 0 ? (
        <div style={{
          background: brand.blockBg, border: `1px solid ${theme.cardBorder}`,
          borderRadius: 18, padding: 60,
          textAlign: "center", color: theme.textMuted,
          fontFamily: FONT.body, fontSize: 14,
          boxShadow: cardShadow,
        }}>
          {emptyMessages[aba]}
        </div>
      ) : (
        // sem overflow:hidden no wrapper externo para não forçar scroll
        <div style={{ background: brand.blockBg, border: `1px solid ${theme.cardBorder}`, borderRadius: 18, boxShadow: cardShadow, overflow: "hidden" }}>
          <table style={{ width: "100%", borderCollapse: "collapse", fontSize: 13, tableLayout: "fixed" }}>
            <colgroup>
              {/* UTM Source: largura fixa razoável, vai quebrar internamente */}
              <col style={{ width: "22%" }} />
              {operadoraFiltro === "todas" && operadorasList.length > 1 && <col style={{ width: "12%" }} />}
              <col style={{ width: "9%" }} />
              <col style={{ width: "9%" }} />
              <col style={{ width: "6%" }} />
              {!hideDepGgr && <col style={{ width: "11%" }} />}
              {!hideDepGgr && <col style={{ width: "11%" }} />}
              {aba === "mapeados" && <col style={{ width: "12%" }} />}
              {/* Ações: espaço restante */}
              <col />
            </colgroup>
            <thead>
              <tr>
                <th scope="col" style={th}>UTM Source</th>
                {operadoraFiltro === "todas" && operadorasList.length > 1 && <th scope="col" style={th}>Operadora</th>}
                <th scope="col" style={th}>1º visto</th>
                <th scope="col" style={th}>Último</th>
                <th scope="col" style={{ ...th, textAlign: "right" }}>FTDs</th>
                <th scope="col" style={{ ...th, textAlign: "right", ...(hideDepGgr ? { display: "none" } : {}) }}>Depósitos</th>
                <th scope="col" style={{ ...th, textAlign: "right", ...(hideDepGgr ? { display: "none" } : {}) }}>GGR</th>
                {aba === "mapeados" && <th scope="col" style={th}>Influencer / Campanha</th>}
                <th scope="col" style={th}>Ações</th>
              </tr>
            </thead>
            <tbody>
              {aliases.map((alias, idx) => {
                const ggr = calcGgr(alias);
                const zebraBg = idx % 2 === 1 ? (isDark ? "rgba(255,255,255,0.03)" : "rgba(0,0,0,0.02)") : "transparent";
                return (
                  <tr
                    key={alias.id}
                    style={{ background: zebraBg }}
                    onMouseEnter={(e) => {
                      e.currentTarget.style.background = isDark ? "rgba(255,255,255,0.04)" : "rgba(0,0,0,0.02)";
                    }}
                    onMouseLeave={(e) => {
                      e.currentTarget.style.background = zebraBg;
                    }}
                  >
                    {/* UTM Source: chip com quebra de linha e maxWidth */}
                    <td style={tdUtm}>
                      <span style={{
                        display: "inline-flex", alignItems: "flex-start", gap: 5,
                        background: `${BRAND.roxoVivo}22`, color: BRAND.roxoVivo,
                        border: `1px solid ${BRAND.roxoVivo}44`,
                        borderRadius: 6, padding: "3px 9px",
                        fontSize: 12, fontWeight: 600, fontFamily: "monospace",
                        wordBreak: "break-all", maxWidth: "100%",
                      }}>
                        <Link2 size={11} style={{ flexShrink: 0, marginTop: 2 }} />
                        <span>{alias.utm_source}</span>
                      </span>
                    </td>
                    {operadoraFiltro === "todas" && operadorasList.length > 1 && (
                      <td style={td}>{operadorasList.find((o) => o.slug === alias.operadora_slug)?.nome ?? alias.operadora_slug ?? "—"}</td>
                    )}
                    <td style={tdMuted}>{fmtData(alias.primeiro_visto)}</td>
                    <td style={tdMuted}>{fmtData(alias.ultimo_visto)}</td>
                    <td style={{ ...td, textAlign: "right" }}>{alias.total_ftds}</td>
                    <td style={{ ...td, textAlign: "right", ...(hideDepGgr ? { display: "none" } : {}) }}>{fmt(alias.total_deposit)}</td>
                    <td style={{ ...td, textAlign: "right", ...(hideDepGgr ? { display: "none" } : {}) }}>
                      <span style={ggr >= 0 ? { color: BRAND.verde, fontWeight: 600 } : { color: BRAND.vermelho, fontWeight: 600 }}>{fmt(ggr)}</span>
                    </td>
                    {aba === "mapeados" && (
                      <td style={td}>
                        {alias.influencer_id ? (alias.influencer_name ?? "—") : (alias.campanha_nome ?? "—")}
                      </td>
                    )}
                    <td style={td}>
                      <div style={{ display: "flex", gap: 6, alignItems: "center", flexWrap: "wrap" }}>
                        {aba === "pendentes" && podeMapearAlias() && (
                          <>
                            <button onClick={() => abrirModal(alias)}
                              style={{ display: "inline-flex", alignItems: "center", gap: 5, padding: "6px 12px", borderRadius: 10, border: "none", background: brand.useBrand ? "linear-gradient(135deg, var(--brand-primary), var(--brand-secondary))" : `linear-gradient(135deg, ${BRAND.roxo}, ${BRAND.azul})`, color: "#fff", fontSize: 12, fontWeight: 700, fontFamily: FONT.body, cursor: "pointer", whiteSpace: "nowrap" }}>
                              <Link2 size={12} /> Mapear
                            </button>
                            <button onClick={() => ignorar(alias)}
                              style={{ display: "inline-flex", alignItems: "center", gap: 5, padding: "6px 12px", borderRadius: 10, border: `1px solid ${theme.cardBorder}`, background: "transparent", color: theme.textMuted, fontSize: 12, fontFamily: FONT.body, cursor: "pointer", whiteSpace: "nowrap" }}>
                              <EyeOff size={12} /> Ignorar
                            </button>
                          </>
                        )}
                        {(aba === "mapeados" || aba === "ignorados") && podeReativarAlias(alias) && (
                          <button onClick={() => reativar(alias)}
                            style={{ display: "inline-flex", alignItems: "center", gap: 5, padding: "6px 12px", borderRadius: 10, border: `1px solid ${theme.cardBorder}`, background: "transparent", color: theme.text, fontSize: 12, fontFamily: FONT.body, cursor: "pointer", whiteSpace: "nowrap" }}>
                            <RotateCcw size={12} /> Reabrir
                          </button>
                        )}
                      </div>
                    </td>
                  </tr>
                );
              })}
            </tbody>
          </table>
        </div>
      )}

      {/* ─── Modal ───────────────────────────────────────────────────────────── */}
      {modalAberto && aliasSelecionado && (
        <ModalBase onClose={solicitarFecharModal} maxWidth={440}>
          <ModalHeader title="Mapear link órfão" onClose={solicitarFecharModal} />
            <p style={{ fontSize: 12, color: theme.textMuted, marginBottom: 22, fontFamily: FONT.body }}>
              Associe o UTM <strong style={{ color: BRAND.roxoVivo }}>{aliasSelecionado.utm_source}</strong> a um influencer ou campanha.
            </p>

            <div className="app-grid-3" style={{ background: theme.inputBg ?? theme.cardBg, border: `1px solid ${theme.cardBorder}`, borderRadius: 12, padding: "14px 18px", marginBottom: 20 }}>
              {[
                { label: "FTDs",      value: String(aliasSelecionado.total_ftds) },
                { label: "Depósitos", value: fmt(aliasSelecionado.total_deposit) },
                { label: "GGR",       value: fmt(calcGgr(aliasSelecionado)) },
              ].map(({ label, value }) => (
                <div key={label}>
                  <div style={{ fontSize: 10, color: theme.textMuted, textTransform: "uppercase", letterSpacing: "0.08em", fontFamily: FONT.body }}>{label}</div>
                  <div style={{ fontSize: 14, fontWeight: 600, color: theme.text, fontFamily: FONT.body }}>{value}</div>
                </div>
              ))}
            </div>

            <div style={{ display: "flex", gap: 8, marginBottom: 14 }}>
              <button
                type="button"
                aria-pressed={tipoMapeamento === "influencer"}
                onClick={() => { setTipoMapeamento("influencer"); setCampanhaSelecionada(""); }}
                style={{
                  flex: 1, padding: "8px 14px", borderRadius: 10, border: `1px solid ${tipoMapeamento === "influencer" ? BRAND.roxoVivo : theme.cardBorder}`,
                  background: tipoMapeamento === "influencer" ? `${BRAND.roxoVivo}22` : "transparent",
                  color: tipoMapeamento === "influencer" ? BRAND.roxoVivo : theme.textMuted,
                  fontSize: 13, fontWeight: tipoMapeamento === "influencer" ? 700 : 400, fontFamily: FONT.body, cursor: "pointer",
                }}
              >
                Influencer
              </button>
              <button
                type="button"
                aria-pressed={tipoMapeamento === "campanha"}
                onClick={() => { setTipoMapeamento("campanha"); setInfluencerSelecionado(""); }}
                style={{
                  flex: 1, padding: "8px 14px", borderRadius: 10, border: `1px solid ${tipoMapeamento === "campanha" ? BRAND.roxoVivo : theme.cardBorder}`,
                  background: tipoMapeamento === "campanha" ? `${BRAND.roxoVivo}22` : "transparent",
                  color: tipoMapeamento === "campanha" ? BRAND.roxoVivo : theme.textMuted,
                  fontSize: 13, fontWeight: tipoMapeamento === "campanha" ? 700 : 400, fontFamily: FONT.body, cursor: "pointer",
                }}
              >
                Campanha
              </button>
            </div>

            {tipoMapeamento === "influencer" ? (
              <>
                <label style={{ display: "block", fontSize: 11, fontWeight: 700, color: theme.textMuted, textTransform: "uppercase", letterSpacing: "1.1px", marginBottom: 6, fontFamily: FONT.body }}>Influencer</label>
                <select value={influencerSelecionado} onChange={(e) => setInfluencerSelecionado(e.target.value)}
                  style={{ width: "100%", padding: "10px 12px", background: theme.inputBg ?? theme.cardBg, border: `1px solid ${theme.cardBorder}`, borderRadius: 10, color: theme.text, fontSize: 14, marginBottom: 16, outline: "none", fontFamily: FONT.body, cursor: "pointer" }}>
                  <option value="">Selecione o influencer...</option>
                  {(perm.canEditar === "proprios" ? influencers.filter((inf) => podeVerInfluencer(inf.id)) : influencers)
                    .sort((a, b) => (a.nome_artistico ?? "").localeCompare(b.nome_artistico ?? "", "pt-BR"))
                    .map((inf) => (
                      <option key={inf.id} value={inf.id}>{inf.nome_artistico}{inf.status !== "ativo" ? ` (${inf.status})` : ""}</option>
                    ))}
                </select>
              </>
            ) : (
              <>
                <label style={{ display: "block", fontSize: 11, fontWeight: 700, color: theme.textMuted, textTransform: "uppercase", letterSpacing: "1.1px", marginBottom: 6, fontFamily: FONT.body }}>Campanha</label>
                <select value={campanhaSelecionada} onChange={(e) => setCampanhaSelecionada(e.target.value)}
                  style={{ width: "100%", padding: "10px 12px", background: theme.inputBg ?? theme.cardBg, border: `1px solid ${theme.cardBorder}`, borderRadius: 10, color: theme.text, fontSize: 14, marginBottom: 16, outline: "none", fontFamily: FONT.body, cursor: "pointer" }}>
                  <option value="">Selecione a campanha...</option>
                  {[...campanhas].sort((a, b) => a.nome.localeCompare(b.nome, "pt-BR")).map((c) => (
                    <option key={c.id} value={c.id}>{c.nome}</option>
                  ))}
                </select>
              </>
            )}

            {erroModal && (
              <div style={{ display: "flex", alignItems: "center", gap: 8, background: `${BRAND.vermelho}18`, border: `1px solid ${BRAND.vermelho}44`, borderRadius: 10, padding: "10px 14px", fontSize: 12, color: BRAND.vermelho, marginBottom: 16, fontFamily: FONT.body }}>
                <AlertCircle size={14} /> {erroModal}
              </div>
            )}

            <div style={{ display: "flex", justifyContent: "flex-end", gap: 10 }}>
              <button type="button" onClick={solicitarFecharModal}
                style={{ padding: "9px 20px", background: "transparent", border: `1px solid ${theme.cardBorder}`, borderRadius: 10, color: theme.text, fontSize: 13, fontFamily: FONT.body, cursor: salvando ? "not-allowed" : "pointer" }}>
                Cancelar
              </button>
              <button type="button" onClick={() => void confirmarMapeamento()} disabled={(tipoMapeamento === "influencer" ? !influencerSelecionado : !campanhaSelecionada) || salvando}
                aria-disabled={(tipoMapeamento === "influencer" ? !influencerSelecionado : !campanhaSelecionada) || salvando}
                style={{ display: "inline-flex", alignItems: "center", gap: 6, padding: "9px 20px", borderRadius: 10, border: "none", background: `linear-gradient(135deg, ${BRAND.roxo}, ${BRAND.azul})`, color: "#fff", fontSize: 13, fontWeight: 700, fontFamily: FONT.body, cursor: (tipoMapeamento === "influencer" ? influencerSelecionado : campanhaSelecionada) && !salvando ? "pointer" : "not-allowed", opacity: (tipoMapeamento === "influencer" ? influencerSelecionado : campanhaSelecionada) && !salvando ? 1 : 0.5 }}>
                <Link2 size={13} />{salvando ? "Salvando..." : "Confirmar mapeamento"}
              </button>
            </div>
        </ModalBase>
      )}
      {confirmFechar ? (
        <ModalConfirmDelete
          zIndex={1100}
          title="Fechar sem mapear?"
          texto="Existe uma seleção pendente (influencer ou campanha). Deseja fechar sem concluir o mapeamento?"
          confirmLabel="Fechar"
          destructive={false}
          onCancel={() => setConfirmFechar(false)}
          onConfirm={fecharModalLimpo}
        />
      ) : null}
    </div>
  );
}

import { useState, useEffect, useCallback } from "react";
import { supabase } from "../../../lib/supabase";
import { validarBrandguide } from "../../../lib/brandguideValidation";
import { useApp } from "../../../context/AppContext";
import { usePermission } from "../../../hooks/usePermission";
import { useDashboardBrand } from "../../../hooks/useDashboardBrand";
import { BRAND_SEMANTIC as BRAND, FONT, FONT_TITLE } from "../../../constants/theme";
import { Operadora } from "../../../types";
import { Pencil, AlertCircle, Upload, Check } from "lucide-react";
import { GiShield } from "react-icons/gi";
import { ModalBase, ModalHeader } from "../../../components/OperacoesModal";

// ─── Componente Principal ─────────────────────────────────────────────────────
export default function GestaoOperadoras() {
  const { theme: t } = useApp();
  const dashBrand = useDashboardBrand();
  const perm = usePermission("gestao_operadoras");
  const [operadoras, setOperadoras] = useState<Operadora[]>([]);
  const [loading, setLoading] = useState(true);
  const [modalOpen, setModalOpen] = useState(false);
  const [editando, setEditando] = useState<Operadora | null>(null);

  const carregar = useCallback(async () => {
    setLoading(true);
    const { data } = await supabase.from("operadoras").select("*").order("nome");
    setOperadoras(data ?? []);
    setLoading(false);
  }, []);

  useEffect(() => { carregar(); }, [carregar]);

  const ativas = operadoras.filter((o) => o.ativo).length;
  const contadorLabel = operadoras.length === 1 ? "1 operadora cadastrada" : `${operadoras.length} operadoras cadastradas`;

  // ─── Estilos de tabela ───────────────────────────────────────────────────
  const th: React.CSSProperties = {
    textAlign: "left", padding: "10px 16px", color: t.textMuted,
    fontWeight: 700, fontSize: 11, textTransform: "uppercase",
    letterSpacing: "0.08em", fontFamily: FONT.body,
    background: t.isDark ? "rgba(255,255,255,0.05)" : "rgba(0,0,0,0.04)",
    borderBottom: `1px solid ${t.cardBorder}`,
    whiteSpace: "nowrap",
  };
  const td: React.CSSProperties = {
    padding: "12px 16px", color: t.text, fontFamily: FONT.body,
    fontSize: 13, verticalAlign: "middle",
    borderBottom: `1px solid ${t.cardBorder}`,
  };

  if (perm.canView === "nao") {
    return <div style={{ padding: 24, textAlign: "center", color: t.textMuted, fontFamily: FONT.body }}>Você não tem permissão para visualizar a Gestão de Operadoras.</div>;
  }

  return (
    <div className="app-page-shell">

      {/* ─── Header ─────────────────────────────────────────────────────────── */}
      <div style={{ display: "flex", alignItems: "flex-start", gap: 14, marginBottom: 24 }}>
        <span style={{
          width: 28, height: 28, borderRadius: 8,
          background: dashBrand.primaryIconBg,
          border: dashBrand.primaryIconBorder,
          display: "flex", alignItems: "center", justifyContent: "center",
          color: dashBrand.primaryIconColor,
          flexShrink: 0, marginTop: 3,
        }}>
          <GiShield size={14} />
        </span>
        <div>
          <h1 style={{ fontSize: 22, fontWeight: 800, color: dashBrand.primary, fontFamily: FONT_TITLE, margin: 0, letterSpacing: "0.5px", textTransform: "uppercase" }}>
            Gestão de Operadoras
          </h1>
          <p style={{ color: t.textMuted, marginTop: 5, fontFamily: FONT.body, fontSize: 13, margin: "5px 0 0" }}>
            Gerencie as operadoras parceiras da Spin Gaming.
          </p>
        </div>
      </div>

      {/* ─── Cards de resumo ─────────────────────────────────────────────────── */}
      <div className="app-grid-kpi-3" style={{ marginBottom: 24 }}>
        {[
          { label: "Total",    valor: operadoras.length,            cor: BRAND.roxoVivo },
          { label: "Ativas",   valor: ativas,                       cor: "#059669"      },
          { label: "Inativas", valor: operadoras.length - ativas,   cor: BRAND.cinza    },
        ].map((c) => (
          <div key={c.label} style={{
            background: t.cardBg, border: `1px solid ${t.cardBorder}`,
            borderLeft: `3px solid ${c.cor}`,
            borderRadius: 18, padding: "16px 20px",
            boxShadow: t.isDark ? "0 4px 20px rgba(0,0,0,0.25)" : "0 2px 8px rgba(0,0,0,0.07)",
          }}>
            <div style={{ fontSize: 10, fontWeight: 700, letterSpacing: "1.4px", textTransform: "uppercase", color: t.textMuted, fontFamily: FONT.body, marginBottom: 6 }}>
              {c.label}
            </div>
            <div style={{ fontSize: 28, fontWeight: 900, color: c.cor, fontFamily: FONT_TITLE, lineHeight: 1 }}>
              {c.valor}
            </div>
          </div>
        ))}
      </div>

      {/* ─── Tabela ──────────────────────────────────────────────────────────── */}
      <div style={{
        background: t.cardBg, border: `1px solid ${t.cardBorder}`,
        borderRadius: 18,
        boxShadow: t.isDark ? "0 4px 20px rgba(0,0,0,0.25)" : "0 2px 8px rgba(0,0,0,0.07)",
        overflow: "hidden",
      }}>
        {/* Header da tabela */}
        <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", padding: "18px 20px 16px" }}>
          <span style={{ fontFamily: FONT.body, fontSize: 13, color: t.textMuted }}>{contadorLabel}</span>
          {perm.canCriarOk && (
            <button
              type="button"
              onClick={() => { setEditando(null); setModalOpen(true); }}
              style={{
                background: dashBrand.useBrand ? "var(--brand-action, #7c3aed)" : `linear-gradient(135deg, ${BRAND.roxo}, ${BRAND.azul})`,
                color: "#fff", border: "none", borderRadius: 10,
                padding: "9px 18px", cursor: "pointer",
                fontFamily: FONT.body, fontSize: 13, fontWeight: 700,
              }}
            >
              + Nova Operadora
            </button>
          )}
        </div>

        {loading ? (
          <div style={{ padding: "40px 20px", color: t.textMuted, fontFamily: FONT.body, textAlign: "center" }}>Carregando...</div>
        ) : operadoras.length === 0 ? (
          <div style={{ padding: "48px 20px", color: t.textMuted, fontFamily: FONT.body, textAlign: "center" }}>Nenhuma operadora cadastrada.</div>
        ) : (
          <div style={{ overflowX: "auto" }}>
          <table style={{ width: "100%", borderCollapse: "separate", borderSpacing: 0 }}>
            <thead>
              <tr>
                <th style={th}>Slug</th>
                <th style={th}>Nome</th>
                <th style={th}>Status</th>
                <th style={th}>Criada em</th>
                {perm.canEditarOk && <th style={th}>Ações</th>}
              </tr>
            </thead>
            <tbody>
              {operadoras.map((op, idx) => (
                <tr key={op.slug} style={{ background: idx % 2 === 1 ? (t.isDark ? "rgba(255,255,255,0.03)" : "rgba(0,0,0,0.02)") : "transparent" }}>
                  <td style={td}>
                    <code style={{
                      background: `${BRAND.roxoVivo}18`, borderRadius: 6,
                      padding: "3px 9px", fontSize: 12,
                      color: BRAND.roxoVivo, fontFamily: "monospace",
                      border: `1px solid ${BRAND.roxoVivo}33`,
                    }}>
                      {op.slug}
                    </code>
                  </td>
                  <td style={{ ...td, fontWeight: 600 }}>{op.nome}</td>
                  <td style={td}>
                    <span style={{
                      background: op.ativo ? "#05966922" : "#6b728022",
                      color: op.ativo ? "#059669" : "#6b7280",
                      border: `1px solid ${op.ativo ? "#05966944" : "#6b728044"}`,
                      borderRadius: 6, padding: "3px 10px",
                      fontSize: 12, fontWeight: 600, fontFamily: FONT.body,
                    }}>
                      {op.ativo ? "Ativa" : "Inativa"}
                    </span>
                  </td>
                  <td style={{ ...td, color: t.textMuted, fontSize: 12 }}>
                    {op.criado_em ? new Date(op.criado_em).toLocaleDateString("pt-BR") : "—"}
                  </td>
                  {perm.canEditarOk && (
                    <td style={td}>
                      <button
                        type="button"
                        onClick={() => { setEditando(op); setModalOpen(true); }}
                        style={{
                          display: "inline-flex", alignItems: "center", gap: 5,
                          background: "transparent", border: `1px solid ${t.cardBorder}`,
                          borderRadius: 10, padding: "6px 14px", cursor: "pointer",
                          fontFamily: FONT.body, fontSize: 12, color: t.text, fontWeight: 600,
                        }}
                      >
                        <Pencil size={13} /> Editar
                      </button>
                    </td>
                  )}
                </tr>
              ))}
            </tbody>
          </table>
          </div>
        )}
      </div>

      {modalOpen && (
        <ModalOperadora
          t={t}
          dashBrand={dashBrand}
          editando={editando}
          onClose={() => setModalOpen(false)}
          onSalvo={carregar}
        />
      )}
    </div>
  );
}

// ─── Modal ────────────────────────────────────────────────────────────────────
interface ModalProps {
  t: ReturnType<typeof useApp>["theme"];
  dashBrand: ReturnType<typeof useDashboardBrand>;
  editando: Operadora | null;
  onClose: () => void;
  onSalvo: () => void;
}

function ModalOperadora({ t, dashBrand, editando, onClose, onSalvo }: ModalProps) {
  const [nome, setNome] = useState(editando?.nome ?? "");
  const [slug, setSlug] = useState(editando?.slug ?? "");
  const [ativo, setAtivo] = useState(editando?.ativo ?? true);
  const [brandAction, setBrandAction] = useState(editando?.brand_action ?? "");
  const [brandContrast, setBrandContrast] = useState(editando?.brand_contrast ?? "");
  const [brandBg, setBrandBg] = useState(editando?.brand_bg ?? "");
  const [brandText, setBrandText] = useState(editando?.brand_text ?? "");
  const [brandAvisos, setBrandAvisos] = useState<string[]>([]);
  const [logoUrl, setLogoUrl] = useState(editando?.logo_url ?? "");
  const [fontUrl, setFontUrl] = useState(editando?.font_url ?? "");
  const [salvando, setSalvando] = useState(false);
  const [uploadingLogo, setUploadingLogo] = useState(false);
  const [uploadingFont, setUploadingFont] = useState(false);
  const [erro, setErro] = useState("");

  // Gera slug automaticamente a partir do nome — invisível ao usuário na criação
  useEffect(() => {
    if (!editando) {
      setSlug(
        nome
          .toLowerCase()
          .normalize("NFD")
          .replace(/[\u0300-\u036f]/g, "")
          .replace(/[^a-z0-9]+/g, "_")
          .replace(/^_|_$/g, "")
      );
    }
  }, [nome, editando]);

  // Sincroniza campos de brand quando abre para outra operadora
  useEffect(() => {
    if (editando) {
      setBrandAction(editando.brand_action ?? "");
      setBrandContrast(editando.brand_contrast ?? "");
      setBrandBg(editando.brand_bg ?? "");
      setBrandText(editando.brand_text ?? "");
      setBrandAvisos([]);
      setLogoUrl(editando.logo_url ?? "");
      setFontUrl(editando.font_url ?? "");
    }
  }, [editando?.slug]);

  const BUCKET = "operadoras-brand";

  const handleUploadLogo = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file || !editando?.slug) return;
    setUploadingLogo(true);
    setErro("");
    try {
      const ext = file.name.split(".").pop()?.toLowerCase() || "png";
      const path = `${editando.slug}/logo.${ext}`;
      const { error } = await supabase.storage.from(BUCKET).upload(path, file, { upsert: true });
      if (error) throw error;
      const { data: { publicUrl } } = supabase.storage.from(BUCKET).getPublicUrl(path);
      // Cache-busting: evita que o navegador sirva logo antigo após novo upload
      setLogoUrl(`${publicUrl}?v=${Date.now()}`);
    } catch (err) {
      setErro(err instanceof Error ? err.message : "Erro ao enviar logo.");
    } finally {
      setUploadingLogo(false);
      e.target.value = "";
    }
  };

  const FONT_MIME: Record<string, string> = {
    woff2: "font/woff2",
    woff: "font/woff",
    ttf: "font/ttf",
    otf: "font/otf",
  };

  const handleUploadFont = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file || !editando?.slug) return;
    setUploadingFont(true);
    setErro("");
    try {
      const ext = file.name.split(".").pop()?.toLowerCase() || "woff2";
      const path = `${editando.slug}/font.${ext}`;
      const contentType = FONT_MIME[ext] ?? "font/woff2";
      const { error } = await supabase.storage.from(BUCKET).upload(path, file, { upsert: true, contentType });
      if (error) throw error;
      const { data: { publicUrl } } = supabase.storage.from(BUCKET).getPublicUrl(path);
      setFontUrl(publicUrl);
    } catch (err) {
      setErro(err instanceof Error ? err.message : "Erro ao enviar fonte.");
    } finally {
      setUploadingFont(false);
      e.target.value = "";
    }
  };

  const salvar = async () => {
    setErro("");
    if (!nome.trim()) { setErro("Nome é obrigatório."); return; }
    if (!slug.trim()) { setErro("Slug inválido. Verifique o nome informado."); return; }
    if (!/^[a-z0-9_]+$/.test(slug)) { setErro("Slug inválido. Use apenas letras minúsculas, números e underscore."); return; }

    setSalvando(true);
    try {
      const brandPayload: Record<string, string | null> = {
        logo_url: logoUrl.trim() || null,
        font_url: fontUrl.trim() || null,
      };
      if (editando) {
        const v = validarBrandguide({
          action: brandAction.trim() || null,
          contrast: brandContrast.trim() || null,
          bg: brandBg.trim() || null,
          text: brandText.trim() || null,
        });
        setBrandAvisos(v.warnings);
        brandPayload.brand_action = v.action;
        brandPayload.brand_contrast = v.contrast;
        brandPayload.brand_bg = v.bg;
        brandPayload.brand_text = v.text;
      }
      if (editando) {
        const { error } = await supabase.from("operadoras").update({ nome, ativo, ...brandPayload }).eq("slug", editando.slug);
        if (error) throw error;
      } else {
        const { data: existe } = await supabase.from("operadoras").select("slug").eq("slug", slug).maybeSingle();
        if (existe) { setErro("Este slug já está em uso. Tente um nome diferente."); setSalvando(false); return; }
        const { error } = await supabase.from("operadoras").insert({ slug, nome, ativo: true, ...brandPayload });
        if (error) throw error;
      }
      onSalvo();
      onClose();
    } catch (e: unknown) {
      setErro(e instanceof Error ? e.message : "Erro ao salvar.");
    } finally {
      setSalvando(false);
    }
  };

  const inputStyle: React.CSSProperties = {
    width: "100%", background: t.inputBg ?? t.cardBg,
    border: `1px solid ${t.cardBorder}`,
    borderRadius: 10, padding: "10px 14px", color: t.text,
    fontFamily: FONT.body, fontSize: 14, boxSizing: "border-box",
    outline: "none",
  };
  const labelStyle: React.CSSProperties = {
    display: "block", fontFamily: FONT.body, fontSize: 11,
    fontWeight: 700, color: t.textMuted, marginBottom: 6,
    textTransform: "uppercase", letterSpacing: "1px",
  };
  const fieldStyle: React.CSSProperties = { marginBottom: 18 };
  const tryClose = () => { if (!salvando) onClose(); };

  return (
    <ModalBase maxWidth={460} onClose={tryClose}>
        <ModalHeader
          title={editando ? "Editar Operadora" : "Nova Operadora"}
          onClose={tryClose}
        />

        {/* Campo Nome */}
        <div style={fieldStyle}>
          <label style={labelStyle}>Nome</label>
          <input
            style={inputStyle}
            value={nome}
            onChange={(e) => setNome(e.target.value)}
            placeholder="Ex: Blaze"
            autoFocus
          />
        </div>

        {/* Slug — apenas visível na edição, como referência somente leitura */}
        {editando && (
          <div style={fieldStyle}>
            <label style={labelStyle}>
              Identificador interno
              <span style={{ opacity: 0.5, fontWeight: 400, marginLeft: 6, fontSize: 10 }}>(não editável)</span>
            </label>
            <input
              style={{
                ...inputStyle,
                opacity: 0.5,
                cursor: "not-allowed",
                fontFamily: "monospace",
                color: BRAND.roxoVivo,
                fontSize: 13,
              }}
              value={slug}
              readOnly
            />
          </div>
        )}

        {/* Brandguide — cores exibidas para operadores desta operadora */}
        {editando && (
          <div style={{ ...fieldStyle, padding: 16, background: t.isDark ? "rgba(255,255,255,0.05)" : "rgba(0,0,0,0.04)", borderRadius: 12, border: `1px solid ${t.cardBorder}`, maxHeight: 420, overflowY: "auto" }}>
            <div style={{ ...labelStyle, marginBottom: 12 }}>Brandguide (operadores)</div>
            <div className="app-grid-2-tight">
              <div>
                <label style={{ ...labelStyle, fontSize: 10 }}>Cor de ação</label>
                <div style={{ fontSize: 10, color: t.textMuted, marginBottom: 4, fontFamily: FONT.body, lineHeight: 1.35 }}>
                  CTAs, títulos, item ativo no menu. Alto contraste sobre o fundo.
                </div>
                <input type="color" value={brandAction || "#7c3aed"} onChange={(e) => setBrandAction(e.target.value)}
                  style={{ width: "100%", height: 36, border: `1px solid ${t.cardBorder}`, borderRadius: 8, cursor: "pointer" }} />
                <input type="text" value={brandAction} onChange={(e) => setBrandAction(e.target.value)} placeholder="#7c3aed"
                  style={{ ...inputStyle, marginTop: 6, fontSize: 12 }} />
              </div>
              <div>
                <label style={{ ...labelStyle, fontSize: 10 }}>Cor de contraste</label>
                <div style={{ fontSize: 10, color: t.textMuted, marginBottom: 4, fontFamily: FONT.body, lineHeight: 1.35 }}>
                  Comparativos e destaque secundário — deve ser distinta da cor de ação.
                </div>
                <input type="color" value={brandContrast || "#1e36f8"} onChange={(e) => setBrandContrast(e.target.value)}
                  style={{ width: "100%", height: 36, border: `1px solid ${t.cardBorder}`, borderRadius: 8, cursor: "pointer" }} />
                <input type="text" value={brandContrast} onChange={(e) => setBrandContrast(e.target.value)} placeholder="#1e36f8"
                  style={{ ...inputStyle, marginTop: 6, fontSize: 12 }} />
              </div>
              <div>
                <label style={{ ...labelStyle, fontSize: 10 }}>Fundo</label>
                <div style={{ fontSize: 10, color: t.textMuted, marginBottom: 4, fontFamily: FONT.body, lineHeight: 1.35 }}>
                  Background da aplicação (modo operador escuro).
                </div>
                <input type="color" value={brandBg || "#0f0f1a"} onChange={(e) => setBrandBg(e.target.value)}
                  style={{ width: "100%", height: 36, border: `1px solid ${t.cardBorder}`, borderRadius: 8, cursor: "pointer" }} />
                <input type="text" value={brandBg} onChange={(e) => setBrandBg(e.target.value)} placeholder="#0f0f1a"
                  style={{ ...inputStyle, marginTop: 6, fontSize: 12 }} />
              </div>
              <div>
                <label style={{ ...labelStyle, fontSize: 10 }}>Texto</label>
                <div style={{ fontSize: 10, color: t.textMuted, marginBottom: 4, fontFamily: FONT.body, lineHeight: 1.35 }}>
                  Texto principal e ícones estruturais (derivados de contraste no app).
                </div>
                <input type="color" value={brandText || "#ffffff"} onChange={(e) => setBrandText(e.target.value)}
                  style={{ width: "100%", height: 36, border: `1px solid ${t.cardBorder}`, borderRadius: 8, cursor: "pointer" }} />
                <input type="text" value={brandText} onChange={(e) => setBrandText(e.target.value)} placeholder="#ffffff"
                  style={{ ...inputStyle, marginTop: 6, fontSize: 12 }} />
              </div>
              {brandAvisos.length > 0 && (
                <div style={{ gridColumn: "1 / -1", fontSize: 11, color: BRAND.amarelo, fontFamily: FONT.body, lineHeight: 1.45, padding: "8px 10px", borderRadius: 8, border: `1px solid ${BRAND.amarelo}55`, background: `${BRAND.amarelo}14` }}>
                  {brandAvisos.map((w, i) => (
                    <div key={i}>{w}</div>
                  ))}
                </div>
              )}
              <div style={{ gridColumn: "1 / -1" }}>
                <label style={{ ...labelStyle, fontSize: 10 }}>Logo (opcional)</label>
                <input type="url" value={logoUrl} onChange={e => setLogoUrl(e.target.value)} placeholder="URL ou envie um arquivo"
                  style={inputStyle} />
                <div style={{ display: "flex", alignItems: "center", gap: 8, marginTop: 8 }}>
                  <label style={{
                    display: "inline-flex", alignItems: "center", gap: 6, padding: "8px 14px",
                    background: t.isDark ? "rgba(255,255,255,0.06)" : "rgba(0,0,0,0.04)", border: `1px solid ${t.cardBorder}`,
                    borderRadius: 8, cursor: uploadingLogo ? "not-allowed" : "pointer",
                    fontSize: 12, fontFamily: FONT.body, color: t.text,
                  }}>
                    <Upload size={14} />
                    {uploadingLogo ? "Enviando..." : "Enviar logo (PNG, JPG, SVG)"}
                    <input type="file" accept="image/png,image/jpeg,image/svg+xml,image/webp" hidden disabled={uploadingLogo} onChange={handleUploadLogo} />
                  </label>
                  {logoUrl && (
                    <a href={logoUrl} target="_blank" rel="noopener noreferrer" style={{ fontSize: 11, color: BRAND.roxoVivo }}>Ver</a>
                  )}
                </div>
              </div>
              <div style={{ gridColumn: "1 / -1" }}>
                <label style={{ ...labelStyle, fontSize: 10 }}>Fonte customizada (opcional)</label>
                <input type="url" value={fontUrl} onChange={e => setFontUrl(e.target.value)} placeholder="URL ou envie .woff2, .woff, .ttf, .otf"
                  style={inputStyle} />
                <div style={{ display: "flex", alignItems: "center", gap: 8, marginTop: 8 }}>
                  <label style={{
                    display: "inline-flex", alignItems: "center", gap: 6, padding: "8px 14px",
                    background: t.isDark ? "rgba(255,255,255,0.06)" : "rgba(0,0,0,0.04)", border: `1px solid ${t.cardBorder}`,
                    borderRadius: 8, cursor: uploadingFont ? "not-allowed" : "pointer",
                    fontSize: 12, fontFamily: FONT.body, color: t.text,
                  }}>
                    <Upload size={14} />
                    {uploadingFont ? "Enviando..." : "Enviar fonte (WOFF2, WOFF, TTF, OTF)"}
                    <input type="file" accept=".woff2,.woff,.ttf,.otf,font/woff2,font/woff,font/ttf,font/otf" hidden disabled={uploadingFont} onChange={handleUploadFont} />
                  </label>
                  {fontUrl && (
                    <a href={fontUrl} target="_blank" rel="noopener noreferrer" style={{ fontSize: 11, color: BRAND.roxoVivo }}>Ver</a>
                  )}
                </div>
              </div>
            </div>
          </div>
        )}

        {/* Status — apenas na edição */}
        {editando && (
          <div style={{ ...fieldStyle, display: "flex", alignItems: "center", gap: 12 }}>
            <label style={{ ...labelStyle, margin: 0 }}>Status</label>
            <button
              type="button"
              aria-pressed={ativo}
              onClick={() => setAtivo((prev) => !prev)}
              style={{
                border: `1px solid ${ativo ? "#05966966" : t.cardBorder}`,
                background: ativo ? "#05966922" : "transparent",
                color: ativo ? "#059669" : t.textMuted,
                borderRadius: 10, padding: "6px 16px", cursor: "pointer",
                fontFamily: FONT.body, fontSize: 13, fontWeight: 600,
                display: "inline-flex", alignItems: "center", gap: 6,
              }}
            >
              {ativo && <Check size={13} aria-hidden="true" />}
              {ativo ? "Ativa" : "Inativa"}
            </button>
            {!ativo && (
              <div style={{ display: "flex", alignItems: "center", gap: 6, fontSize: 12, color: BRAND.roxoVivo, fontFamily: FONT.body }}>
                <AlertCircle size={13} /> Vínculos existentes não são removidos
              </div>
            )}
          </div>
        )}

        {/* Erro */}
        {erro && (
          <div style={{ display: "flex", alignItems: "center", gap: 8, background: `${BRAND.vermelho}18`, border: `1px solid ${BRAND.vermelho}44`, borderRadius: 10, padding: "10px 14px", fontSize: 13, color: BRAND.vermelho, marginBottom: 16, fontFamily: FONT.body }}>
            <AlertCircle size={14} /> {erro}
          </div>
        )}

        {/* Botões */}
        <div style={{ display: "flex", gap: 10, justifyContent: "flex-end", marginTop: 8 }}>
          <button
            type="button"
            onClick={tryClose}
            style={{ background: "transparent", border: `1px solid ${t.cardBorder}`, borderRadius: 10, padding: "9px 18px", cursor: "pointer", fontFamily: FONT.body, fontSize: 13, color: t.text }}
          >
            Cancelar
          </button>
          <button
            type="button"
            onClick={salvar}
            disabled={salvando}
            style={{
              background: dashBrand.useBrand ? "var(--brand-action, #7c3aed)" : `linear-gradient(135deg, ${BRAND.roxo}, ${BRAND.azul})`,
              color: "#fff", border: "none", borderRadius: 10,
              padding: "9px 20px", cursor: salvando ? "not-allowed" : "pointer",
              fontFamily: FONT.body, fontSize: 13, fontWeight: 700, opacity: salvando ? 0.7 : 1,
            }}
          >
            {salvando ? "Salvando..." : editando ? "Salvar alterações" : "Criar operadora"}
          </button>
        </div>
    </ModalBase>
  );
}

import { useState, useEffect } from "react";
import { X, AlertCircle } from "lucide-react";
import { supabase } from "../../../lib/supabase";
import { callSupabaseEdgeFunction, isAbortError } from "../../../lib/supabaseEdgeFetch";
import { useDashboardBrand } from "../../../hooks/useDashboardBrand";
import { ModalBase, ModalHeader } from "../../../components/OperacoesModal";
import { FONT } from "../../../constants/theme";
import type { Role, UsuarioCompleto, Operadora } from "../../../types";
import type { Theme } from "../../../constants/theme";
import { BRAND, ROLES, roleBadgeColor, GESTOR_TIPOS } from "./constants";
import { ParesAgenciaUI } from "./ParesAgenciaUI";

interface ModalUsuarioProps {
  t: Theme;
  editando: UsuarioCompleto | null;
  operadoras: Operadora[];
  onClose: () => void;
  onSalvo: () => void;
}

export function ModalUsuario({ t, editando, operadoras, onClose, onSalvo }: ModalUsuarioProps) {
  const brand = useDashboardBrand();
  const [nome, setNome] = useState(editando?.name ?? "");
  const [email, setEmail] = useState(editando?.email ?? "");
  const [role, setRole] = useState<Role>(editando?.role ?? "gestor");
  const [scopeInfluencers, setScopeInfluencers] = useState<string[]>([]);
  const [scopeOperadoras, setScopeOperadoras] = useState<string[]>([]);
  const [scopePares, setScopePares] = useState<string[]>([]);
  const [scopeGestorTipos, setScopeGestorTipos] = useState<string[]>([]);
  const [paresAgencia, setParesAgencia] = useState<Array<{ influencerId: string; operadoraSlug: string }>>([]);
  const [influencers, setInfluencers] = useState<{ id: string; nome: string }[]>([]);
  const [salvando, setSalvando] = useState(false);
  const [erro, setErro] = useState("");

  useEffect(() => {
    (async () => {
      const { data: profiles } = await supabase
        .from("profiles")
        .select("id, name, email")
        .eq("role", "influencer")
        .order("name");
      if (!profiles?.length) {
        setInfluencers([]);
        return;
      }
      const ids = profiles.map((p: { id: string }) => p.id);
      const { data: perfis } = await supabase.from("influencer_perfil").select("id, nome_artistico").in("id", ids);
      const perfisMap = new Map((perfis ?? []).map((p: { id: string; nome_artistico: string }) => [p.id, p.nome_artistico]));
      setInfluencers(
        profiles.map((p: { id: string; name?: string; email?: string }) => ({
          id: p.id,
          nome: perfisMap.get(p.id) ?? p.name ?? p.email ?? p.id,
        }))
      );
    })();
  }, []);

  /** Sincroniza cabeçalho do formulário quando abre outro usuário (evita estado velho se o modal reutilizar instância). */
  useEffect(() => {
    setNome(editando?.name ?? "");
    setEmail(editando?.email ?? "");
    setRole((editando?.role ?? "gestor") as Role);
    setErro("");
  }, [editando?.id]);

  useEffect(() => {
    const scopes = editando?.scopes ?? [];
    setScopeInfluencers(scopes.filter((s) => s.scope_type === "influencer").map((s) => s.scope_ref));
    setScopeOperadoras(scopes.filter((s) => s.scope_type === "operadora").map((s) => s.scope_ref));
    setScopePares(scopes.filter((s) => s.scope_type === "agencia_par").map((s) => s.scope_ref));
    setScopeGestorTipos(scopes.filter((s) => s.scope_type === "gestor_tipo").map((s) => s.scope_ref));
  }, [editando]);

  /** Troca explícita no select: limpa escopos incompatíveis (evita useEffect em [role] que conflita com sync de `editando`). */
  const handleRoleChange = (next: Role) => {
    if (next === role) return;
    setRole(next);
    setScopeInfluencers([]);
    setScopeOperadoras([]);
    setScopePares([]);
    setScopeGestorTipos([]);
  };

  /** Novo usuário influencer: pré-preenche operadora a partir do Scout (parceria), alinhado ao criar-usuario na Edge. */
  useEffect(() => {
    if (editando?.id) return;
    if (role !== "influencer") return;
    const em = email.trim().toLowerCase();
    if (!em || !/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(em)) return;

    const timer = window.setTimeout(() => {
      void (async () => {
        const { data: row } = await supabase
          .from("scout_influencer")
          .select("operadora_slug")
          .ilike("email", em)
          .order("updated_at", { ascending: false })
          .limit(1)
          .maybeSingle();

        const slug = String(row?.operadora_slug ?? "").trim();
        if (!slug) return;
        const { data: op } = await supabase.from("operadoras").select("slug").eq("slug", slug).maybeSingle();
        if (!op?.slug) return;
        setScopeOperadoras((prev) => (prev.includes(slug) ? prev : [...prev, slug]));
      })();
    }, 450);

    return () => clearTimeout(timer);
  }, [email, role, editando?.id]);

  useEffect(() => {
    if (role !== "agencia") return;
    const scopes = editando?.scopes ?? [];
    const agenciaPars = scopes.filter((s: { scope_type: string }) => s.scope_type === "agencia_par");
    if (agenciaPars.length > 0) {
      setParesAgencia(
        agenciaPars.map((s: { scope_ref: string }) => {
          const [inf, op] = (s.scope_ref || "").split(":");
          return { influencerId: inf ?? "", operadoraSlug: op ?? "" };
        })
      );
    } else {
      setParesAgencia([{ influencerId: "", operadoraSlug: "" }]);
    }
  }, [role, editando?.id]);

  const toggleItem = (list: string[], setList: React.Dispatch<React.SetStateAction<string[]>>, val: string) =>
    setList((prev) => (prev.includes(val) ? prev.filter((v) => v !== val) : [...prev, val]));

  const selectOperadoraUnica = (slug: string) =>
    setScopeOperadoras((prev) => (prev.includes(slug) ? prev : [slug]));

  const salvar = async () => {
    setErro("");
    if (!nome.trim()) {
      setErro("Nome é obrigatório.");
      return;
    }
    if (!editando && !email.trim()) {
      setErro("E-mail é obrigatório.");
      return;
    }
    if (role === "influencer" && scopeOperadoras.length === 0) {
      setErro("Selecione pelo menos uma operadora para o influencer.");
      return;
    }
    if (role === "operador" && scopeOperadoras.length === 0) {
      setErro("Selecione uma operadora para o operador.");
      return;
    }
    if (role === "operador" && scopeOperadoras.length > 1) {
      setErro("O perfil Operador permite apenas uma operadora.");
      return;
    }
    if (role === "gestor" && scopeGestorTipos.length === 0) {
      setErro("Selecione pelo menos um tipo de gestor.");
      return;
    }
    const paresValidos = role === "agencia" ? paresAgencia.filter((p) => p.influencerId && p.operadoraSlug) : [];
    if (role === "agencia" && paresValidos.length === 0) {
      setErro("Adicione pelo menos um par influencer + operadora.");
      return;
    }
    setSalvando(true);
    try {
      let uid = editando?.id ?? "";
      const scopeParesParaApi =
        role === "agencia"
          ? paresAgencia.filter((p) => p.influencerId && p.operadoraSlug).map((p) => `${p.influencerId}:${p.operadoraSlug}`)
          : scopePares;
      const scopeInfluencersArr = Array.isArray(scopeInfluencers) ? scopeInfluencers : [];
      const scopeOperadorasArr =
        role === "operador"
          ? (Array.isArray(scopeOperadoras) ? scopeOperadoras : []).slice(0, 1)
          : Array.isArray(scopeOperadoras) ? scopeOperadoras : [];
      const scopeGestorTiposArr = role === "gestor" ? (Array.isArray(scopeGestorTipos) ? scopeGestorTipos : []) : [];

      if (editando) {
        await callSupabaseEdgeFunction("atualizar-perfil", {
          userId: uid,
          name: nome.trim(),
          role,
          scopeInfluencers: scopeInfluencersArr,
          scopeOperadoras: scopeOperadorasArr,
          scopePares: scopeParesParaApi,
          scopeGestorTipos: scopeGestorTiposArr,
        });
      } else {
        const loginUrl = typeof window !== "undefined" ? window.location.origin : "";
        const fnData = await callSupabaseEdgeFunction<{ userId?: string }>("criar-usuario", {
          email: email.trim().toLowerCase(),
          nome: nome.trim(),
          role,
          scopeInfluencers: scopeInfluencersArr,
          scopeOperadoras: scopeOperadorasArr,
          scopePares: scopeParesParaApi,
          scopeGestorTipos: role === "gestor" ? scopeGestorTiposArr : [],
          loginUrl,
        });
        uid = fnData.userId ?? "";
        if (!uid) throw new Error("Usuário criado mas ID não retornado");
      }
      onSalvo();
      onClose();
    } catch (e: unknown) {
      if (isAbortError(e)) {
        setErro(
          "Tempo esgotado ou rede indisponível. Confira se as funções criar-usuario e atualizar-perfil estão deployadas no Supabase (CLI: supabase functions deploy)."
        );
      } else {
        setErro(e instanceof Error ? e.message : "Erro ao salvar.");
      }
    } finally {
      setSalvando(false);
    }
  };

  const labelStyle: React.CSSProperties = {
    display: "block",
    fontFamily: FONT.body,
    fontSize: 11,
    fontWeight: 700,
    color: t.textMuted,
    marginBottom: 6,
    textTransform: "uppercase",
    letterSpacing: "0.8px",
  };
  const inputStyle: React.CSSProperties = {
    width: "100%",
    background: t.inputBg ?? t.cardBg,
    border: `1px solid ${t.cardBorder}`,
    borderRadius: 8,
    padding: "10px 12px",
    color: t.text,
    fontFamily: FONT.body,
    fontSize: 14,
    boxSizing: "border-box",
    outline: "none",
    transition: "border-color 0.18s",
  };
  const selectStyle: React.CSSProperties = { ...inputStyle, cursor: "pointer" };
  const field: React.CSSProperties = { marginBottom: 18 };

  const addParAgencia = () => setParesAgencia((prev) => [...prev, { influencerId: "", operadoraSlug: "" }]);
  const removeParAgencia = (idx: number) =>
    setParesAgencia((prev) => (prev.length > 1 ? prev.filter((_, i) => i !== idx) : [{ influencerId: "", operadoraSlug: "" }]));
  const updateParAgencia = (idx: number, f: "influencerId" | "operadoraSlug", val: string) =>
    setParesAgencia((prev) => prev.map((p, i) => (i === idx ? { ...p, [f]: val } : p)));

  const SingleSelectOperadora = ({
    label,
    items,
    selected,
    onSelect,
    cor = BRAND.roxoVivo,
    obrigatorio = false,
  }: {
    label: string;
    items: { value: string; label: string }[];
    selected: string[];
    onSelect: (v: string) => void;
    cor?: string;
    obrigatorio?: boolean;
  }) => (
    <div style={field}>
      <label style={labelStyle}>
        {label}
        {obrigatorio && <span style={{ color: BRAND.vermelho, marginLeft: 4 }}>*</span>}
        <span style={{ opacity: 0.5, fontWeight: 400, marginLeft: 6 }}>(seleção única)</span>
      </label>
      <div
        style={{
          border: `1px solid ${t.cardBorder}`,
          borderRadius: 8,
          padding: 10,
          display: "flex",
          flexWrap: "wrap",
          gap: 8,
          maxHeight: 160,
          overflowY: "auto",
          background: t.inputBg ?? t.cardBg,
        }}
      >
        {items.map((op) => {
          const sel = selected.includes(op.value);
          return (
            <button
              key={op.value}
              type="button"
              onClick={() => onSelect(op.value)}
              style={{
                border: `1px solid ${sel ? cor : t.cardBorder}`,
                background: sel ? `${cor}22` : "transparent",
                color: sel ? cor : t.text,
                borderRadius: 20,
                padding: "5px 12px",
                cursor: "pointer",
                fontFamily: FONT.body,
                fontSize: 12,
                fontWeight: sel ? 700 : 400,
                transition: "all 0.15s",
              }}
            >
              {op.label}
            </button>
          );
        })}
      </div>
      {selected.length > 0 && (
        <p style={{ fontFamily: FONT.body, fontSize: 11, color: t.textMuted, marginTop: 4 }}>
          Operadora selecionada: {items.find((i) => i.value === selected[0])?.label ?? selected[0]}
        </p>
      )}
    </div>
  );

  const MultiSelect = ({
    label,
    items,
    selected,
    onToggle,
    cor = BRAND.roxoVivo,
    obrigatorio = false,
  }: {
    label: string;
    items: { value: string; label: string }[];
    selected: string[];
    onToggle: (v: string) => void;
    cor?: string;
    obrigatorio?: boolean;
  }) => (
    <div style={field}>
      <label style={labelStyle}>
        {label}
        {obrigatorio && <span style={{ color: BRAND.vermelho, marginLeft: 4 }}>*</span>}
        <span style={{ opacity: 0.5, fontWeight: 400, marginLeft: 6 }}>(multi-seleção)</span>
      </label>
      <div
        style={{
          border: `1px solid ${t.cardBorder}`,
          borderRadius: 8,
          padding: 10,
          display: "flex",
          flexWrap: "wrap",
          gap: 8,
          maxHeight: 160,
          overflowY: "auto",
          background: t.inputBg ?? t.cardBg,
        }}
      >
        {items.map((op) => {
          const sel = selected.includes(op.value);
          return (
            <button
              key={op.value}
              type="button"
              onClick={() => onToggle(op.value)}
              style={{
                border: `1px solid ${sel ? cor : t.cardBorder}`,
                background: sel ? `${cor}22` : "transparent",
                color: sel ? cor : t.text,
                borderRadius: 20,
                padding: "5px 12px",
                cursor: "pointer",
                fontFamily: FONT.body,
                fontSize: 12,
                fontWeight: sel ? 700 : 400,
                transition: "all 0.15s",
                display: "flex",
                alignItems: "center",
                gap: sel ? 5 : 0,
              }}
            >
              {op.label}
              {sel && <X size={10} style={{ flexShrink: 0 }} />}
            </button>
          );
        })}
      </div>
      {selected.length > 0 && (
        <p style={{ fontFamily: FONT.body, fontSize: 11, color: t.textMuted, marginTop: 4 }}>
          {selected.length} selecionado{selected.length !== 1 ? "s" : ""}
        </p>
      )}
    </div>
  );

  const tituloModal = editando ? "Editar Usuário" : "Novo Usuário";
  const salvarBg = salvando
    ? BRAND.cinza
    : brand.useBrand
      ? "var(--brand-primary)"
      : BRAND.gradiente;

  return (
    <ModalBase onClose={onClose} maxWidth={560} zIndex={999}>
      <ModalHeader title={tituloModal} onClose={onClose} />
        <div style={field}>
          <label style={labelStyle}>Nome</label>
          <input
            style={inputStyle}
            value={nome}
            onChange={(e) => setNome(e.target.value)}
            placeholder="Nome completo"
            onFocus={(e) => { e.currentTarget.style.borderColor = BRAND.roxoVivo; }}
            onBlur={(e) => { e.currentTarget.style.borderColor = t.cardBorder; }}
          />
        </div>
        {!editando && (
          <div style={field}>
            <label style={labelStyle}>E-mail</label>
            <input
              style={inputStyle}
              value={email}
              onChange={(e) => setEmail(e.target.value)}
              placeholder="email@exemplo.com"
              type="email"
              onFocus={(e) => { e.currentTarget.style.borderColor = BRAND.roxoVivo; }}
              onBlur={(e) => { e.currentTarget.style.borderColor = t.cardBorder; }}
            />
          </div>
        )}
        <div style={field}>
          <label style={labelStyle}>Perfil</label>
          <select style={selectStyle} value={role} onChange={(e) => handleRoleChange(e.target.value as Role)}>
            {[...ROLES].sort((a, b) => a.label.localeCompare(b.label, "pt-BR")).map((r) => (
              <option key={r.value} value={r.value}>
                {r.label}
              </option>
            ))}
          </select>
        </div>
        {role === "admin" ? (
          <div style={field}>
            <label style={labelStyle}>Escopo de acesso</label>
            <div
              style={{
                background: t.inputBg ?? t.cardBg,
                border: `1px solid ${t.cardBorder}`,
                borderRadius: 8,
                padding: "10px 14px",
                fontFamily: FONT.body,
                fontSize: 14,
                color: t.textMuted,
                fontStyle: "italic",
              }}
            >
              Todos os influencers e operadoras
            </div>
          </div>
        ) : role === "gestor" ? (
          <MultiSelect
            label="Tipos de gestor"
            obrigatorio
            cor={roleBadgeColor("gestor")}
            items={GESTOR_TIPOS.map((g) => ({ value: g.slug, label: g.label }))}
            selected={scopeGestorTipos}
            onToggle={(v) => toggleItem(scopeGestorTipos, setScopeGestorTipos, v)}
          />
        ) : role === "agencia" ? (
          <ParesAgenciaUI
            pares={paresAgencia}
            onAdd={addParAgencia}
            onRemove={removeParAgencia}
            onUpdate={updateParAgencia}
            influencers={influencers}
            operadoras={operadoras}
            labelStyle={labelStyle}
            selectStyle={selectStyle}
            field={field}
            t={t}
          />
        ) : role === "influencer" ? (
          <MultiSelect
            label="Operadoras atribuídas"
            obrigatorio
            cor={roleBadgeColor("influencer")}
            items={operadoras.map((o) => ({ value: o.slug, label: o.nome }))}
            selected={scopeOperadoras}
            onToggle={(v) => toggleItem(scopeOperadoras, setScopeOperadoras, v)}
          />
        ) : (
          <>
            {role !== "executivo" && role !== "operador" && (
              <MultiSelect
                label="Influencers (opcional)"
                cor={roleBadgeColor("operador")}
                items={influencers.map((i) => ({ value: i.id, label: i.nome }))}
                selected={scopeInfluencers}
                onToggle={(v) => toggleItem(scopeInfluencers, setScopeInfluencers, v)}
              />
            )}
            {role === "operador" ? (
              <SingleSelectOperadora
                label="Operadora atribuída"
                obrigatorio
                cor={roleBadgeColor("operador")}
                items={operadoras.map((o) => ({ value: o.slug, label: o.nome }))}
                selected={scopeOperadoras}
                onSelect={selectOperadoraUnica}
              />
            ) : (
              <MultiSelect
                label="Operadoras (opcional)"
                cor={roleBadgeColor("executivo")}
                items={operadoras.map((o) => ({ value: o.slug, label: o.nome }))}
                selected={scopeOperadoras}
                onToggle={(v) => toggleItem(scopeOperadoras, setScopeOperadoras, v)}
              />
            )}
          </>
        )}
        {erro && (
          <div
            role="alert"
            style={{
              display: "flex",
              alignItems: "flex-start",
              gap: 8,
              background: `${BRAND.vermelho}18`,
              border: `1px solid ${BRAND.vermelho}44`,
              borderRadius: 8,
              padding: "10px 12px",
              marginBottom: 16,
            }}
          >
            <AlertCircle size={14} color={BRAND.vermelho} style={{ flexShrink: 0, marginTop: 2 }} aria-hidden />
            <span
              style={{
                color: BRAND.vermelho,
                fontFamily: FONT.body,
                fontSize: 13,
                lineHeight: 1.45,
                whiteSpace: "pre-line",
                wordBreak: "break-word",
              }}
            >
              {erro}
            </span>
          </div>
        )}
        <div style={{ display: "flex", gap: 10, justifyContent: "flex-end" }}>
          <button
            type="button"
            onClick={onClose}
            style={{
              background: "none",
              border: `1px solid ${t.cardBorder}`,
              borderRadius: 8,
              padding: "9px 18px",
              cursor: "pointer",
              fontFamily: FONT.body,
              fontSize: 13,
              color: t.text,
            }}
          >
            Cancelar
          </button>
          <button
            type="button"
            onClick={salvar}
            disabled={salvando}
            style={{
              background: salvarBg,
              color: "#fff",
              border: "none",
              borderRadius: 8,
              padding: "9px 20px",
              cursor: salvando ? "not-allowed" : "pointer",
              fontFamily: FONT.body,
              fontSize: 13,
              fontWeight: 600,
              opacity: salvando ? 0.7 : 1,
              transition: "opacity 0.15s",
            }}
          >
            {salvando ? "Salvando..." : editando ? "Salvar alterações" : "Criar usuário"}
          </button>
        </div>
    </ModalBase>
  );
}

import { useState, useEffect, useCallback } from "react";
import { supabase, supabaseUrl, supabaseAnonKey } from "../../../lib/supabase";
import { useApp } from "../../../context/AppContext";
import { usePermission } from "../../../hooks/usePermission";
import { useDashboardBrand } from "../../../hooks/useDashboardBrand";
import { BRAND_SEMANTIC as BRAND, FONT, FONT_TITLE } from "../../../constants/theme";
import { MSG_SEM_DADOS_FILTRO } from "../../../lib/dashboardConstants";
import { GiRadarSweep, GiSiren, GiCircuitry, GiGearStick } from "react-icons/gi";
import { CheckCircle2, AlertTriangle, XCircle, RefreshCw } from "lucide-react";

/** Upload OCR PLS removido do produto — ocultar mesmo se a linha ainda existir em `integrations`. */
const SLUG_INTEGRACAO_PLS_UPLOAD_RETIRADA = "upload_pls_daily_commercial";

// ─── SectionTitle (padrão da plataforma) ─────────────────────────────────────
function SectionTitle({ icon, children }: { icon: React.ReactNode; children: React.ReactNode }) {
  const { theme: t } = useApp();
  const brand = useDashboardBrand();
  return (
    <div style={{ display: "flex", alignItems: "center", gap: 8, marginBottom: 20 }}>
      <span style={{
        width: 28, height: 28, borderRadius: 8,
        background: brand.primaryIconBg,
        border: brand.primaryIconBorder,
        display: "flex", alignItems: "center", justifyContent: "center",
        color: brand.primaryIconColor, flexShrink: 0,
      }}>
        {icon}
      </span>
      <span style={{
        fontSize: 14, fontWeight: 800, color: t.text,
        fontFamily: FONT_TITLE,
        letterSpacing: "0.05em", textTransform: "uppercase" as const,
      }}>
        {children}
      </span>
    </div>
  );
}

// ─── KpiCard (padrão da plataforma com accent bar) ───────────────────────────
function KpiCard({ label, value, accentColor, loading }: {
  label: string; value: React.ReactNode; accentColor: string; loading?: boolean;
}) {
  const { theme: t } = useApp();
  return (
    <div style={{
      background: t.cardBg, borderRadius: 16,
      border: `1px solid ${t.cardBorder}`, overflow: "hidden",
    }}>
      <div style={{ height: 3, background: `linear-gradient(90deg, ${accentColor}, transparent)` }} />
      <div style={{ padding: "18px 20px" }}>
        <p style={{
          fontFamily: FONT.body, fontSize: 11, fontWeight: 700,
          color: t.textMuted, textTransform: "uppercase", letterSpacing: "1px",
          margin: "0 0 10px",
        }}>
          {label}
        </p>
        <div style={{
          fontFamily: FONT.body, fontSize: 28, fontWeight: 800,
          color: t.text, margin: 0, lineHeight: 1.1,
        }}>
          {loading ? "—" : value}
        </div>
      </div>
    </div>
  );
}

// ─── TIPOS ────────────────────────────────────────────────────────────────────
interface SyncLog {
  id: string;
  integracao_slug: string;
  executado_em: string;
  status: "ok" | "falha";
  registros_inseridos: number;
  registros_atualizados: number;
  erros_count: number;
  mensagem_erro: string | null;
  duracao_ms: number | null;
  periodo_inicio: string | null;
  periodo_fim: string | null;
}

interface TechLog {
  id: string;
  integracao_slug: string | null;
  tipo: string;
  descricao: string;
  created_at: string;
}

interface PipelineRun {
  id: string;
  run_date: string;
  channel: string;
  status: string;
  error_msg: string | null;
  created_at: string;
}

interface Integration {
  slug: string;
  nome: string;
  descricao: string | null;
  ativo: boolean;
}

interface FluxoDia {
  data: string;
  cda: number;
  social: number;
  emails: Record<string, number>; // tipo -> destinatarios_count
  total: number;
}

export default function StatusTecnico() {
  const { theme: t } = useApp();
  const dashBrand = useDashboardBrand();
  const perm = usePermission("status_tecnico");
  const [loading, setLoading] = useState(true);
  const [syncExecutando, setSyncExecutando] = useState(false);
  const [syncMensagem, setSyncMensagem] = useState<{ tipo: "ok" | "erro"; texto: string } | null>(null);
  const [syncSocialExecutando, setSyncSocialExecutando] = useState(false);
  const [syncSocialMensagem, setSyncSocialMensagem] = useState<{ tipo: "ok" | "erro"; texto: string } | null>(null);
  const [emailEnviando, setEmailEnviando] = useState(false);
  const [emailMensagem, setEmailMensagem] = useState<{ tipo: "ok" | "erro"; texto: string } | null>(null);
  const [emailAgendaEnviando, setEmailAgendaEnviando] = useState(false);
  const [emailAgendaMensagem, setEmailAgendaMensagem] = useState<{ tipo: "ok" | "erro"; texto: string } | null>(null);
  const [integrations, setIntegrations] = useState<Integration[]>([]);
  const [syncLogs, setSyncLogs] = useState<SyncLog[]>([]);
  const [techLogs, setTechLogs] = useState<TechLog[]>([]);
  const [pipelineRuns, setPipelineRuns] = useState<PipelineRun[]>([]);
  const [fluxoDados, setFluxoDados] = useState<FluxoDia[]>([]);
  const [registrosHoje, setRegistrosHoje] = useState(0);
  const [emailUltimoDiretoria, setEmailUltimoDiretoria] = useState<string | null>(null);
  const [emailUltimoAgenda, setEmailUltimoAgenda] = useState<string | null>(null);
