          await new Promise((r) => setTimeout(r, 800));
          res = await tentarFetch();
        }
      } catch (fetchErr) {
        const raw = fetchErr instanceof Error ? fetchErr.message : String(fetchErr);
        const rede =
          raw.includes("Failed to fetch") ||
          raw.includes("NetworkError") ||
